-- Poems batch 477
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('yuding-34','柳絮','李中','唐','御定全唐诗','yuding','','[]','年年二月暮，散亂雜飛花。雨過微風起，狂飄千萬家。',24,'御定全唐詩/json/750.json','["年年二月暮，散亂雜飛花。雨過微風起，狂飄千萬家。"]'),
('yuding-35','早春','李中','唐','御定全唐诗','yuding','','[]','一種和風至，千花未放妍。草心並柳眼，長是被恩先。',24,'御定全唐詩/json/750.json','["一種和風至，千花未放妍。草心並柳眼，長是被恩先。"]'),
('yuding-36','春雲','李中','唐','御定全唐诗','yuding','','[]','陰去為膏澤，晴來媚曉空。無心亦無滯，舒卷在東風。',24,'御定全唐詩/json/750.json','["陰去為膏澤，晴來媚曉空。無心亦無滯，舒卷在東風。"]'),
('yuding-37','送姚端秀才游毗陵','李中','唐','御定全唐诗','yuding','','[]','毗陵嘉景太湖邊，才子經游稱少年。風弄青簾沽酒市，',40,'御定全唐詩/json/750.json','["毗陵嘉景太湖邊，才子經游稱少年。風弄青簾沽酒市，", "此去高吟須早返，廣寒丹桂莫遷延。"]'),
('yuding-38','和朐陽載筆魯裕見寄','李中','唐','御定全唐诗','yuding','','[]','燕台多事每開顏，相許論交淡薄間。飲興共憐芳草岸，',40,'御定全唐詩/json/750.json','["燕台多事每開顏，相許論交淡薄間。飲興共憐芳草岸，", "何事此時攀憶甚，與君俱是別鄉關。"]'),
('yuding-39','敘吟二首','李中','唐','御定全唐诗','yuding','','[]','往哲搜羅妙入神，隋珠和璧未為珍。',64,'御定全唐詩/json/750.json','["往哲搜羅妙入神，隋珠和璧未為珍。", "而今所得慚難繼，謬向平生著苦辛。", "成僻成魔二雅中，每逢知己是亨通。", "言之無罪終難厭，欲把風騷繼古風。"]'),
('yuding-40','貽毗陵正勤禪院奉長老','李中','唐','御定全唐诗','yuding','','[]','隨緣駐瓶錫，心已悟無生。默坐煙霞散，閑觀水月明。',48,'御定全唐詩/json/750.json','["隨緣駐瓶錫，心已悟無生。默坐煙霞散，閑觀水月明。", "竹深風倍冷，堂迥磬偏清。願作傳燈者，忘言學淨名。"]'),
('yuding-41','冬日書懷寄惟真大師','李中','唐','御定全唐诗','yuding','','[]','自別吾師後，風騷道甚孤。雪霜侵鬢髮，音信隔江湖。',96,'御定全唐詩/json/750.json','["自別吾師後，風騷道甚孤。雪霜侵鬢髮，音信隔江湖。", "擾擾悲時世，悠悠役夢途。向公期盡節，多病怕傾壺。", "賤跡雖慚滯，幽情忍使辜。詩成天外句，棋覆夜中圖。", "落壁燈花碎，飄窗雪片粗。煮茶燒栗興，早晚複圍爐。"]'),
('yuding-42','獻中書潘舍人','李中','唐','御定全唐诗','yuding','','[]','運葉半千數，天鐘許國臣。鵬霄開羽翼，鳳闕演絲綸。',312,'御定全唐詩/json/750.json','["運葉半千數，天鐘許國臣。鵬霄開羽翼，鳳闕演絲綸。", "顧問當清夜，從容向紫宸。立言成雅誥，正意敘彝倫。", "樸素偕前哲，馨香越搢紳。褒辭光萬代，優旨重千鈞。", "公退誰堪接，清閒道是鄰。世間身屬幻，物外意通津。", "吊往兼春夢，文高賦複新。琴彈三峽水，屏畫十洲春。", "庭冷鋪苔色，池寒浸月輪。竹風來枕簟，藥氣上衣巾。", "茶譜傳溪叟，棋經受羽人。清虛雖得趣，獻替不妨陳。", "杞梓呈才後，神仙入侍頻。孤寒皆有賴，中外亦同忻。", "有士曾多難，無門得望塵。忙忙罹險阻，往往耗精神。", "尋果巢枝願，終全負米身。遭逢敦孝治，蹇塞值通津。", "最慶清朝祿，還沾白髮親。甘柔心既遂，虛薄報何因。", "遠宦聯綿曆，卑棲夙夜勤。良時空愛惜，末路每悲辛。", "骨立駒猶病，顏凋女尚貧。而今諧顧遇，尺蠖願求伸。"]'),
('yuding-0','早春左省寓直','徐鉉','唐','御定全唐诗','yuding','','[]','旭景鸞臺上，微雲象闕間。時清政事少，日永直官閑。',48,'御定全唐詩/json/751.json','["旭景鸞臺上，微雲象闕間。時清政事少，日永直官閑。", "遠籟飛簫管，零冰響佩環。終軍年二十，默坐叩玄關。"]'),
('yuding-1','寒食宿陳公塘上','徐鉉','唐','御定全唐诗','yuding','','[]','垂楊界官道，茅屋倚高坡。月下春塘水，風中牧豎歌。',48,'御定全唐詩/json/751.json','["垂楊界官道，茅屋倚高坡。月下春塘水，風中牧豎歌。", "折花閑立久，對酒遠情多。今夜孤亭夢，悠揚奈爾何。"]'),
('yuding-2','將去廣陵別史員外南齋','徐鉉','唐','御定全唐诗','yuding','','[]','家聲曾與金張輩，官署今居何宋間。起得高齋臨靜曲，',40,'御定全唐詩/json/751.json','["家聲曾與金張輩，官署今居何宋間。起得高齋臨靜曲，", "賤子今朝獨南去，不堪回首望清閒。"]'),
('yuding-3','將過江題白沙館','徐鉉','唐','御定全唐诗','yuding','','[]','少長在維揚，依然認故鄉。金陵佳麗地，不道少風光。',48,'御定全唐詩/json/751.json','["少長在維揚，依然認故鄉。金陵佳麗地，不道少風光。", "稍望吳台遠，行登楚塞長。殷勤語江嶺，歸夢莫相妨。"]'),
('yuding-4','登甘露寺北望','徐鉉','唐','御定全唐诗','yuding','','[]','京口潮來曲岸平，海門風起浪花生。人行沙上見日影，',40,'御定全唐詩/json/751.json','["京口潮來曲岸平，海門風起浪花生。人行沙上見日影，", "遊人鄉思應如橘，相望須含兩地情。"]'),
('yuding-5','山路花','徐鉉','唐','御定全唐诗','yuding','','[]','不共垂楊映綺寮，倚山臨路自嬌饒。遊人過去知香遠，',40,'御定全唐詩/json/751.json','["不共垂楊映綺寮，倚山臨路自嬌饒。遊人過去知香遠，", "城中春色還如此，幾處笙歌按舞腰。"]'),
('yuding-6','京口江際弄水','徐鉉','唐','御定全唐诗','yuding','','[]','退公求靜獨臨川，揚子江南二月天。百尺翠屏甘露閣，',40,'御定全唐詩/json/751.json','["退公求靜獨臨川，揚子江南二月天。百尺翠屏甘露閣，", "安得乘槎更東去，十洲風外弄潺湲。"]'),
('yuding-7','早春旬假獨直寄江舍人','徐鉉','唐','御定全唐诗','yuding','','[]','省署皆歸沐，西垣公事稀。詠詩前砌立，聽漏向申歸。',48,'御定全唐詩/json/751.json','["省署皆歸沐，西垣公事稀。詠詩前砌立，聽漏向申歸。", "遠思風醒酒，餘寒雨濕衣。春光已堪探，芝蓋共誰飛。"]'),
('yuding-8','從駕東幸呈諸公','徐鉉','唐','御定全唐诗','yuding','','[]','吳公台下舊京城，曾掩衡門過十春。別後不知新景象，',40,'御定全唐詩/json/751.json','["吳公台下舊京城，曾掩衡門過十春。別後不知新景象，", "今日喜為華表鶴，況陪鵷鷺免迷津。"]'),
('yuding-9','重遊木蘭亭','徐鉉','唐','御定全唐诗','yuding','','[]','繚繞長堤帶碧潯，昔年游此尚青衿。蘭橈破浪城陰直，',40,'御定全唐詩/json/751.json','["繚繞長堤帶碧潯，昔年游此尚青衿。蘭橈破浪城陰直，", "那知年長多情後，重憑欄幹一獨吟。"]'),
('yuding-10','賦得彩燕','徐鉉','唐','御定全唐诗','yuding','','[]','縷彩成飛燕，迎和啟蟄時。翠翹生玉指，繡羽拂文楣。',48,'御定全唐詩/json/751.json','["縷彩成飛燕，迎和啟蟄時。翠翹生玉指，繡羽拂文楣。", "詎費銜泥力，無勞剪爪期。化工今在此，翻怪社來遲。"]'),
('yuding-11','送魏舍人仲甫為蘄州判官','徐鉉','唐','御定全唐诗','yuding','','[]','從事蘄春興自長，蘄人應識紫薇郎。山資足後拋名路，',40,'御定全唐詩/json/751.json','["從事蘄春興自長，蘄人應識紫薇郎。山資足後拋名路，", "如聞郡閣吹橫笛，時望青溪憶野王。"]'),
('yuding-12','題殷舍人宅木芙蓉','徐鉉','唐','御定全唐诗','yuding','','[]','憐君庭下木芙蓉，嫋嫋纖枝淡淡紅。曉吐芳心零宿露，',40,'御定全唐詩/json/751.json','["憐君庭下木芙蓉，嫋嫋纖枝淡淡紅。曉吐芳心零宿露，", "默飲數杯應未稱，不知歌管與誰同。"]'),
('yuding-13','送史館高員外使嶺南','徐鉉','唐','御定全唐诗','yuding','','[]','東觀時閒暇，還修喻蜀書。雙旌馳縣道，百越從軺車。',48,'御定全唐詩/json/751.json','["東觀時閒暇，還修喻蜀書。雙旌馳縣道，百越從軺車。", "桂蠹晨餐罷，貪泉訪古初。春江多好景，莫使醉吟疏。"]'),
('yuding-14','春日紫岩山期客不至','徐鉉','唐','御定全唐诗','yuding','','[]','郊外春華好，人家帶碧溪。淺莎藏鴨戲，輕靄隔雞啼。',48,'御定全唐詩/json/751.json','["郊外春華好，人家帶碧溪。淺莎藏鴨戲，輕靄隔雞啼。", "掩映紅桃穀，夤緣翠柳堤。王孫竟不至，芳草自萋萋。"]'),
('yuding-15','宿蔣帝廟，明日游山南諸寺','徐鉉','唐','御定全唐诗','yuding','','[]','便返城闉尚未甘，更從山北到山南。花枝似雪春雖半，',40,'御定全唐詩/json/751.json','["便返城闉尚未甘，更從山北到山南。花枝似雪春雖半，", "登臨莫怪偏留戀，遊宦多年事事諳。"]'),
('yuding-16','賦得有所思','徐鉉','唐','御定全唐诗','yuding','','[]','所思何在杳難尋，路遠山長水複深。衰草滿庭空佇立，',40,'御定全唐詩/json/751.json','["所思何在杳難尋，路遠山長水複深。衰草滿庭空佇立，", "落日鮮雲偏聚散，可能知我獨傷心。"]'),
('yuding-17','贈王貞素先生','徐鉉','唐','御定全唐诗','yuding','','[]','先生嘗已佩真形，紺發朱顏骨氣清。道秘未傳鴻寶術，',40,'御定全唐詩/json/751.json','["先生嘗已佩真形，紺發朱顏骨氣清。道秘未傳鴻寶術，", "三十六天皆有籍，他年何處問歸程。"]'),
('yuding-18','春夜月','徐鉉','唐','御定全唐诗','yuding','','[]','幽人春望本多情，況是花繁月正明。',32,'御定全唐詩/json/751.json','["幽人春望本多情，況是花繁月正明。", "竟夕無言亦無寐，繞階芳草影隨行。"]'),
('yuding-19','愛敬寺有老僧嘗游長安言秦雍間事歷歷可聽…示同行客','徐鉉','唐','御定全唐诗','yuding','','[]','白首棲禪者，嘗談灞滻遊。能令過江客，偏起失鄉愁。',48,'御定全唐詩/json/751.json','["白首棲禪者，嘗談灞滻遊。能令過江客，偏起失鄉愁。", "室倚桃花崦，門臨杜若洲。城中無此景，將子剩淹留。"]'),
('yuding-20','游蔣山題辛夷花寄陳奉禮','徐鉉','唐','御定全唐诗','yuding','','[]','今歲遊山已恨遲，山中仍喜見辛夷。簪纓且免全為累，',40,'御定全唐詩/json/751.json','["今歲遊山已恨遲，山中仍喜見辛夷。簪纓且免全為累，", "山郎不作同行伴，折得何由寄所思。"]'),
('yuding-21','和殷舍人蕭員外春雪','徐鉉','唐','御定全唐诗','yuding','','[]','萬里春陰乍履端，廣庭風起玉塵幹。梅花嶺上連天白，',40,'御定全唐詩/json/751.json','["萬里春陰乍履端，廣庭風起玉塵幹。梅花嶺上連天白，", "此時鴛侶皆閒暇，贈答詩成禁漏殘。"]'),
('yuding-22','寄蘄州高郎中','徐鉉','唐','御定全唐诗','yuding','','[]','賈傅棲遲楚澤東，蘭皋三度換秋風。紛紛世事來無盡，',40,'御定全唐詩/json/751.json','["賈傅棲遲楚澤東，蘭皋三度換秋風。紛紛世事來無盡，", "知君多少思鄉恨，並在山城一笛中。"]'),
('yuding-23','寄和州韓舍人','徐鉉','唐','御定全唐诗','yuding','','[]','急景駸駸度，遙懷處處生。風頭乍寒暖，天色半陰晴。',48,'御定全唐詩/json/751.json','["急景駸駸度，遙懷處處生。風頭乍寒暖，天色半陰晴。", "久別魂空斷，終年道不行。殷勤雲上雁，為過曆陽城。"]'),
('yuding-24','從兄龍武將軍沒于邊戍，過舊營宅作','徐鉉','唐','御定全唐诗','yuding','','[]','前年都尉沒邊城，帳下何人領舊兵。徼外瘴煙沉鼓角，',40,'御定全唐詩/json/751.json','["前年都尉沒邊城，帳下何人領舊兵。徼外瘴煙沉鼓角，", "今日園林過寒食，馬蹄猶擬入門行。"]'),
('yuding-25','景陽臺懷古','徐鉉','唐','御定全唐诗','yuding','','[]','後主忘家不悔，江南異代長春。',28,'御定全唐詩/json/751.json','["後主忘家不悔，江南異代長春。", "今日景陽臺上，閒人何用傷神。"]'),
('yuding-26','春分日','徐鉉','唐','御定全唐诗','yuding','','[]','仲春初四日，春色正中分。綠野徘徊月，晴天斷續雲。',48,'御定全唐詩/json/751.json','["仲春初四日，春色正中分。綠野徘徊月，晴天斷續雲。", "燕飛猶個個，花落已紛紛。思婦高樓晚，歌聲不可聞。"]'),
('yuding-27','寄駕部郎中','徐鉉','唐','御定全唐诗','yuding','','[]','賤子乖慵性，頻為省直牽。交親每相見，多在相門前。',48,'御定全唐詩/json/751.json','["賤子乖慵性，頻為省直牽。交親每相見，多在相門前。", "君獨疏名路，為郎過十年。炎風久成別，南望思悠然。"]'),
('yuding-28','和王庶子寄題兄長建州廉使新亭','徐鉉','唐','御定全唐诗','yuding','','[]','謝守高齋結構新，一方風景萬家情。群賢詎減山陰會，',40,'御定全唐詩/json/751.json','["謝守高齋結構新，一方風景萬家情。群賢詎減山陰會，", "阿連詩句偏多思，遙想池塘晝夢成。"]'),
('yuding-29','謝文靖墓下作','徐鉉','唐','御定全唐诗','yuding','','[]','越徼稽天討，周京亂虜塵。蒼生何可奈，江表更無人。',48,'御定全唐詩/json/751.json','["越徼稽天討，周京亂虜塵。蒼生何可奈，江表更無人。", "豈憚尋荒壟，猶思認後身。春風白楊裏，獨步淚沾巾。"]'),
('yuding-0','《觀人讀春秋》','徐鉉','唐','御定全唐诗','yuding','','[]','日覺儒風薄，誰將霸道羞。亂臣無所懼，何用讀春秋。',24,'御定全唐詩/json/752.json','["日覺儒風薄，誰將霸道羞。亂臣無所懼，何用讀春秋。"]'),
('yuding-1','秋日雨中與蕭贊善訪殷舍人于翰林座中作','徐鉉','唐','御定全唐诗','yuding','','[]','野出西垣步步遲，秋光如水雨如絲。銅龍樓下逢閑客，',40,'御定全唐詩/json/752.json','["野出西垣步步遲，秋光如水雨如絲。銅龍樓下逢閑客，", "銀台鑰入須歸去，不惜餘歡盡酒卮。"]'),
('yuding-2','送和州張員外為江都令','徐鉉','唐','御定全唐诗','yuding','','[]','經年相望隔重湖，一旦相逢在上都。塞詔官班聊慰否，',40,'御定全唐詩/json/752.json','["經年相望隔重湖，一旦相逢在上都。塞詔官班聊慰否，", "若向西岡尋勝賞，舊題名處為躊躇。"]'),
('yuding-3','和明道人宿山寺','徐鉉','唐','御定全唐诗','yuding','','[]','聞道經行處，山前與水陽。磬聲深小院，燈影迥高房。',48,'御定全唐詩/json/752.json','["聞道經行處，山前與水陽。磬聲深小院，燈影迥高房。", "落宿依樓角，歸雲擁殿廊。羨師閑未得，早起逐班行。"]'),
('yuding-4','晚歸','徐鉉','唐','御定全唐诗','yuding','','[]','暑服道情出，煙街薄暮還。風清飄短袂，馬健弄連環。',48,'御定全唐詩/json/752.json','["暑服道情出，煙街薄暮還。風清飄短袂，馬健弄連環。", "水靜聞歸櫓，霞明見遠山。過從本無事，從此涉旬間。"]'),
('yuding-5','月真歌','徐鉉','唐','御定全唐诗','yuding','','[]','揚州勝地多麗人，其間麗者名月真。月真初年十四五，',184,'御定全唐詩/json/752.json','["揚州勝地多麗人，其間麗者名月真。月真初年十四五，", "揚州帝京多名賢，其間賢者殷德川。德川初秉綸闈筆，", "閒庭深院資賢宅，宅門嚴峻無凡客。垂簾偶坐唯月真，", "朝雲暮雨鎮相隨，石頭城下還相遇。二月三月江南春，", "綠窗繡幌天將曉，殘燭依依香嫋嫋。離腸卻恨苦多情，", "人間想望不可見，唯向月真存舊心。我慚闒茸何為者，", "我本山人愚且貞，歌筵歌席常無情。自從一見月真後，", "良辰美景數追隨，莫教長說相思苦。"]'),
('yuding-6','走筆送義興令趙宣輔','徐鉉','唐','御定全唐诗','yuding','','[]','聞君孤棹泛荊溪，隴首雲隨別恨飛。',32,'御定全唐詩/json/752.json','["聞君孤棹泛荊溪，隴首雲隨別恨飛。", "杜牧舊居憑買取，他年藜杖願同歸。"]'),
('yuding-7','天闕山絕句','徐鉉','唐','御定全唐诗','yuding','','[]','散誕愛山客，淒涼懷古心。寒風天闕晚，盡日倚軒吟。',24,'御定全唐詩/json/752.json','["散誕愛山客，淒涼懷古心。寒風天闕晚，盡日倚軒吟。"]'),
('yuding-8','除夜','徐鉉','唐','御定全唐诗','yuding','','[]','寒燈耿耿漏遲遲，送故迎新了不欺。往事並隨殘曆日，',40,'御定全唐詩/json/752.json','["寒燈耿耿漏遲遲，送故迎新了不欺。往事並隨殘曆日，", "吟罷明朝贈知己，便須題作去年詩。"]'),
('yuding-9','寄鐘謨','徐鉉','唐','御定全唐诗','yuding','','[]','看看潘鬢二毛生，昨日林梢又轉鶯。欲對春風忘世慮，',40,'御定全唐詩/json/752.json','["看看潘鬢二毛生，昨日林梢又轉鶯。欲對春風忘世慮，", "不得車公終不樂，已教紅袖出門迎。"]'),
('yuding-10','正初答鐘郎中見招','徐鉉','唐','御定全唐诗','yuding','','[]','高齋遲景雪初晴，風拂喬枝待早鶯。南省郎官名籍籍，',40,'御定全唐詩/json/752.json','["高齋遲景雪初晴，風拂喬枝待早鶯。南省郎官名籍籍，", "新歲相思自過訪，不煩虛左遠相迎。"]'),
('yuding-11','聞雁寄故人','徐鉉','唐','御定全唐诗','yuding','','[]','久作他鄉客，深慚薄宦非。不知雲上雁，何得每年歸。',48,'御定全唐詩/json/752.json','["久作他鄉客，深慚薄宦非。不知雲上雁，何得每年歸。", "夜靜聲彌怨，天空影更微。往年離別淚，今夕重沾衣。"]'),
('yuding-12','江舍人宅筵上有妓唱和州韓舍人歌辭，因以寄','徐鉉','唐','御定全唐诗','yuding','','[]','良宵絲竹偶成歡，中有佳人俯翠鬟。白雪飄颻傳樂府，',40,'御定全唐詩/json/752.json','["良宵絲竹偶成歡，中有佳人俯翠鬟。白雪飄颻傳樂府，", "深夜酒空筵欲散，向隅惆悵鬢堪斑。"]'),
('yuding-13','寒食日作','徐鉉','唐','御定全唐诗','yuding','','[]','廚冷煙初禁，門閑日更斜。東風不好事，吹落滿庭花。',48,'御定全唐詩/json/752.json','["廚冷煙初禁，門閑日更斜。東風不好事，吹落滿庭花。", "過社紛紛燕，新晴淡淡霞。京都盛遊觀，誰訪子雲家。"]'),
('yuding-14','賀殷遊二舍人入翰林、江給事拜中丞','徐鉉','唐','御定全唐诗','yuding','','[]','清晨待漏獨徘徊，霄漢懸心不易裁。閣老深嚴歸翰苑，',40,'御定全唐詩/json/752.json','["清晨待漏獨徘徊，霄漢懸心不易裁。閣老深嚴歸翰苑，", "猶有西垣廳記在，莫忘同草紫泥來。"]'),
('yuding-15','歐陽太監雨中視決堤因墮水明日見於省中因戲之','徐鉉','唐','御定全唐诗','yuding','','[]','聞道張晨蓋，徘徊石首東。浚川非伯禹，落水異三公。',48,'御定全唐詩/json/752.json','["聞道張晨蓋，徘徊石首東。浚川非伯禹，落水異三公。", "衣濕仍愁雨，冠欹更怯風。今朝複相見，疑是葛仙翁。"]'),
('yuding-16','送吳郎中為宣州推官知涇縣','徐鉉','唐','御定全唐诗','yuding','','[]','征虜亭邊月，雞鳴伴客行。可憐何水部，今事謝宣城。',48,'御定全唐詩/json/752.json','["征虜亭邊月，雞鳴伴客行。可憐何水部，今事謝宣城。", "風物聊供賞，班資莫系情。同心不同載，留滯為浮名。"]'),
('yuding-17','寄舒州杜員外','徐鉉','唐','御定全唐诗','yuding','','[]','信到得君書，知君已下車。粉闈情在否，蓮幕興何如。',48,'御定全唐詩/json/752.json','["信到得君書，知君已下車。粉闈情在否，蓮幕興何如。", "人望征賢入，餘思從子居。灊山真隱地，憑為卜茅廬。"]'),
('yuding-18','九月十一日寄陳郎中','徐鉉','唐','御定全唐诗','yuding','','[]','我多吏事君多病，寂絕過從又幾旬。',32,'御定全唐詩/json/752.json','["我多吏事君多病，寂絕過從又幾旬。", "前日龍山煙景好，風前落帽是何人。"]'),
('yuding-19','和司門郎中陳彥','徐鉉','唐','御定全唐诗','yuding','','[]','衡門寂寂逢迎少，不見仙郎向五旬。',32,'御定全唐詩/json/752.json','["衡門寂寂逢迎少，不見仙郎向五旬。", "莫問龍山前日事，菊花開卻為閒人。"]'),
('yuding-20','賦得擣衣','徐鉉','唐','御定全唐诗','yuding','','[]','江上多離別，居人夜擣衣。拂砧知露滴，促杵恐霜飛。',48,'御定全唐詩/json/752.json','["江上多離別，居人夜擣衣。拂砧知露滴，促杵恐霜飛。", "漏轉聲頻斷，愁多力自微。裁縫依夢見，腰帶定應非。"]'),
('yuding-21','九月三十夜雨寄故人','徐鉉','唐','御定全唐诗','yuding','','[]','獨聽空階雨，方知秋事悲。寂寥旬假日，蕭颯夜長時。',48,'御定全唐詩/json/752.json','["獨聽空階雨，方知秋事悲。寂寥旬假日，蕭颯夜長時。", "別念紛紛起，寒更故故遲。情人如不醉，定是兩相思。"]'),
('yuding-22','寄撫州鐘郎中','徐鉉','唐','御定全唐诗','yuding','','[]','去載分襟後，尋聞在建安。封疆正多事，尊俎若為歡。',48,'御定全唐詩/json/752.json','["去載分襟後，尋聞在建安。封疆正多事，尊俎若為歡。", "都護空遺鏃，明君欲舞幹。繞朝時不用，非是殺身難。"]'),
('yuding-23','送歐陽太監游廬山','徐鉉','唐','御定全唐诗','yuding','','[]','家家門外廬山路，唯有夫君乞假游。案牘乍拋公署晚，',40,'御定全唐詩/json/752.json','["家家門外廬山路，唯有夫君乞假游。案牘乍拋公署晚，", "此去蕭然好長往，人間何事不悠悠。"]'),
('yuding-24','立秋後一日與朱舍人同直','徐鉉','唐','御定全唐诗','yuding','','[]','一宿秋風未覺涼，數聲宮漏日猶長。',32,'御定全唐詩/json/752.json','["一宿秋風未覺涼，數聲宮漏日猶長。", "林泉無計消殘暑，虛向華池費稻粱。"]'),
('yuding-25','賦得霍將軍辭第','徐鉉','唐','御定全唐诗','yuding','','[]','漢將承恩久，圖勳肯顧私。匈奴猶未滅，安用以家為。',72,'御定全唐詩/json/752.json','["漢將承恩久，圖勳肯顧私。匈奴猶未滅，安用以家為。", "郢匠雖聞詔，衡門竟不移。甯煩張老頌，無待晏嬰辭。", "甲乙人徒費，親鄰我自持。悠悠千載下，長作帥臣師。"]'),
('yuding-26','和元帥書記蕭郎中觀習水師','徐鉉','唐','御定全唐诗','yuding','','[]','元帥樓船出治兵，落星山外火旗明。千帆日助江陵勢，',40,'御定全唐詩/json/752.json','["元帥樓船出治兵，落星山外火旗明。千帆日助江陵勢，", "仲宣一作從軍詠，回顧儒衣自不平。"]'),
('yuding-27','秋日盧龍村舍','徐鉉','唐','御定全唐诗','yuding','','[]','置卻人間事，閑從野老遊。樹聲村店晚，草色古城秋。',48,'御定全唐詩/json/752.json','["置卻人間事，閑從野老遊。樹聲村店晚，草色古城秋。", "獨鳥飛天外，閑雲度隴頭。姓名君莫問，山木與虛舟。"]'),
('yuding-28','和蕭郎中小雪日作','徐鉉','唐','御定全唐诗','yuding','','[]','征西府裏日西斜，獨試新爐自煮茶。籬菊盡來低覆水，',40,'御定全唐詩/json/752.json','["征西府裏日西斜，獨試新爐自煮茶。籬菊盡來低覆水，", "算得流年無奈處，莫將詩句祝蒼華。"]'),
('yuding-29','中書相公溪亭閑宴依韻','徐鉉','唐','御定全唐诗','yuding','','[]','雨霽秋光晚，亭虛野興回。沙鷗掠岸去，溪水上階來。',48,'御定全唐詩/json/752.json','["雨霽秋光晚，亭虛野興回。沙鷗掠岸去，溪水上階來。", "客傲風欹幘，筵香菊在杯。東山長許醉，何事憶天臺。"]'),
('yuding-30','寄饒州王郎中效李白體','徐鉉','唐','御定全唐诗','yuding','','[]','珍重王光嗣，交情尚在不。蕪城連宅住，楚塞並車遊。',48,'御定全唐詩/json/752.json','["珍重王光嗣，交情尚在不。蕪城連宅住，楚塞並車遊。", "別後官三改，年來歲六周。銀鉤無一字，何以緩離愁。"]'),
('yuding-31','寄歙州呂判官','徐鉉','唐','御定全唐诗','yuding','','[]','任公郡占好山川，溪水縈回路屈盤。南國自來推勝境，',40,'御定全唐詩/json/752.json','["任公郡占好山川，溪水縈回路屈盤。南國自來推勝境，", "莫憶班行重回首，是非多處是長安。"]'),
('yuding-32','宣威苗將軍貶官後重經故宅','徐鉉','唐','御定全唐诗','yuding','','[]','蔣山南望近西坊，亭館依然鎖院牆。天子未嘗過細柳，',40,'御定全唐詩/json/752.json','["蔣山南望近西坊，亭館依然鎖院牆。天子未嘗過細柳，", "為將為儒皆寂寞，門前愁殺馬中郎。"]'),
('yuding-33','附池州薛郎中書因寄歙州張員外','徐鉉','唐','御定全唐诗','yuding','','[]','新安從事舊台郎，直氣多才不可忘。一旦江山馳別夢，',40,'御定全唐詩/json/752.json','["新安從事舊台郎，直氣多才不可忘。一旦江山馳別夢，", "因附鄰州寄消息，接輿今日信為狂。"]'),
('yuding-34','寄江都路員外','徐鉉','唐','御定全唐诗','yuding','','[]','吾兄失意在東都，聞說襟懷任所如。已縱乖慵為傲吏，',40,'御定全唐詩/json/752.json','["吾兄失意在東都，聞說襟懷任所如。已縱乖慵為傲吏，", "知道故人相憶否，嵇康不得懶修書。"]'),
('yuding-35','張員外好茅山風景，求為句容令，作此送','徐鉉','唐','御定全唐诗','yuding','','[]','句曲山前縣，依依數舍程。還同適勾漏，非是厭承明。',48,'御定全唐詩/json/752.json','["句曲山前縣，依依數舍程。還同適勾漏，非是厭承明。", "柳谷供詩景，華陽契道情。金門容傲吏，官滿且還城。"]'),
('yuding-36','送應之道人歸江西','徐鉉','唐','御定全唐诗','yuding','','[]','曾騎竹馬傍洪厓，二十餘年變物華。客夢等閒過驛閣，',40,'御定全唐詩/json/752.json','["曾騎竹馬傍洪厓，二十餘年變物華。客夢等閒過驛閣，", "歲暮定知回未得，信來憑為寄梅花。"]'),
('yuding-37','送元帥書記高郎中出為婺源建威軍使','徐鉉','唐','御定全唐诗','yuding','','[]','寒風蕭瑟楚江南，記室戎裝掛錦帆。倚馬未曾妨笑傲，',40,'御定全唐詩/json/752.json','["寒風蕭瑟楚江南，記室戎裝掛錦帆。倚馬未曾妨笑傲，", "惟有杯盤思上國，酒醪甜淡菜蔬甘。"]'),
('yuding-38','游方山宿李道士房','徐鉉','唐','御定全唐诗','yuding','','[]','從來未面李先生，借我西窗臥月明。',32,'御定全唐詩/json/752.json','["從來未面李先生，借我西窗臥月明。", "二十三家同願識，素騾何日暫還城。"]'),
('yuding-39','題畫石山','徐鉉','唐','御定全唐诗','yuding','','[]','彼美巉岩石，誰施黼藻功。回岩明照地，絕壁爛臨空。',96,'御定全唐詩/json/752.json','["彼美巉岩石，誰施黼藻功。回岩明照地，絕壁爛臨空。", "錦段鮮須濯，羅屏展易窮。不因秋蘚綠，非假晚霞紅。", "羽客藏書洞，樵人取箭風。靈蹤理難問，仙路去何通。", "返駕歸塵裏，留情向此中。回瞻畫圖畔，遙羨面山翁。"]'),
('yuding-40','臨石步港','徐鉉','唐','御定全唐诗','yuding','','[]','埼岸墮縈帶，微風起細漣。綠陰三月後，倒影亂峰前。',48,'御定全唐詩/json/752.json','["埼岸墮縈帶，微風起細漣。綠陰三月後，倒影亂峰前。", "吹浪遊鱗小，黏苔碎石圓。會將腰下組，換取釣魚船。"]'),
('yuding-41','病題二首','徐鉉','唐','御定全唐诗','yuding','','[]','性靈慵懶百無能，唯被朝參遣夙興。聖主優容恩未答，',80,'御定全唐詩/json/752.json','["性靈慵懶百無能，唯被朝參遣夙興。聖主優容恩未答，", "進與時乖不知退，可憐身計謾騰騰。", "人間多事本難論，況是人間懶慢人。不解養生何怪病，", "金馬門前君識否，東方曼倩是前身。"]'),
('yuding-42','寄江州蕭給事','徐鉉','唐','御定全唐诗','yuding','','[]','夕郎憂國不憂身，今向天涯作逐臣。魂夢暗馳龍闕曙，',40,'御定全唐詩/json/752.json','["夕郎憂國不憂身，今向天涯作逐臣。魂夢暗馳龍闕曙，", "惆悵懦夫何足道，自離群後已同塵。"]'),
('yuding-43','和江州江中丞見寄','徐鉉','唐','御定全唐诗','yuding','','[]','賈傅南遷久，江關道路遙。北來空見雁，西去不如潮。',48,'御定全唐詩/json/752.json','["賈傅南遷久，江關道路遙。北來空見雁，西去不如潮。", "鼠穴依城社，鴻飛在泬寥。高低各有處，不擬更相招。"]'),
('yuding-44','和鐘郎中送朱先輩還京垂寄','徐鉉','唐','御定全唐诗','yuding','','[]','分司洗馬無人問，辭客殷勤輟棹歌。蒼蘚滿庭行徑小，',40,'御定全唐詩/json/752.json','["分司洗馬無人問，辭客殷勤輟棹歌。蒼蘚滿庭行徑小，", "且共勝遊消永日，西岡風物近如何。"]'),
('yuding-45','送郝郎中為浙西判官','徐鉉','唐','御定全唐诗','yuding','','[]','大藩從事本優賢，幕府仍當北固前。花繞樓臺山倚郭，',40,'御定全唐詩/json/752.json','["大藩從事本優賢，幕府仍當北固前。花繞樓臺山倚郭，", "若許他時作閑伴，殷勤為買釣魚船。"]'),
('yuding-46','翰林游舍人清明日入院中途見過餘明日…因寄游君','徐鉉','唐','御定全唐诗','yuding','','[]','榆柳開新焰，梨花發故枝。輜輧隘城市，圭組坐曹司。',48,'御定全唐詩/json/752.json','["榆柳開新焰，梨花發故枝。輜輧隘城市，圭組坐曹司。", "獨對芝泥檢，遙憐白馬兒。禁林還視草，氣味兩相知。"]'),
('yuding-47','陪王庶子遊後湖涵虛閣','徐鉉','唐','御定全唐诗','yuding','','[]','懸圃清虛乍過秋，看山尋水上茲樓。輕鷗的的飛難沒，',40,'御定全唐詩/json/752.json','["懸圃清虛乍過秋，看山尋水上茲樓。輕鷗的的飛難沒，", "躋攀況有承華客，如在南皮奉勝遊。"]'),
('yuding-48','柳枝辭十二首','徐鉉','唐','御定全唐诗','yuding','','[]','把酒憑君唱柳枝，也從絲管遞相隨。',384,'御定全唐詩/json/752.json','["把酒憑君唱柳枝，也從絲管遞相隨。", "逢春只合朝朝醉，記取秋風落葉時。", "南園日暮起春風，吹散楊花雪滿空。", "不惜楊花飛也得，愁君老盡臉邊紅。", "陌上朱門柳映花，簾鉤半卷綠陰斜。", "憑郎暫駐青驄馬，此是錢塘小小家。", "夾岸朱欄柳映樓，綠波平幔帶花流。", "歌聲不出長條密，忽地風回見彩舟。", "老大逢春總恨春，綠楊陰裏最愁人。", "舊遊一別無因見，嫩葉如眉處處新。", "濛濛堤畔柳含煙，疑是陽和二月天。", "醉裏不知時節改，漫隨兒女打秋千。", "水閣春來乍減寒，曉妝初罷倚欄幹。", "長條亂拂春波動，不許佳人照影看。", "柳岸煙昏醉裏歸，不知深處有芳菲。", "重來已見花飄盡，唯有黃鶯囀樹飛。", "此去仙源不是遙，垂楊深處有朱橋。", "共君同過朱橋去，索映垂楊聽洞簫。", "暫別揚州十度春，不知光景屬何人。", "一帆歸客千條柳，腸斷東風揚子津。", "仙樂春來按舞腰，清聲偏似傍嬌饒。", "應緣鶯舌多情賴，長向雙成說翠條。", "鳳笙臨檻不能吹，舞袖當筵亦自疑。", "唯有美人多意緒，解依芳態畫雙眉。"]'),
('yuding-49','貶官泰州出城作','徐鉉','唐','御定全唐诗','yuding','','[]','浮名浮利信悠悠，四海干戈痛主憂。三諫不從為逐客，',40,'御定全唐詩/json/752.json','["浮名浮利信悠悠，四海干戈痛主憂。三諫不從為逐客，", "惟有戀恩終不改，半程猶自望城樓。"]'),
('yuding-50','過江','徐鉉','唐','御定全唐诗','yuding','','[]','別路知何極，離腸有所思。登艫望城遠，搖櫓過江遲。',48,'御定全唐詩/json/752.json','["別路知何極，離腸有所思。登艫望城遠，搖櫓過江遲。", "斷岸煙中失，長天水際垂。此心非橘柚，不為兩鄉移。"]'),
('yuding-51','經東都太子橋','徐鉉','唐','御定全唐诗','yuding','','[]','綸闈放逐知何道，桂苑風流且暫歸。',32,'御定全唐詩/json/752.json','["綸闈放逐知何道，桂苑風流且暫歸。", "莫問升遷橋上客，身謀疏拙舊心違。"]'),
('yuding-0','贈維揚故人','徐鉉','唐','御定全唐诗','yuding','','[]','東京少長認維桑，書劍誰教入帝鄉。一事無成空放逐，',40,'御定全唐詩/json/753.json','["東京少長認維桑，書劍誰教入帝鄉。一事無成空放逐，", "莫怪臨風惆悵久，十年春色憶維揚。"]'),
('yuding-1','泰州道中卻寄東京故人','徐鉉','唐','御定全唐诗','yuding','','[]','風緊雨淒淒，川回岸漸低。吳州林外近，隋苑霧中迷。',48,'御定全唐詩/json/753.json','["風緊雨淒淒，川回岸漸低。吳州林外近，隋苑霧中迷。", "聚散紛如此，悲歡豈易齊。料君殘酒醒，還聽子規啼。"]'),
('yuding-2','得浙西郝判官書未及報聞燕王移鎮京口…田書記消息','徐鉉','唐','御定全唐诗','yuding','','[]','秋風海上久離居，曾得劉公一紙書。淡水心情長若此，',40,'御定全唐詩/json/753.json','["秋風海上久離居，曾得劉公一紙書。淡水心情長若此，", "今日京吳建朱邸，問君誰共曳長裾。"]'),
('yuding-3','贈陶使君求梨','徐鉉','唐','御定全唐诗','yuding','','[]','昨宵宴罷醉如泥，惟憶張公大穀梨。白玉花繁曾綴處，',40,'御定全唐詩/json/753.json','["昨宵宴罷醉如泥，惟憶張公大穀梨。白玉花繁曾綴處，", "今旦中山方酒渴，唯應此物最相宜。"]'),
('yuding-4','陳覺放還至泰州，以詩見寄，作此答之','徐鉉','唐','御定全唐诗','yuding','','[]','朱雲曾為漢家憂，不怕交親作世仇。壯氣未平空咄咄，',40,'御定全唐詩/json/753.json','["朱雲曾為漢家憂，不怕交親作世仇。壯氣未平空咄咄，", "勞寄新詩平宿憾，此生心氣貫清秋。"]'),
('yuding-5','王三十七自京垂訪，作此送之','徐鉉','唐','御定全唐诗','yuding','','[]','失鄉遷客在天涯，門掩苔垣向水斜。只就鱗鴻求遠信，',40,'御定全唐詩/json/753.json','["失鄉遷客在天涯，門掩苔垣向水斜。只就鱗鴻求遠信，", "惆悵明朝尊酒散，夢魂相送到京華。"]'),
('yuding-6','陶使君挽歌二首','徐鉉','唐','御定全唐诗','yuding','','[]','太守今何在，行春去不歸。筵空收管吹，郊迥儼驂騑。',96,'御定全唐詩/json/753.json','["太守今何在，行春去不歸。筵空收管吹，郊迥儼驂騑。", "營外星才落，園中露已稀。傷心梁上燕，猶解向人飛。", "始憶花前宴，笙歌醉夕陽。那堪城外送，哀挽逐歸艎。", "鈴閣朝猶閉，風亭日已荒。唯餘遷客淚，沾灑後池傍。"]'),
('yuding-7','雪中作','徐鉉','唐','御定全唐诗','yuding','','[]','賦分多情客，經年去國心。疏鐘寒郭晚，密雪水亭深。',48,'御定全唐詩/json/753.json','["賦分多情客，經年去國心。疏鐘寒郭晚，密雪水亭深。", "影迥鴻投渚，聲愁雀噪林。他鄉一尊酒，獨坐不成斟。"]'),
('yuding-8','賦得風光草際浮','徐鉉','唐','御定全唐诗','yuding','','[]','宿露依芳草，春郊古陌旁。風輕不盡偃，日早未晞陽。',72,'御定全唐詩/json/753.json','["宿露依芳草，春郊古陌旁。風輕不盡偃，日早未晞陽。", "耿耿依平遠，離離入望長。映空無定彩，飄徑有餘光。", "颭若荷珠亂，紛如爝火颺。詩人多感物，凝思繞池塘。"]'),
('yuding-9','寒食成判官垂訪因贈','徐鉉','唐','御定全唐诗','yuding','','[]','常年寒食在京華，今歲清明在海涯。遠巷蹋歌深夜月，',40,'御定全唐詩/json/753.json','["常年寒食在京華，今歲清明在海涯。遠巷蹋歌深夜月，", "不是多情成二十，斷無人解訪貧家。"]'),
('yuding-10','送客至城西，望圖山，因寄浙西府中','徐鉉','唐','御定全唐诗','yuding','','[]','牧叟鄒生笑語同，莫嗟江上聽秋風。',32,'御定全唐詩/json/753.json','["牧叟鄒生笑語同，莫嗟江上聽秋風。", "君看逐客思鄉處，猶在圖山更向東。"]'),
('yuding-11','送寫真成處士入京','徐鉉','唐','御定全唐诗','yuding','','[]','傳神蹤跡本來高，澤畔形容愧彩毫。',32,'御定全唐詩/json/753.json','["傳神蹤跡本來高，澤畔形容愧彩毫。", "京邑功臣多佇望，淩煙閣上莫辭勞。"]'),
('yuding-12','九日雨中','徐鉉','唐','御定全唐诗','yuding','','[]','茱萸房重雨霏微，去國逢秋此恨稀。目極暫登臺上望，',40,'御定全唐詩/json/753.json','["茱萸房重雨霏微，去國逢秋此恨稀。目極暫登臺上望，", "唯有多情一枝菊，滿杯顏色自依依。"]'),
('yuding-13','寄外甥苗武仲','徐鉉','唐','御定全唐诗','yuding','','[]','放逐今來漲海邊，親情多在鳳台前。且將聚散為閒事，',40,'御定全唐詩/json/753.json','["放逐今來漲海邊，親情多在鳳台前。且將聚散為閒事，", "此中唯欠韓康伯，共對秋風詠數篇。"]'),
('yuding-14','寄從兄憲兼示二弟','徐鉉','唐','御定全唐诗','yuding','','[]','別路吳將楚，離憂弟與兄。斷雲驚晚吹，秋色滿孤城。',48,'御定全唐詩/json/753.json','["別路吳將楚，離憂弟與兄。斷雲驚晚吹，秋色滿孤城。", "信遠鴻初下，鄉遙月共明。一枝棲未穩，回首望三京。"]'),
('yuding-15','附書與鐘郎中因寄京妓越賓','徐鉉','唐','御定全唐诗','yuding','','[]','暮春橋下手封書，寄向江南問越姑。',32,'御定全唐詩/json/753.json','["暮春橋下手封書，寄向江南問越姑。", "不道諸郎少歡笑，經年相別憶儂無。"]'),
('yuding-16','代鐘答','徐鉉','唐','御定全唐诗','yuding','','[]','一幅輕綃寄海濱，越姑長感昔時恩。',32,'御定全唐詩/json/753.json','["一幅輕綃寄海濱，越姑長感昔時恩。", "欲知別後情多少，點點憑君看淚痕。"]'),
('yuding-17','亞元舍人不替深知猥貽佳作三篇清絕不敢輕…庶資一笑耳','徐鉉','唐','御定全唐诗','yuding','','[]','海陵城裏春正月，海畔朝陽照殘雪。城中有客獨登樓，',384,'御定全唐詩/json/753.json','["海陵城裏春正月，海畔朝陽照殘雪。城中有客獨登樓，", "閶門曉辟旌旗影，玉墀風細佩環聲。此處追飛皆俊彥，", "王言簡靜官司閑，朋好殷勤多往還。新亭風景如東洛，", "有時邀賓複攜妓，造門不問都非是。酣歌叫笑驚四鄰，", "可憐諸貴賢且才，時情物望兩無猜。伊餘獨稟狂狷性，", "一朝削跡為遷客，旦暮青雲千里隔。離鴻別雁各分飛，", "白沙江上曾行路，青林花落何紛紛。漢皇昔幸回中道，", "禪智寺，山光橋，風瑟瑟兮雨蕭蕭。行杯已醒殘夢斷，", "乍申拜起已開眉，卻問辛勤還執手。精廬水榭最清幽，", "郡齋勝境有後池，山亭菌閣互參差。有時虛左來相召，", "酒酣耳熱眼生花，暫似京華歡會處。歸來旅館還端居，", "春來憑檻方歎息，仰頭忽見南來翼。足系紅箋墮我前，", "短韻三篇皆麗絕，小梅寄意情偏切。金蘭投分一何堅，", "長卿曾作美人賦，玄成今有責躬詩。報章欲托還京信，", "寧須買藥療羈愁，只恨無書消鄙吝。遊處當時靡不同，", "曲終筆閣緘封已，翩翩驛騎行塵起。寄向中朝謝故人，"]'),
('yuding-18','送蒯司錄歸京','徐鉉','唐','御定全唐诗','yuding','','[]','早年聞有蒯先生，二十餘年道不行。抵掌曾論天下事，',40,'御定全唐詩/json/753.json','["早年聞有蒯先生，二十餘年道不行。抵掌曾論天下事，", "遷客臨流倍惆悵，冷風黃葉滿山城。"]'),
('yuding-19','聞查建州陷賊寄鐘郎中','徐鉉','唐','御定全唐诗','yuding','','[]','聞道將軍輕壯圖，螺江城下委犀渠。旌旗零落沉荒服，',40,'御定全唐詩/json/753.json','["聞道將軍輕壯圖，螺江城下委犀渠。旌旗零落沉荒服，", "自憐放逐無長策，空使盧諶淚滿裾。"]'),
('yuding-20','還過東都，留守周公筵上贈座客','徐鉉','唐','御定全唐诗','yuding','','[]','賈生三載在長沙，故友相思道路賒。已分終年甘寂寞，',40,'御定全唐詩/json/753.json','["賈生三載在長沙，故友相思道路賒。已分終年甘寂寞，", "明旦江頭倍惆悵，遠山芳草映殘霞。"]'),
('yuding-21','送楊郎中唐員外奉使湖南','徐鉉','唐','御定全唐诗','yuding','','[]','江邊微雨柳條新，握節含香二使臣。兩綬對懸雲夢日，',40,'御定全唐詩/json/753.json','["江邊微雨柳條新，握節含香二使臣。兩綬對懸雲夢日，", "同是多情懷古客，不妨為賦吊靈均。"]'),
('yuding-22','表弟包穎見寄','徐鉉','唐','御定全唐诗','yuding','','[]','常思帝裏奉交親，別後光陰屈指頻。蘭佩卻歸綸閣下，',40,'御定全唐詩/json/753.json','["常思帝裏奉交親，別後光陰屈指頻。蘭佩卻歸綸閣下，", "料得此生強健在，會須重賞昔年春。"]'),
('yuding-23','寄蕭給事','徐鉉','唐','御定全唐诗','yuding','','[]','危言危行古時人，歸向西山臥白雲。買宅尚尋徐處士，',40,'御定全唐詩/json/753.json','["危言危行古時人，歸向西山臥白雲。買宅尚尋徐處士，", "今日城中春又至，落梅愁緒共紛紛。"]'),
('yuding-24','賦石奉送鐘德林少尹員外','徐鉉','唐','御定全唐诗','yuding','','[]','我愛他山石，中含絕代珍。煙披寒落落，沙淺靜磷磷。',48,'御定全唐詩/json/753.json','["我愛他山石，中含絕代珍。煙披寒落落，沙淺靜磷磷。", "翠色辭文陛，清聲出泗濱。扁舟載歸去，知是泛槎人。"]'),
('yuding-0','贈泰州掾令狐克己','徐鉉','唐','御定全唐诗','yuding','','[]','念子才多命且奇，亂中拋擲少年時。深藏七澤衣如雪，',40,'御定全唐詩/json/754.json','["念子才多命且奇，亂中拋擲少年時。深藏七澤衣如雪，", "孤芳自愛淩霜處，詠取文公白菊詩。"]'),
('yuding-1','送荻栽與秀才朱觀','徐鉉','唐','御定全唐诗','yuding','','[]','羨子清吟處，茅齋面碧流。解憎蓮豔俗，唯欠荻花幽。',48,'御定全唐詩/json/754.json','["羨子清吟處，茅齋面碧流。解憎蓮豔俗，唯欠荻花幽。", "鷺立低枝晚，風驚折葉秋。贈君須種取，不必樹忘憂。"]'),
('yuding-2','使浙西先寄獻燕王侍中','徐鉉','唐','御定全唐诗','yuding','','[]','京江風靜喜乘流，極目遙瞻萬歲樓。喜氣蘢蔥甘露晚，',40,'御定全唐詩/json/754.json','["京江風靜喜乘流，極目遙瞻萬歲樓。喜氣蘢蔥甘露晚，", "欲問平臺門下吏，相君還許吐茵不。"]'),
('yuding-3','常州驛中喜雨','徐鉉','唐','御定全唐诗','yuding','','[]','颯颯旱天雨，涼風一夕回。遠尋南畝去，細入驛亭來。',48,'御定全唐詩/json/754.json','["颯颯旱天雨，涼風一夕回。遠尋南畝去，細入驛亭來。", "蓑唱牛初牧，漁歌棹正開。盈庭頓無事，歸思酌金罍。"]'),
('yuding-4','驛中七夕','徐鉉','唐','御定全唐诗','yuding','','[]','七夕雨初霽，行人正憶家。江天望河漢，水館折蓮花。',48,'御定全唐詩/json/754.json','["七夕雨初霽，行人正憶家。江天望河漢，水館折蓮花。", "獨坐涼何甚，微吟月易斜。今年不乞巧，鈍拙轉堪嗟。"]'),
('yuding-5','贈浙西顧推官','徐鉉','唐','御定全唐诗','yuding','','[]','盛府賓寮八十餘，閉門高臥興無如。梁王苑裏相逢早，',40,'御定全唐詩/json/754.json','["盛府賓寮八十餘，閉門高臥興無如。梁王苑裏相逢早，", "願君百歲猶強健，他日相尋隱士廬。"]'),
('yuding-6','贈浙西妓亞仙','徐鉉','唐','御定全唐诗','yuding','','[]','翠黛嚬如怨，朱顏醉更春。占將南國貌，惱殺別家人。',48,'御定全唐詩/json/754.json','["翠黛嚬如怨，朱顏醉更春。占將南國貌，惱殺別家人。", "粉汗沾巡盞，花鈿逐舞茵。明朝綺窗下，離恨兩殷勤。"]'),
('yuding-7','回至瓜洲獻侍中','徐鉉','唐','御定全唐诗','yuding','','[]','紫微垣裏舊賓從，來向吳門謁府公。奉使謬持嚴助節，',40,'御定全唐詩/json/754.json','["紫微垣裏舊賓從，來向吳門謁府公。奉使謬持嚴助節，", "日暮瓜洲江北岸，兩行清淚滴西風。"]'),
('yuding-8','邵伯埭下寄高郵陳郎中','徐鉉','唐','御定全唐诗','yuding','','[]','故人相別動經年，候館相逢倍慘然。顧我飲冰難輟棹，',40,'御定全唐詩/json/754.json','["故人相別動經年，候館相逢倍慘然。顧我飲冰難輟棹，", "欲識酒醒魂斷處，謝公祠畔客亭前。"]'),
('yuding-9','謫居舒州，累得韓高二舍人書，作此寄之','徐鉉','唐','御定全唐诗','yuding','','[]','三峰煙靄碧臨溪，中有騷人理釣絲。會友少於分袂日，',40,'御定全唐詩/json/754.json','["三峰煙靄碧臨溪，中有騷人理釣絲。會友少於分袂日，", "珍重韓君與高子，殷勤書劄寄相思。"]'),
('yuding-10','和張先輩見寄二首','徐鉉','唐','御定全唐诗','yuding','','[]','去國離群擲歲華，病容憔悴愧丹砂。溪連捨下衣長潤，',80,'御定全唐詩/json/754.json','["去國離群擲歲華，病容憔悴愧丹砂。溪連捨下衣長潤，", "故人書劄頻相慰，誰道西京道路賒。", "清時淪放在山州，邛竹紗巾處處遊。野日蒼茫悲鵩舍，", "兩首新詩千里道，感君情分獨知丘。"]'),
('yuding-11','印秀才至舒州見尋，別後寄詩依韻和','徐鉉','唐','御定全唐诗','yuding','','[]','羈游白社身雖屈，高步辭場道不卑。投分共為知我者，',40,'御定全唐詩/json/754.json','["羈游白社身雖屈，高步辭場道不卑。投分共為知我者，", "今日溪邊正相憶，雪晴山秀柳絲垂。"]'),
('yuding-12','行園樹','徐鉉','唐','御定全唐诗','yuding','','[]','松節淩霜久，蓬根逐吹頻。群生各有性，桃李但爭春。',24,'御定全唐詩/json/754.json','["松節淩霜久，蓬根逐吹頻。群生各有性，桃李但爭春。"]'),
('yuding-13','題雷公井','徐鉉','唐','御定全唐诗','yuding','','[]','掩靄愚公谷，蕭寥羽客家。俗人知處所，應為有桃花。',24,'御定全唐詩/json/754.json','["掩靄愚公谷，蕭寥羽客家。俗人知處所，應為有桃花。"]'),
('yuding-14','送彭秀才','徐鉉','唐','御定全唐诗','yuding','','[]','賈生去國已三年，短褐閑行皖水邊。盡日野雲生捨下，',40,'御定全唐詩/json/754.json','["賈生去國已三年，短褐閑行皖水邊。盡日野雲生捨下，", "滿袖新詩好回去，莫隨騷客醉林泉。"]'),
('yuding-15','移饒州別周使君','徐鉉','唐','御定全唐诗','yuding','','[]','正憐東道感賢侯，何幸南冠脫楚囚。睆伯台前收別宴，',40,'御定全唐詩/json/754.json','["正憐東道感賢侯，何幸南冠脫楚囚。睆伯台前收別宴，", "更向鄱陽湖上去，青衫憔悴淚交流。"]'),
('yuding-16','避難東歸，依韻和黃秀才見寄','徐鉉','唐','御定全唐诗','yuding','','[]','戚戚逢人問所之，東流相送向京畿。自甘逐客紉蘭佩，',40,'御定全唐詩/json/754.json','["戚戚逢人問所之，東流相送向京畿。自甘逐客紉蘭佩，", "時危道喪無才術，空手徘徊不忍歸。"]'),
('yuding-17','酬郭先輩','徐鉉','唐','御定全唐诗','yuding','','[]','太原郭夫子，行高文炳蔚。弱齡負世譽，一舉遊月窟。',192,'御定全唐詩/json/754.json','["太原郭夫子，行高文炳蔚。弱齡負世譽，一舉遊月窟。", "仙籍第三人，時人故稱屈。昔餘吏西省，傾蓋名籍籍。", "及我竄群舒，向風心鬱鬱。歸來暮江上，雲霧一披拂。", "雷雨不下施，猶作池中物。念君介然氣，感時思奮發。", "示我數篇文，與古爭馳突。彩褥粲英華，理深刮肌骨。", "古詩尤精奧，史論皆宏拔。舉此措諸民，何憂民不活。", "籲嗟吾道薄，與世長迂闊。顧我徒有心，數奇身正絀。", "論兵屬少年，經國須儒術。夫子無自輕，蒼生正愁疾。"]'),
('yuding-18','和集賢鐘郎中','徐鉉','唐','御定全唐诗','yuding','','[]','石渠冊府神仙署，當用明朝第一人。腰下別懸新印綬，',40,'御定全唐詩/json/754.json','["石渠冊府神仙署，當用明朝第一人。腰下別懸新印綬，", "從此翻飛應更遠，遍尋三十六天春。"]'),
('yuding-19','送劉山陽','徐鉉','唐','御定全唐诗','yuding','','[]','舊族知名士，朱衣宰楚城。所嗟吾道薄，豈是主恩輕。',48,'御定全唐詩/json/754.json','["舊族知名士，朱衣宰楚城。所嗟吾道薄，豈是主恩輕。", "戰鼓何時息，儒冠獨自行。此心多感激，相送若為情。"]'),
('yuding-20','題伏龜山北隅','徐鉉','唐','御定全唐诗','yuding','','[]','茲山信岑寂，陰崖積蒼翠。水石何必多，宛有千岩意。',72,'御定全唐詩/json/754.json','["茲山信岑寂，陰崖積蒼翠。水石何必多，宛有千岩意。", "孰知近人境，旦暮含佳氣。池影搖輕風，林光澹新霽。", "支頤藉芳草，自足忘世事。未得歸去來，聊為宴居地。"]'),
('yuding-21','送黃梅江明府','徐鉉','唐','御定全唐诗','yuding','','[]','封疆多難正經綸，台閣如何不用君。江上又勞為小邑，',40,'御定全唐詩/json/754.json','["封疆多難正經綸，台閣如何不用君。江上又勞為小邑，", "一首新詩無限意，再三吟味向秋雲。"]'),
('yuding-22','詠梅子真送郭先輩','徐鉉','唐','御定全唐诗','yuding','','[]','忠臣本愛君，仁人本愛民。寧知貴與賤，豈計名與身。',120,'御定全唐詩/json/754.json','["忠臣本愛君，仁人本愛民。寧知貴與賤，豈計名與身。", "梅生為一尉，獻疏來君門。君門深萬里，金虎重千鈞。", "向永且不用，況複論子真。拂衣遂長往，高節邈無鄰。", "至今仙籍中，謂之梅真人。郭生負逸氣，百代繼遺塵。", "進退生自知，得喪吾不陳。斯民苟有幸，期子一朝伸。"]'),
('yuding-23','和蕭郎中午日見寄','徐鉉','唐','御定全唐诗','yuding','','[]','細雨輕風采藥時，褰簾隱幾更何為。豈知澤畔紉蘭客，',40,'御定全唐詩/json/754.json','["細雨輕風采藥時，褰簾隱幾更何為。豈知澤畔紉蘭客，", "謝公制勝常閒暇，願接西州敵手棋。"]'),
('yuding-24','送黃秀才姑孰辟命','徐鉉','唐','御定全唐诗','yuding','','[]','世亂離情苦，家貧色養難。水雲孤棹去，風雨暮春寒。',48,'御定全唐詩/json/754.json','["世亂離情苦，家貧色養難。水雲孤棹去，風雨暮春寒。", "幕府才方急，騷人淚未幹。何時王道泰，萬里看鵬摶。"]'),
('yuding-25','送王四十五歸東都','徐鉉','唐','御定全唐诗','yuding','','[]','海內兵方起，離筵淚易垂。憐君負米去，惜此落花時。',48,'御定全唐詩/json/754.json','["海內兵方起，離筵淚易垂。憐君負米去，惜此落花時。", "想憶看來信，相寬指後期。殷勤手中柳，此是向南枝。"]'),
('yuding-26','和太常蕭少卿近郊馬上偶吟','徐鉉','唐','御定全唐诗','yuding','','[]','田園經雨綠分畦，飛蓋閑行九裏堤。拂袖清風塵不起，',40,'御定全唐詩/json/754.json','["田園經雨綠分畦，飛蓋閑行九裏堤。拂袖清風塵不起，", "怪得仙郎詩句好，斷霞殘照遠山西。"]'),
('yuding-27','又和','徐鉉','唐','御定全唐诗','yuding','','[]','抱甕何人灌藥畦，金銜為爾駐平堤。村橋野店景無限，',40,'御定全唐詩/json/754.json','["抱甕何人灌藥畦，金銜為爾駐平堤。村橋野店景無限，", "鳳城回望真堪畫，萬戶千門蔣嶠西。"]'),
('yuding-28','拋球樂辭二首','徐鉉','唐','御定全唐诗','yuding','','[]','歌舞送飛球，金觥碧玉籌。管弦桃李月，簾幕鳳凰樓。',72,'御定全唐詩/json/754.json','["歌舞送飛球，金觥碧玉籌。管弦桃李月，簾幕鳳凰樓。", "一笑千場醉，浮生任白頭。", "灼灼傳花枝，紛紛度畫旗。不知紅燭下，照見彩球飛。", "借勢因期克，巫山暮雨歸。"]'),
('yuding-29','離歌辭五首','徐鉉','唐','御定全唐诗','yuding','','[]','莫折紅芳樹，但知盡意看。狂風幸無意，那忍折教殘。',120,'御定全唐詩/json/754.json','["莫折紅芳樹，但知盡意看。狂風幸無意，那忍折教殘。", "朝日城南路，旌旗照綠蕪。使君何處去，桑下覓羅敷。", "事與年俱往，情將分共深。莫驚容鬢改，只是舊時心。", "暫別勞相送，佳期願莫違。朱顏不須老，留取待郎歸。", "拂匣收珠佩，回燈拭薄妝。莫嫌春夜短，匹似楚襄王。"]'),
('yuding-30','夢遊三首','徐鉉','唐','御定全唐诗','yuding','','[]','魂夢悠揚不奈何，夜來還在故人家。香蒙蠟燭時時暗，',120,'御定全唐詩/json/754.json','["魂夢悠揚不奈何，夜來還在故人家。香蒙蠟燭時時暗，", "天明又作人間別，洞口春深道路賒。", "繡幌銀屏杳靄間，若非魂夢到應難。窗前人靜偏宜夜，", "錦書若要知名字，滿縣花開不姓潘。", "南國佳人字玉兒，芙蓉雙臉遠山眉。仙郎有約長相憶，", "因思別後閑窗下，織得回文幾首詩。"]'),
('yuding-31','和蕭少卿見慶新居','徐鉉','唐','御定全唐诗','yuding','','[]','湘浦懷沙已不疑，京城賜第豈前期。鼓聲到晚知坊遠，',40,'御定全唐詩/json/754.json','["湘浦懷沙已不疑，京城賜第豈前期。鼓聲到晚知坊遠，", "新詩問我偏饒思，還念鷦鷯得一枝。"]'),
('yuding-32','又和','徐鉉','唐','御定全唐诗','yuding','','[]','驚蓬偶駐知多幸，斷雁重聯愜素期。當戶小山如舊識，',40,'御定全唐詩/json/754.json','["驚蓬偶駐知多幸，斷雁重聯愜素期。當戶小山如舊識，", "更喜良鄰有嘉樹，綠陰分得近南枝。"]'),
('yuding-33','送勳道人之建安','徐鉉','唐','御定全唐诗','yuding','','[]','下國兵方起，君家義獨聞。若為輕世利，歸去臥溪雲。',48,'御定全唐詩/json/754.json','["下國兵方起，君家義獨聞。若為輕世利，歸去臥溪雲。", "掛席沖嵐翠，攜筇破蘚紋。離情似霜葉，江上正紛紛。"]'),
('yuding-34','送許郎中歙州判官兼黟縣','徐鉉','唐','御定全唐诗','yuding','','[]','嘗聞黟縣似桃源，況是優遊冠玳筵。遺愛非遙應臥理，',40,'御定全唐詩/json/754.json','["嘗聞黟縣似桃源，況是優遊冠玳筵。遺愛非遙應臥理，", "大抵宦遊須自適，莫辭離別二三年。"]'),
('yuding-35','送彭秀才南游','徐鉉','唐','御定全唐诗','yuding','','[]','問君孤棹去何之，玉笥春風楚水西。山上斷雲分翠靄，',40,'御定全唐詩/json/754.json','["問君孤棹去何之，玉笥春風楚水西。山上斷雲分翠靄，", "他日時清更隨計，莫如劉阮洞中迷。"]'),
('yuding-36','和明上人除夜見寄','徐鉉','唐','御定全唐诗','yuding','','[]','酌酒圍爐久，愁襟默自增。長年逢歲暮，多病見兵興。',48,'御定全唐詩/json/754.json','["酌酒圍爐久，愁襟默自增。長年逢歲暮，多病見兵興。", "夜色開庭燎，寒威入硯冰。湯師無別念，吟坐一燈凝。"]'),
('yuding-37','正初和鄂州邊郎中見寄','徐鉉','唐','御定全唐诗','yuding','','[]','潦倒含香客，淒涼賦鵩人。未能全捲舌，終擬學垂綸。',48,'御定全唐詩/json/754.json','["潦倒含香客，淒涼賦鵩人。未能全捲舌，終擬學垂綸。", "故友暌離久，音書問訊頻。相思俱老大，又見一年新。"]'),
('yuding-38','送劉司直出宰','徐鉉','唐','御定全唐诗','yuding','','[]','之子有雄文，風標秀不群。低飛從墨綬，逸志在青雲。',48,'御定全唐詩/json/754.json','["之子有雄文，風標秀不群。低飛從墨綬，逸志在青雲。", "柳色臨流動，春光到縣分。賢人多靜理，未爽醉醺醺。"]'),
('yuding-39','送從兄赴臨川幕','徐鉉','唐','御定全唐诗','yuding','','[]','梁王籍寵就東藩，還召鄒枚坐兔園。今日好論天下事，',40,'御定全唐詩/json/754.json','["梁王籍寵就東藩，還召鄒枚坐兔園。今日好論天下事，", "唯有音書慰離別，一杯相送別無言。"]'),
('yuding-40','送龔員外赴江州幕','徐鉉','唐','御定全唐诗','yuding','','[]','煩君更上築金台，世難民勞藉俊才。自有聲名馳羽檄，',40,'御定全唐詩/json/754.json','["煩君更上築金台，世難民勞藉俊才。自有聲名馳羽檄，", "莫忘故人離別恨，海潮回處寄書來。"]'),
('yuding-41','送朱先輩尉廬陵','徐鉉','唐','御定全唐诗','yuding','','[]','我重朱夫子，依然見古人。成名無愧色，得祿及慈親。',48,'御定全唐詩/json/754.json','["我重朱夫子，依然見古人。成名無愧色，得祿及慈親。", "莫歎官資屈，寧論活計貧。平生心氣在，終任靜邊塵。"]'),
('yuding-42','送鐘德林郎中學士赴東府詩：得酒','徐鉉','唐','御定全唐诗','yuding','','[]','酌此杯中物，茱萸滿把秋。今朝將送別，他日是忘憂。',48,'御定全唐詩/json/754.json','["酌此杯中物，茱萸滿把秋。今朝將送別，他日是忘憂。", "世亂方多事，年加易得愁。政成頻一醉，亦未減風流。"]'),
('yuding-0','送陳先生之洪井寄蕭少卿','徐鉉','唐','御定全唐诗','yuding','','[]','聞君仙袂指洪厓，我憶情人別路賒。知有歡娛游楚澤，',40,'御定全唐詩/json/755.json','["聞君仙袂指洪厓，我憶情人別路賒。知有歡娛游楚澤，", "此處相逢應見問，為言搔首望龍沙。"]'),
('yuding-1','送龔明府九江歸甯','徐鉉','唐','御定全唐诗','yuding','','[]','茂宰隳官去，扁舟著彩衣。湓城春酒熟，匡阜野花稀。',48,'御定全唐詩/json/755.json','["茂宰隳官去，扁舟著彩衣。湓城春酒熟，匡阜野花稀。", "解纜垂楊綠，開帆宿鷺飛。一朝吾道泰，還逐落潮歸。"]'),
('yuding-2','和江西蕭少卿見寄二首','徐鉉','唐','御定全唐诗','yuding','','[]','亡羊岐路愧司南，二紀窮通聚散三。老去何妨從笑傲，',80,'御定全唐詩/json/755.json','["亡羊岐路愧司南，二紀窮通聚散三。老去何妨從笑傲，", "珍重加餐省思慮，時時斟酒壓山嵐。", "身遙上國三千里，名在朝中二十春。金印不須辭入幕，", "世路風波自翻覆，虛舟無計得沉淪。"]'),
('yuding-3','送薛少卿赴青陽','徐鉉','唐','御定全唐诗','yuding','','[]','我愛陶靖節，吏隱從弦歌。我愛費征君，高臥歸九華。',132,'御定全唐詩/json/755.json','["我愛陶靖節，吏隱從弦歌。我愛費征君，高臥歸九華。", "清風激頹波，來者無以加。我志兩不遂，漂淪浩無涯。", "數奇時且亂，此圖今愈賒。賢哉薛夫子，高舉淩晨霞。", "安民即是道，投足皆為家。功名與權位，悠悠何用誇。", "攜朋出遠郊，酌酒藉平沙。雲收遠天靜，江闊片帆斜。", "離懷與企羨，南望長咨嗟。"]'),
('yuding-4','送高起居之涇縣','徐鉉','唐','御定全唐诗','yuding','','[]','右史罷朝歸，之官句水湄。別我行千里，送君傾一卮。',132,'御定全唐詩/json/755.json','["右史罷朝歸，之官句水湄。別我行千里，送君傾一卮。", "酒罷長歎息，此歎君應悲。亂中吾道薄，卿族舊人稀。", "胡為佩銅墨，去此白玉墀。吏事豈所堪，民病何可醫。", "藏用清其心，此外慎勿為。縣郭有佳境，千峰溪水西。", "雲樹杳回合，岩巒互蔽虧。彈琴坐其中，世事吾不知。", "時時寄書劄，以慰長相思。"]'),
('yuding-5','宿茅山寄舍弟','徐鉉','唐','御定全唐诗','yuding','','[]','茅許稟靈氣，一家同上賓。仙山空有廟，舉世更無人。',48,'御定全唐詩/json/755.json','["茅許稟靈氣，一家同上賓。仙山空有廟，舉世更無人。", "獨往誠違俗，浮名亦累真。當年各自勉，雲洞鎮長春。"]'),
('yuding-6','晚憩白鶴廟寄句容張少府','徐鉉','唐','御定全唐诗','yuding','','[]','日入林初靜，山空暑更寒。泉鳴細岩竇，鶴唳眇雲端。',48,'御定全唐詩/json/755.json','["日入林初靜，山空暑更寒。泉鳴細岩竇，鶴唳眇雲端。", "拂榻安棋局，焚香戴道冠。望君殊不見，終夕憑欄幹。"]'),
('yuding-7','題紫陽觀','徐鉉','唐','御定全唐诗','yuding','','[]','南朝名士富仙才，追步東卿遂不回。丹井自深桐暗老，',40,'御定全唐詩/json/755.json','["南朝名士富仙才，追步東卿遂不回。丹井自深桐暗老，", "惆悵霓裳太平事，一函真跡鎖昭台。"]'),
('yuding-8','贈奚道士','徐鉉','唐','御定全唐诗','yuding','','[]','先生曾有洞天期，猶傍天壇摘紫芝。處世自能心混沌，',40,'御定全唐詩/json/755.json','["先生曾有洞天期，猶傍天壇摘紫芝。處世自能心混沌，", "他日飆輪謁茅許，願同雞犬去相隨。"]'),
('yuding-9','題碧岩亭贈孫尊師','徐鉉','唐','御定全唐诗','yuding','','[]','絕境何人識，高亭萬象含。憑軒臨樹杪，送目極天南。',96,'御定全唐詩/json/755.json','["絕境何人識，高亭萬象含。憑軒臨樹杪，送目極天南。", "積靄生泉洞，歸雲鎖石龕。丹霞披翠巘，白鳥帶晴嵐。", "仙去留虛室，龍歸漲碧潭。幽岩君獨愛，玄味我曾耽。", "世上愁何限，人間事久諳。終須脫羈鞅，來此會空談。"]'),
('yuding-10','題白鶴廟','徐鉉','唐','御定全唐诗','yuding','','[]','平生心事向玄關，一入仙鄉似舊山。白鶴唳空晴眇眇，',40,'御定全唐詩/json/755.json','["平生心事向玄關，一入仙鄉似舊山。白鶴唳空晴眇眇，", "滿洞煙霞互陵亂，何峰台榭是蕭閑。"]'),
('yuding-11','步虛詞五首','徐鉉','唐','御定全唐诗','yuding','','[]','氣為還元正，心由抱一靈。凝神歸罔象，飛步入青冥。',240,'御定全唐詩/json/755.json','["氣為還元正，心由抱一靈。凝神歸罔象，飛步入青冥。", "整服乘三素，旋綱躡九星。瓊章開後學，稽首奉真經。", "天帝黃金闕，真人紫錦書。霓裳紛蔽景，羽服迥淩虛。", "白鶴能為使，班麟解駕車。靈符終願借，轉共世情疏。", "聖主過幽谷，虛皇在蕊宮。五千宗物母，七字秘神童。", "世上金壺遠，人間玉龠空。唯餘養身法，修此與天通。", "何處求玄解，人間有洞天。勤行皆是道，謫下尚為仙。", "蔽景乘朱鳳，排虛駕紫煙。不嫌園吏傲，願在玉宸前。", "三素霏霏遠，盟威凜凜寒。火鈴空滅沒，星斗曉闌幹。", "佩響流虛殿，爐煙在醮壇。蕭寥不可極，驂駕上雲端。"]'),
('yuding-12','留題仙觀','徐鉉','唐','御定全唐诗','yuding','','[]','瑤壇醮罷晚雲開，羽客分飛俗士回。',32,'御定全唐詩/json/755.json','["瑤壇醮罷晚雲開，羽客分飛俗士回。", "為報移文不須勒，未曾遊處待重來。"]'),
('yuding-13','和陳洗馬山莊新泉','徐鉉','唐','御定全唐诗','yuding','','[]','已開山館待抽簪，更要岩泉欲洗心。常被松聲迷細韻，',40,'御定全唐詩/json/755.json','["已開山館待抽簪，更要岩泉欲洗心。常被松聲迷細韻，", "何日煎茶醞香酒，沙邊同聽暝猿吟。"]'),
('yuding-14','奉和七夕應令','徐鉉','唐','御定全唐诗','yuding','','[]','今宵星漢共晶光，應笑羅敷嫁侍郎。斗柄易傾離恨促，',40,'御定全唐詩/json/755.json','["今宵星漢共晶光，應笑羅敷嫁侍郎。斗柄易傾離恨促，", "誰見宣猷堂上宴，一篇清韻振金鐺。"]'),
('yuding-15','又和八日','徐鉉','唐','御定全唐诗','yuding','','[]','微雲疏雨淡新秋，曉夢依稀十二樓。故作別離應有以，',40,'御定全唐詩/json/755.json','["微雲疏雨淡新秋，曉夢依稀十二樓。故作別離應有以，", "博望苑中殘酒醒，香風佳氣獨遲留。"]'),
('yuding-16','和印先輩及第後獻座主朱舍人郊居之作','徐鉉','唐','御定全唐诗','yuding','','[]','成名郊外掩柴扉，樹影蟬聲共息機。積雨暗封青蘚徑，',40,'御定全唐詩/json/755.json','["成名郊外掩柴扉，樹影蟬聲共息機。積雨暗封青蘚徑，", "獨坐公廳正煩暑，喜吟新詠見玄微。"]'),
('yuding-17','和致仕張尚書新創道院','徐鉉','唐','御定全唐诗','yuding','','[]','梓澤成新致，金丹有舊情。掛冠朝睡足，隱幾暮江清。',48,'御定全唐詩/json/755.json','["梓澤成新致，金丹有舊情。掛冠朝睡足，隱幾暮江清。", "藥圃分輕綠，松窗起細聲。養高寧厭病，默坐對諸生。"]'),
('yuding-18','和尉遲贊善秋暮僻居','徐鉉','唐','御定全唐诗','yuding','','[]','登高節物最堪憐，小嶺疏林對檻前。輕吹斷時雲縹緲，',40,'御定全唐詩/json/755.json','["登高節物最堪憐，小嶺疏林對檻前。輕吹斷時雲縹緲，", "庭有菊花尊有酒，若方陶令愧前賢。"]'),
('yuding-19','和陳贊善致仕還京口','徐鉉','唐','御定全唐诗','yuding','','[]','海門山下一漁舟，中有高人未白頭。已駕安車歸故里，',40,'御定全唐詩/json/755.json','["海門山下一漁舟，中有高人未白頭。已駕安車歸故里，", "今日君臣厚終始，不須辛苦畫雙牛。"]'),
('yuding-20','京使回自臨川，得從兄書寄詩，依韻和','徐鉉','唐','御定全唐诗','yuding','','[]','珍重還京使，殷勤話故人。別離長掛夢，寵祿不關身。',48,'御定全唐詩/json/755.json','["珍重還京使，殷勤話故人。別離長掛夢，寵祿不關身。", "趣向今成道，聲華舊絕塵。莫嗟客鬢老，詩句逐時新。"]'),
('yuding-21','陪鄭王相公賦筵前垂冰，應教依韻','徐鉉','唐','御定全唐诗','yuding','','[]','窗外虛明雪乍晴，簷前垂溜盡成冰。長廊瓦疊行行密，',40,'御定全唐詩/json/755.json','["窗外虛明雪乍晴，簷前垂溜盡成冰。長廊瓦疊行行密，", "晨餐堪醒曹參酒，自恨空腸病不能。"]'),
('yuding-22','送禮部潘尚書致仕還建安','徐鉉','唐','御定全唐诗','yuding','','[]','名遂功成累複輕，鱸魚因起舊鄉情。履聲初下金華省，',40,'御定全唐詩/json/755.json','["名遂功成累複輕，鱸魚因起舊鄉情。履聲初下金華省，", "冥鴻高舉真難事，相送何須淚滿纓。"]'),
('yuding-23','和尉遲贊善病中見寄','徐鉉','唐','御定全唐诗','yuding','','[]','仙郎移病暑天過，卻似冥鴻避罻羅。晝夢乍驚風動竹，',40,'御定全唐詩/json/755.json','["仙郎移病暑天過，卻似冥鴻避罻羅。晝夢乍驚風動竹，", "望苑恩深期勿藥，青雲岐路未蹉跎。"]'),
('yuding-24','池州陳使君見示游齊山詩因寄','徐鉉','唐','御定全唐诗','yuding','','[]','往歲曾游弄水亭，齊峰濃翠暮軒橫。哀猿出檻心雖喜，',40,'御定全唐詩/json/755.json','["往歲曾游弄水亭，齊峰濃翠暮軒橫。哀猿出檻心雖喜，", "今朝池口風波靜，遙賀山前有頌聲。"]'),
('yuding-25','再領制誥和王明府見賀','徐鉉','唐','御定全唐诗','yuding','','[]','蹇步還依列宿邊，拱辰重認舊雲天。自嗟多難飄零困，',40,'御定全唐詩/json/755.json','["蹇步還依列宿邊，拱辰重認舊雲天。自嗟多難飄零困，", "從來不解為身計，一葉悠悠任大川。"]'),
('yuding-26','送高舍人使嶺南','徐鉉','唐','御定全唐诗','yuding','','[]','西掖官曹近，南溟道路遙。使星將渡漢，仙棹乍乘潮。',72,'御定全唐詩/json/755.json','["西掖官曹近，南溟道路遙。使星將渡漢，仙棹乍乘潮。", "柳映靈和折，梅依大庾飄。江帆風淅淅，山館雨蕭蕭。", "陸賈真迂闊，終童久寂寥。送君何限意，把酒一長謠。"]'),
('yuding-27','和王明府見寄','徐鉉','唐','御定全唐诗','yuding','','[]','時情世難消吾道，薄宦流年危此身。莫歎京華同寂寞，',40,'御定全唐詩/json/755.json','["時情世難消吾道，薄宦流年危此身。莫歎京華同寂寞，", "善政空多尚淹屈，不知誰是解憂民。"]'),
('yuding-28','和方泰州見寄','徐鉉','唐','御定全唐诗','yuding','','[]','逐客淒淒重入京，舊愁新恨兩難勝。雲收楚塞千山雪，',40,'御定全唐詩/json/755.json','["逐客淒淒重入京，舊愁新恨兩難勝。雲收楚塞千山雪，", "更殘月落知孤坐，遙望船窗一點星。"]'),
('yuding-29','文獻太子挽歌詞五首','徐鉉','唐','御定全唐诗','yuding','','[]','國有承祧重，人知秉哲尊。清風來望苑，遺烈在東藩。',240,'御定全唐詩/json/755.json','["國有承祧重，人知秉哲尊。清風來望苑，遺烈在東藩。", "此日升緱嶺，何因到寢門。天高不可問，煙靄共昏昏。", "夏啟吾君子，周儲上帝賓。音容一飄忽，功業自紛綸。", "露泣承華月，風驚麗正塵。空餘商嶺客，行淚下宜春。", "出處成交讓，經綸有大功。淚碑瓜步北，棠樹蒜山東。", "百揆方時敘，重離遂不融。故臣偏感咽，曾是歎三窮。", "甲觀光陰促，園陵天地長。簫笳咽無韻，賓禦哭相將。", "盛烈傳彝鼎，遺文被樂章。君臣知己分，零淚亂無行。", "彩仗清晨出，非同齒胄時。愁煙鎖平甸，朔吹繞寒枝。", "楚客來何補，緱山去莫追。回瞻飛蓋處，掩袂不勝悲。"]'),
('yuding-30','送王員外宰德安','徐鉉','唐','御定全唐诗','yuding','','[]','家世朱門貴，官資粉署優。今為百里長，應好五峰遊。',48,'御定全唐詩/json/755.json','["家世朱門貴，官資粉署優。今為百里長，應好五峰遊。", "柳影連彭澤，湖光接庾樓。承明須再入，官滿莫淹留。"]'),
('yuding-31','以端溪硯酬張員外水精珠兼和來篇','徐鉉','唐','御定全唐诗','yuding','','[]','請以端溪潤，酬君水玉明。方圓雖異器，功用信俱呈。',48,'御定全唐詩/json/755.json','["請以端溪潤，酬君水玉明。方圓雖異器，功用信俱呈。", "自得山川秀，能分日月精。巾箱各珍重，所貴在交情。"]'),
('yuding-32','奉使九華山，中途遇青陽薛郎中','徐鉉','唐','御定全唐诗','yuding','','[]','故人相別動相思，此地相逢豈素期。九子峰前閑未得，',40,'御定全唐詩/json/755.json','["故人相別動相思，此地相逢豈素期。九子峰前閑未得，", "且飲一杯消別恨，野花風起漸離披。"]'),
('yuding-33','奉命南使經彭澤','徐鉉','唐','御定全唐诗','yuding','','[]','遠使程途未一分，離心常要醉醺醺。',32,'御定全唐詩/json/755.json','["遠使程途未一分，離心常要醉醺醺。", "那堪彭澤門前立，黃菊蕭疏不見君。"]'),
('yuding-34','南都遇前嘉魚劉令，言遊閩嶺，作此與之','徐鉉','唐','御定全唐诗','yuding','','[]','我持使節經韶石，君作閒遊過武夷。兩地山光成獨賞，',40,'御定全唐詩/json/755.json','["我持使節經韶石，君作閒遊過武夷。兩地山光成獨賞，", "珍重分岐一杯酒，強加餐飯數吟詩。"]'),
('yuding-35','閣皂山','徐鉉','唐','御定全唐诗','yuding','','[]','殿影高低雲掩映，松陰繚繞步徘徊。',32,'御定全唐詩/json/755.json','["殿影高低雲掩映，松陰繚繞步徘徊。", "從今莫厭簪裾累，不是乘軺不得來。"]'),
('yuding-36','玉笥山留題','徐鉉','唐','御定全唐诗','yuding','','[]','仙鄉會應遠，王事知何極。征傳莫辭勞，玉峰聊一息。',72,'御定全唐詩/json/755.json','["仙鄉會應遠，王事知何極。征傳莫辭勞，玉峰聊一息。", "形骸已銷散，心想都凝寂。真氣自清虛，非關好松石。", "九仙皆積學，洞壑多遺跡。遊子歸去來，胡為但征役。"]'),
('yuding-37','廬陵別朱觀先輩','徐鉉','唐','御定全唐诗','yuding','','[]','桂籍知名有幾人，翻飛相續上青雲。解憐才子甯唯我，',40,'御定全唐詩/json/755.json','["桂籍知名有幾人，翻飛相續上青雲。解憐才子甯唯我，", "新詩試為重高詠，朝漢台前不可聞。"]'),
('yuding-38','文彧少卿文山郎中交好深至二紀已餘暌別…留題此詩','徐鉉','唐','御定全唐诗','yuding','','[]','孫家虛座吊諸孤，張叟僧房見手書。二紀歡遊今若此，',40,'御定全唐詩/json/755.json','["孫家虛座吊諸孤，張叟僧房見手書。二紀歡遊今若此，", "珍重遠公應笑我，塵心唯此未能除。"]'),
('yuding-39','朱處士相與有山水之願見送至南康作此以別之','徐鉉','唐','御定全唐诗','yuding','','[]','憐君送我至南康，更憶梅花庾嶺芳。',32,'御定全唐詩/json/755.json','["憐君送我至南康，更憶梅花庾嶺芳。", "多少仙山共遊在，願君百歲尚康強。"]'),
('yuding-40','清明日清遠峽作','徐鉉','唐','御定全唐诗','yuding','','[]','嶺外春過半，途中火又新。殷勤清遠峽，留戀北歸人。',24,'御定全唐詩/json/755.json','["嶺外春過半，途中火又新。殷勤清遠峽，留戀北歸人。"]'),
('yuding-41','回至南康題紫極宮裏道士房','徐鉉','唐','御定全唐诗','yuding','','[]','王事信靡盬，飲冰安足辭。胡為擁征傳，乃至天南陲。',84,'御定全唐詩/json/755.json','["王事信靡盬，飲冰安足辭。胡為擁征傳，乃至天南陲。", "天南非我鄉，留滯忽逾時。還經羽人家，豁若雲霧披。", "何以寬吾懷，老莊有微詞。達士無不可，至人豈偏為。", "客愁勿複道，為君吟此詩。"]'),
('yuding-42','和歙州陳使君見寄','徐鉉','唐','御定全唐诗','yuding','','[]','新安風景好，時令肅轅門。身貴心彌下，功多口不言。',120,'御定全唐詩/json/755.json','["新安風景好，時令肅轅門。身貴心彌下，功多口不言。", "韜鈐家法在，儒雅素風存。簪履陪游盛，鄉閭俗化敦。", "臨窗山色秀，繞郭水聲喧。織絡文章麗，矜嚴道義尊。", "樓臺秋月靜，京庾晚雲屯。曉吹傳衙鼓，晴陽展信幡。", "一篇貽友好，千里倍心論。未見歸驂動，空能役夢魂。"]'),
('yuding-43','和賈員外戩見贈玉蕊花栽','徐鉉','唐','御定全唐诗','yuding','','[]','瓊瑤一簇帶花來，便劚蒼苔手自栽。',32,'御定全唐詩/json/755.json','["瓊瑤一簇帶花來，便劚蒼苔手自栽。", "喜見唐昌舊顏色，為君判病酌金罍。"]'),
('yuding-44','光穆皇后挽歌三首','徐鉉','唐','御定全唐诗','yuding','','[]','仙馭期難改，坤儀道自光。閟宮新表德，沙麓舊膺祥。',144,'御定全唐詩/json/755.json','["仙馭期難改，坤儀道自光。閟宮新表德，沙麓舊膺祥。", "素帟堯門掩，凝笳畢陌長。東風慘陵樹，無複見親桑。", "永樂留虛位，長陵啟夕扉。返虞嚴吉仗，複土掩空衣。", "功業投三母，光靈極四妃。唯應彤史在，不與露花晞。", "隱隱閶門路，煙雲曉更愁。空瞻金輅出，非是濯龍遊。", "德感人倫正，風行內職修。還隨偶物化，同此思軒丘。"]'),
('yuding-45','嚴相公宅牡丹','徐鉉','唐','御定全唐诗','yuding','','[]','但是豪家重牡丹，爭如丞相閣前看。鳳樓日暖開偏早，',40,'御定全唐詩/json/755.json','["但是豪家重牡丹，爭如丞相閣前看。鳳樓日暖開偏早，", "不知更許憑欄否，爛熳春光未肯殘。"]'),
('yuding-46','侍宴賦得歸雁','徐鉉','唐','御定全唐诗','yuding','','[]','夜靜群動息，翩翩一雁歸。清音天際遠，寒影月中微。',48,'御定全唐詩/json/755.json','["夜靜群動息，翩翩一雁歸。清音天際遠，寒影月中微。", "何處雲同宿，長空雪共飛。陽和常借便，免與素心違。"]'),
('yuding-47','又賦早春書事','徐鉉','唐','御定全唐诗','yuding','','[]','苑裏芳華早，皇家勝事多。弓聲達春氣，弈思養天和。',48,'御定全唐詩/json/755.json','["苑裏芳華早，皇家勝事多。弓聲達春氣，弈思養天和。", "暖酒紅爐火，浮舟綠水波。雪晴農事起，擊壤聽賡歌。"]'),
('yuding-48','依韻和令公大王薔薇詩','徐鉉','唐','御定全唐诗','yuding','','[]','綠樹成陰後，群芳稍歇時。誰將新濯錦，掛向最長枝。',217,'御定全唐詩/json/755.json','["綠樹成陰後，群芳稍歇時。誰將新濯錦，掛向最長枝。", "卷箔香先入，憑欄影任移。賞頻嫌酒渴，吟苦怕霜髭。", "架迥籠雲幄，庭虛展繡帷。有情縈舞袖，無力罥遊絲。", "嫩蕊鶯偷采，柔條柳伴垂。荀池波自照，梁苑客嘗窺。", "玉李尋皆謝，金桃亦暗衰。花中應獨貴，庭下故開遲。", "委豔妝苔砌，分華借槿籬。低昂勻灼爍，濃淡疊參差。", "幸植王宮裏，仍逢宰府知。芳心向誰許，醉態不能支。", "芍藥天教避，玫瑰眾共嗤。光明烘晝景，潤膩裛輕rG。", "麗似期神女，珍如重衛姬。君王偏屬詠，七子盡搜奇。"]'),
('yuding-49','和門下殷侍郎新茶二十韻','徐鉉','唐','御定全唐诗','yuding','','[]','暖吹入春園，新芽競粲然。才教鷹觜拆，未放雪花妍。',240,'御定全唐詩/json/755.json','["暖吹入春園，新芽競粲然。才教鷹觜拆，未放雪花妍。", "荷杖青林下，攜筐旭景前。孕靈資雨露，鐘秀自山川。", "碾後香彌遠，烹來色更鮮。名隨土地貴，味逐水泉遷。", "力藉流黃暖，形模紫筍圓。正當鑽柳火，遙想湧金泉。", "任道時新物，須依古法煎。輕甌浮綠乳，孤灶散餘煙。", "甘薺非予匹，宮槐讓我先。竹孤空冉冉，荷弱謾田田。", "解渴消殘酒，清神感夜眠。十漿何足饋，百榼盡堪捐。", "採擷唯憂晚，營求不計錢。任公因焙顯，陸氏有經傳。", "愛甚真成癖，嘗多合得仙。亭台虛靜處，風月豔陽天。", "自可臨泉石，何妨雜管弦。東山似蒙頂，願得從諸賢。"]'),
('yuding-50','春雪應制','徐鉉','唐','御定全唐诗','yuding','','[]','繁陰連曙景，瑞雪灑芳辰。勢密猶疑臘，風和始覺春。',48,'御定全唐詩/json/755.json','["繁陰連曙景，瑞雪灑芳辰。勢密猶疑臘，風和始覺春。", "縈林開玉蕊，飄座裛香塵。欲識宸心悅，雲謠慰兆人。"]'),
('yuding-51','進雪詩','徐鉉','唐','御定全唐诗','yuding','','[]','欲使新正識有年，故飄輕絮伴春還。近看瓊樹籠銀闕，',40,'御定全唐詩/json/755.json','["欲使新正識有年，故飄輕絮伴春還。近看瓊樹籠銀闕，", "朝來花萼樓中宴，數曲賡歌雅頌間。"]'),
('yuding-52','自題山亭三首','徐鉉','唐','御定全唐诗','yuding','','[]','簪組非無累，園林未是歸。世喧長不到，何必故山薇。',72,'御定全唐詩/json/755.json','["簪組非無累，園林未是歸。世喧長不到，何必故山薇。", "小舫行乘月，高齋臥看山。退公聊自足，爭敢望長閑。", "跂石仍臨水，披襟複掛冠。機心忘未得，棋局與魚竿。"]'),
('yuding-53','和陳表用員外求酒','徐鉉','唐','御定全唐诗','yuding','','[]','暑天頻雨亦頻晴，簾外閑雲重複輕。',32,'御定全唐詩/json/755.json','["暑天頻雨亦頻晴，簾外閑雲重複輕。", "珍重一壺酬絕唱，向風遙想醉吟聲。"]'),
('yuding-54','奉和右省僕射西亭高臥作','徐鉉','唐','御定全唐诗','yuding','','[]','院靜蒼苔積，庭幽怪石欹。蟬聲當檻急，虹影向簷垂。',96,'御定全唐詩/json/755.json','["院靜蒼苔積，庭幽怪石欹。蟬聲當檻急，虹影向簷垂。", "晝漏猶憐永，叢蘭未覺衰。疏篁巢翡翠，折葦覆鸕鷀。", "對酒襟懷曠，圍棋旨趣遲。景皆隨所尚，物各遂其宜。", "道與時相會，才非世所羈。賦詩貽座客，秋事爾何悲。"]'),
('yuding-55','憶新淦觴池寄孟賓于員外','徐鉉','唐','御定全唐诗','yuding','','[]','往年淦水駐行軒，引得清流似月圓。自有溪光還碧甃，',40,'御定全唐詩/json/755.json','["往年淦水駐行軒，引得清流似月圓。自有溪光還碧甃，", "珍重詩人頻管領，莫教塵土咽潺潺。"]'),
('yuding-56','右省僕射後湖亭閑宴，鉉以宿直先歸，賦詩留獻','徐鉉','唐','御定全唐诗','yuding','','[]','湖上一陽生，虛亭啟高宴。楓林煙際出，白鳥波心見。',48,'御定全唐詩/json/755.json','["湖上一陽生，虛亭啟高宴。楓林煙際出，白鳥波心見。", "主人忘貴達，座客容疵賤。獨慚殘照催，歸宿明光殿。"]'),
('yuding-0','送孟賓于員外還新淦','徐鉉','唐','御定全唐诗','yuding','','[]','暫來城闕不從容，卻佩銀魚隱玉峰。雙澗水邊欹醉石，',40,'御定全唐詩/json/756.json','["暫來城闕不從容，卻佩銀魚隱玉峰。雙澗水邊欹醉石，", "野鶴乘軒雲出岫，不知何日再相逢。"]'),
('yuding-1','孟君別後相續寄書，作此酬之','徐鉉','唐','御定全唐诗','yuding','','[]','多病怯煩暑，短才憂近職。跂足北窗風，遙懷浩無極。',48,'御定全唐詩/json/756.json','["多病怯煩暑，短才憂近職。跂足北窗風，遙懷浩無極。", "故人易成別，詩句空相憶。尺素寄天涯，淦江秋水色。"]'),
('yuding-2','納後夕侍宴','徐鉉','唐','御定全唐诗','yuding','','[]','天上軒星正，雲間湛露垂。禮容過渭水，宴喜勝瑤池。',168,'御定全唐詩/json/756.json','["天上軒星正，雲間湛露垂。禮容過渭水，宴喜勝瑤池。", "彩霧籠花燭，升龍肅羽儀。君臣歡樂日，文物盛明時。", "簾卷銀河轉，香凝玉漏遲。華封傾祝意，觴酒與聲詩。", "時平物茂歲功成，重翟排雲到玉京。", "四海未知春色至，今宵先入九重城。", "銀燭金爐禁漏移，月輪初照萬年枝。", "造舟已似文王事，卜世應同八百期。", "漢主承幹帝道光，天家花燭宴昭陽。", "六衣盛禮如金屋，彩筆分題似柏梁。"]'),
('yuding-3','北苑侍宴雜詠詩：竹','徐鉉','唐','御定全唐诗','yuding','','[]','勁節生宮苑，虛心奉豫遊。自然名價重，不羨渭川侯。',24,'御定全唐詩/json/756.json','["勁節生宮苑，虛心奉豫遊。自然名價重，不羨渭川侯。"]'),
('yuding-4','北苑侍宴雜詠詩：松','徐鉉','唐','御定全唐诗','yuding','','[]','細韻風中遠，寒青雪後濃。繁陰堪避雨，效用待東封。',24,'御定全唐詩/json/756.json','["細韻風中遠，寒青雪後濃。繁陰堪避雨，效用待東封。"]'),
('yuding-5','北苑侍宴雜詠詩：水','徐鉉','唐','御定全唐诗','yuding','','[]','碧草垂低岸，東風起細波。橫汾從游宴，何謝到天河。',24,'御定全唐詩/json/756.json','["碧草垂低岸，東風起細波。橫汾從游宴，何謝到天河。"]'),
('yuding-6','北苑侍宴雜詠詩：風','徐鉉','唐','御定全唐诗','yuding','','[]','昨朝才解凍，今日又開花。帝力無人識，誰知玩物華。',24,'御定全唐詩/json/756.json','["昨朝才解凍，今日又開花。帝力無人識，誰知玩物華。"]'),
('yuding-7','北苑侍宴雜詠詩：菊','徐鉉','唐','御定全唐诗','yuding','','[]','細麗披金彩，氛氳散遠馨。泛杯頻奉賜，緣解制頹齡。',24,'御定全唐詩/json/756.json','["細麗披金彩，氛氳散遠馨。泛杯頻奉賜，緣解制頹齡。"]'),
('yuding-8','柳枝詞十首','徐鉉','唐','御定全唐诗','yuding','','[]','金馬辭臣賦小詩，梨園弟子唱新詞。',320,'御定全唐詩/json/756.json','["金馬辭臣賦小詩，梨園弟子唱新詞。", "君恩還似東風意，先入靈和蜀柳枝。", "百草千花共待春，綠楊顏色最驚人。", "天邊雨露年年在，上苑芳華歲歲新。", "長愛龍池二月時，毿毿金線弄春姿。", "假饒葉落枝空後，更有梨園笛裏吹。", "綠水成文柳帶搖，東風初到不鳴條。", "龍舟欲過偏留戀，萬縷輕絲拂禦橋。", "百尺長條婉曲塵，詩題不盡畫難真。", "憑君折向人間種，還似君恩處處春。", "風暖雲開晚照明，翠條深映鳳凰城。", "人間欲識靈和態，聽取新詞玉管聲。", "醉折垂楊唱柳枝，金城三月走金羈。", "年年為愛新條好，不覺蒼華也似絲。", "新春花柳競芳姿，偏愛垂楊拂地枝。", "天子遍教詞客賦，宮中要唱洞簫詞。", "凝碧池頭蘸翠漣，鳳凰樓畔簇晴煙。", "新詞欲詠知難詠，說與雙成入管弦。", "侍從甘泉與未央，移舟偏要近垂楊。", "櫻桃未綻梅花老，折得柔條百尺長。"]'),
('yuding-9','奉和宮傅相公懷舊見寄四十韻','徐鉉','唐','御定全唐诗','yuding','','[]','謝傅功成德望全，鸞台初下正蕭然。摶風乍息三千里，',328,'御定全唐詩/json/756.json','["謝傅功成德望全，鸞台初下正蕭然。摶風乍息三千里，", "文辭職業分工拙，流輩班資讓後先。每愧陋容勞刻畫，", "立馬有時同草詔，聯鑣幾處共成篇。閑歌柳葉翻新曲，", "雲龍得路須騰躍，社櫟非材合棄捐。再謁湘江猶是幸，", "聽漏分宵趨建禮，從遊同召赴甘泉。雲開閶闔分台殿，", "師資稷契論中禮，依止山公典小銓。多謝天波垂赤管，", "玉燭調時鈞軸正，臺階平處德星懸。岩廊禮絕威容肅，", "吳門日麗龍銜節，京口沙晴鷁畫船。蓋代名高方赫赫，", "卻許丘明師紀傳，更容疏廣奉周旋。朱門自得施行馬，", "東山妓樂供閒步，北牖風涼足晏眠。玄武湖邊林隱見，", "不遣前騶妨野逸，別尋逋客互招延。棋枰寂靜陳虛閣，", "青雲舊侶嗟誰在，白首親情倍見憐。盡日凝思殊悵望，", "幸喜書生為將相，定由陰德致神仙。羊公剩有登臨興，", "從容自保君臣契，何必扁舟始是賢。"]'),
('yuding-10','右省僕射相公垂覽和詩，複貽長句，輒次來韻','徐鉉','唐','御定全唐诗','yuding','','[]','西院春歸道思深，披衣閑聽暝猿吟。鋪陳政事留黃閣，',40,'御定全唐詩/json/756.json','["西院春歸道思深，披衣閑聽暝猿吟。鋪陳政事留黃閣，", "開晴便作東山約，共賞煙霞放曠心。"]'),
('yuding-11','九日落星山登高','徐鉉','唐','御定全唐诗','yuding','','[]','秋暮天高稻穟成，落星山上會諸賓。黃花泛酒依流俗，',40,'御定全唐詩/json/756.json','["秋暮天高稻穟成，落星山上會諸賓。黃花泛酒依流俗，", "風煙不改年長度，終待林泉老此身。"]'),
('yuding-12','十日和張少監','徐鉉','唐','御定全唐诗','yuding','','[]','重陽高會古平臺，吟遍秋光始下來。黃菊後期香未減，',40,'御定全唐詩/json/756.json','["重陽高會古平臺，吟遍秋光始下來。黃菊後期香未減，", "且喜清時屢行樂，是非名利盡悠哉。"]'),
('yuding-13','禦筵送鄧王','徐鉉','唐','御定全唐诗','yuding','','[]','禁裏秋光似水清，林煙池影共離情。暫移黃閣只三載，',40,'御定全唐詩/json/756.json','["禁裏秋光似水清，林煙池影共離情。暫移黃閣只三載，", "綺霞閣上詩題在，從此還應有頌聲。"]'),
('yuding-14','和張少監晚菊','徐鉉','唐','御定全唐诗','yuding','','[]','憶共庭蘭倚砌栽，柔條輕吹獨依隈。自知佳節終堪賞，',40,'御定全唐詩/json/756.json','["憶共庭蘭倚砌栽，柔條輕吹獨依隈。自知佳節終堪賞，", "今朝旬假猶無事，更好登臨泛一杯。"]'),
('yuding-15','送馮侍郎','徐鉉','唐','御定全唐诗','yuding','','[]','聞君竹馬戲毗陵，誰道觀風自六卿。今日聲明光舊物，',40,'御定全唐詩/json/756.json','["聞君竹馬戲毗陵，誰道觀風自六卿。今日聲明光舊物，", "應念筵中倍離恨，老來偏重十年兄。"]'),
('yuding-16','又絕句寄題毗陵驛','徐鉉','唐','御定全唐诗','yuding','','[]','曾持使節駐毗陵，長與州人有舊情。',32,'御定全唐詩/json/756.json','["曾持使節駐毗陵，長與州人有舊情。", "為向驛橋風月道，舍人髭鬢白千莖。"]'),
('yuding-17','陳侍郎宅觀花燭','徐鉉','唐','御定全唐诗','yuding','','[]','今夜銀河萬里秋，人言織女嫁牽牛。佩聲寥亮和金奏，',40,'御定全唐詩/json/756.json','["今夜銀河萬里秋，人言織女嫁牽牛。佩聲寥亮和金奏，", "世間盛事君知否，朝下鸞台夕鳳樓。"]'),
('yuding-18','送蕭尚書致仕歸廬陵','徐鉉','唐','御定全唐诗','yuding','','[]','江海分飛二十春，重論前事不堪聞。主憂臣辱誰非我，',40,'御定全唐詩/json/756.json','["江海分飛二十春，重論前事不堪聞。主憂臣辱誰非我，", "鶴歸華表望不盡，玉笥山頭多白雲。"]'),
('yuding-19','賦得秋江晚照','徐鉉','唐','御定全唐诗','yuding','','[]','落日照平流，晴空萬里秋。輕明動楓葉，點的亂沙鷗。',48,'御定全唐詩/json/756.json','["落日照平流，晴空萬里秋。輕明動楓葉，點的亂沙鷗。", "罾網魚梁靜，笞簦稻穗收。不教行樂倦，冉冉下城樓。"]'),
('yuding-20','奉和子龍大監與舍弟贈答之什','徐鉉','唐','御定全唐诗','yuding','','[]','石渠東觀兩優賢，明主知臣豈偶然。鴛鷺分行皆接武，',40,'御定全唐詩/json/756.json','["石渠東觀兩優賢，明主知臣豈偶然。鴛鷺分行皆接武，", "多少深情知不盡，好音相慰強成篇。"]'),
('yuding-21','史館庭梅見其毫末曆載三十今已半枯…伏惟垂覽','徐鉉','唐','御定全唐诗','yuding','','[]','東觀婆娑樹，曾憐甲坼時。繁英共攀折，芳歲幾推移。',48,'御定全唐詩/json/756.json','["東觀婆娑樹，曾憐甲坼時。繁英共攀折，芳歲幾推移。", "往事皆陳跡，清香亦暗衰。相看宜自喜，雙鬢合垂絲。"]'),
('yuding-22','太傅相公深感庭梅再成絕唱曲垂借示倍認知憐…攀和','徐鉉','唐','御定全唐诗','yuding','','[]','禁省繁華地，含芳自一時。雪英開複落，紅藥植還移。',48,'御定全唐詩/json/756.json','["禁省繁華地，含芳自一時。雪英開複落，紅藥植還移。", "靜想分今昔，頻吟歎盛衰。多情共如此，爭免鬢成絲。"]'),
('yuding-23','太傅相公以庭梅二篇許舍弟同賦再迂藻思…庶申感謝','徐鉉','唐','御定全唐诗','yuding','','[]','舊眷終無替，流光自足悲。攀條感花萼，和曲許塤篪。',48,'御定全唐詩/json/756.json','["舊眷終無替，流光自足悲。攀條感花萼，和曲許塤篪。", "前會成春夢，何人更己知。緣情聊借喻，爭敢道言詩。"]'),
('yuding-24','和鐘大監泛舟同遊見示','徐鉉','唐','御定全唐诗','yuding','','[]','潮溝橫趣北山阿，一月三遊未是多。老去交親難暫舍，',40,'御定全唐詩/json/756.json','["潮溝橫趣北山阿，一月三遊未是多。老去交親難暫舍，", "孤棹亂流偏有興，滿川晴日弄微波。"]'),
('yuding-25','又和遊光睦院','徐鉉','唐','御定全唐诗','yuding','','[]','寺門山水際，清淺照孱顏。客棹晚維岸，僧房猶掩關。',48,'御定全唐詩/json/756.json','["寺門山水際，清淺照孱顏。客棹晚維岸，僧房猶掩關。", "日華穿竹靜，雲影過階閑。箕踞一長嘯，忘懷物我間。"]'),
('yuding-26','和張少監舟中望蔣山','徐鉉','唐','御定全唐诗','yuding','','[]','溪路向還背，前山高複重。紛披紅葉樹，間斷白雲峰。',48,'御定全唐詩/json/756.json','["溪路向還背，前山高複重。紛披紅葉樹，間斷白雲峰。", "盡日慵移棹，何年醉倚松。自知閑未得，不敢笑周顒。"]'),
('yuding-27','茱萸詩','徐鉉','唐','御定全唐诗','yuding','','[]','萬物慶西成，茱萸獨擅名。芳排紅結小，香透夾衣輕。',48,'御定全唐詩/json/756.json','["萬物慶西成，茱萸獨擅名。芳排紅結小，香透夾衣輕。", "宿露沾猶重，朝陽照更明。長和菊花酒，高宴奉西清。"]'),
('yuding-28','奉和禦制茱萸','徐鉉','唐','御定全唐诗','yuding','','[]','台畔西風禦果新，芳香精彩麗蕭辰。柔條細葉妝治好，',40,'御定全唐詩/json/756.json','["台畔西風禦果新，芳香精彩麗蕭辰。柔條細葉妝治好，", "今朝聖藻偏流詠，黃菊無由更敢鄰。"]'),
('yuding-29','蒙恩賜酒旨令醉，進詩以謝','徐鉉','唐','御定全唐诗','yuding','','[]','明光殿裏夜迢迢，多病逢秋自寂寥。蠟炬乍傳丹鳳詔，',40,'御定全唐詩/json/756.json','["明光殿裏夜迢迢，多病逢秋自寂寥。蠟炬乍傳丹鳳詔，", "為感君恩判一醉，不煩辛苦解金貂。"]'),
('yuding-30','秋日泛舟賦蘋花','徐鉉','唐','御定全唐诗','yuding','','[]','素豔擁行舟，清香覆碧流。遠煙分的的，輕浪泛悠悠。',48,'御定全唐詩/json/756.json','["素豔擁行舟，清香覆碧流。遠煙分的的，輕浪泛悠悠。", "雨歇平湖滿，風涼運瀆秋。今朝流詠處，即是白蘋洲。"]'),
('yuding-31','題梁王舊園','徐鉉','唐','御定全唐诗','yuding','','[]','梁王舊館枕潮溝，共引垂藤系小舟。樹倚荒颱風淅淅，',40,'御定全唐詩/json/756.json','["梁王舊館枕潮溝，共引垂藤系小舟。樹倚荒颱風淅淅，", "節士逢秋多感激，不須頻向此中游。"]'),
('yuding-32','奉酬度支陳員外','徐鉉','唐','御定全唐诗','yuding','','[]','古來賢達士，馳鶩唯群書。非禮誓弗習，違道無與居。',72,'御定全唐詩/json/756.json','["古來賢達士，馳鶩唯群書。非禮誓弗習，違道無與居。", "儒家若迂闊，遂將世情疏。吾友嗣世德，古風藹有餘。", "幸遇漢文皇，握蘭佩金魚。俯視長沙賦，淒淒將焉如。"]'),
('yuding-33','明道人歸西林，求題院額，作此送之','徐鉉','唐','御定全唐诗','yuding','','[]','昔從岐陽狩，簪纓滿翠微。十年勞我夢，今日送師歸。',48,'御定全唐詩/json/756.json','["昔從岐陽狩，簪纓滿翠微。十年勞我夢，今日送師歸。", "曳尾龜應樂，乘軒鶴謾肥。含情題小篆，將去掛岩扉。"]'),
('yuding-34','送宣州丘判官','徐鉉','唐','御定全唐诗','yuding','','[]','憲署遊從阻，平臺道路賒。喜君馳後乘，於此會仙槎。',48,'御定全唐詩/json/756.json','["憲署遊從阻，平臺道路賒。喜君馳後乘，於此會仙槎。", "緩酌遲飛蓋，微吟望綺霞。相迎在春渚，暫別莫咨嗟。"]'),
('yuding-35','北使還襄邑道中作','徐鉉','唐','御定全唐诗','yuding','','[]','九月三十日，獨行梁宋道。河流激似飛，林葉翻如掃。',48,'御定全唐詩/json/756.json','["九月三十日，獨行梁宋道。河流激似飛，林葉翻如掃。", "程遙苦晝短，野迥知寒早。還家亦不閑，要且還家了。"]'),
('yuding-36','禁中新月','徐鉉','唐','御定全唐诗','yuding','','[]','今夕拜新月，沉沉禁署中。玉繩疏間彩，金掌靜無風。',48,'御定全唐詩/json/756.json','["今夕拜新月，沉沉禁署中。玉繩疏間彩，金掌靜無風。", "節換知身老，時平見歲功。吟看北墀暝，蘭燼墜微紅。"]'),
('yuding-37','觀吉王從謙花燭','徐鉉','唐','御定全唐诗','yuding','','[]','王門嘉禮萬人觀，況是新承置醴歡。花燭喧闐丞相府，',40,'御定全唐詩/json/756.json','["王門嘉禮萬人觀，況是新承置醴歡。花燭喧闐丞相府，", "帝裏佳期頻賦頌，長留故事在金鑾。"]'),
('yuding-38','棋賭賦詩輸劉起居','徐鉉','唐','御定全唐诗','yuding','','[]','刻燭知無取，爭先素未精。本圖忘物我，何必計輸贏。',48,'御定全唐詩/json/756.json','["刻燭知無取，爭先素未精。本圖忘物我，何必計輸贏。", "賭墅終規利，焚囊亦近名。不如相視笑，高詠兩三聲。"]'),
('yuding-39','春盡日遊後湖贈劉起居','徐鉉','唐','御定全唐诗','yuding','','[]','今朝湖上送春歸，萬頃澄波照白髭。',32,'御定全唐詩/json/756.json','["今朝湖上送春歸，萬頃澄波照白髭。", "笑折殘花勸君酒，金丹成熟是何時。"]'),
('yuding-40','送察院李侍禦使廬陵因寄孟員外','徐鉉','唐','御定全唐诗','yuding','','[]','繡衣乘驛急如星，山水何妨寄野情。',32,'御定全唐詩/json/756.json','["繡衣乘驛急如星，山水何妨寄野情。", "肯向九仙台下歇，閑聽孟叟醉吟聲。"]'),
('yuding-41','後湖訪古各賦一題得西邸','徐鉉','唐','御定全唐诗','yuding','','[]','南朝藩閫地，八友舊招尋。事往山光在，春晴草色深。',48,'御定全唐詩/json/756.json','["南朝藩閫地，八友舊招尋。事往山光在，春晴草色深。", "曲池魚自樂，叢桂鳥頻吟。今日中興運，猶懷翰墨林。"]'),
('yuding-42','送德邁道人之豫章','徐鉉','唐','御定全唐诗','yuding','','[]','禪靈橋畔落殘花，橋上離情對日斜。顧我乘軒慚組綬，',40,'御定全唐詩/json/756.json','["禪靈橋畔落殘花，橋上離情對日斜。顧我乘軒慚組綬，", "莫道空談便無事，碧雲詩思更無涯。"]'),
('yuding-43','送陳秘監歸泉州','徐鉉','唐','御定全唐诗','yuding','','[]','風滿潮溝木葉飛，水邊行客駐驂騑。三朝恩澤馮唐老，',40,'御定全唐詩/json/756.json','["風滿潮溝木葉飛，水邊行客駐驂騑。三朝恩澤馮唐老，", "離歌不識高堂慶，特地令人淚滿衣。"]'),
('yuding-44','《又聽霓裳羽衣曲》送陳君','徐鉉','唐','御定全唐诗','yuding','','[]','清商一曲遠人行，桃葉津頭月正明。',32,'御定全唐詩/json/756.json','["清商一曲遠人行，桃葉津頭月正明。", "此是開元太平曲，莫教偏作別離聲。"]'),
('yuding-45','又題白鷺洲江鷗送陳君','徐鉉','唐','御定全唐诗','yuding','','[]','白鷺洲邊江路斜，輕鷗接翼滿平沙。吾徒來送遠行客，',72,'御定全唐詩/json/756.json','["白鷺洲邊江路斜，輕鷗接翼滿平沙。吾徒來送遠行客，", "離筵一曲怨複清，滿座銷魂鳥不驚。人生不及水禽樂，", "天涯後會眇難期，從此又應添白髭。願君不忘分飛處，"]'),
('yuding-46','哭刑部侍郎喬公詩','徐鉉','唐','御定全唐诗','yuding','','[]','舉世重文雅，夫君更質真。曾嗟混雞鶴，終日異淄磷。',120,'御定全唐詩/json/756.json','["舉世重文雅，夫君更質真。曾嗟混雞鶴，終日異淄磷。", "詞賦離騷客，封章諫諍臣。襟懷道家侶，標格古時人。", "逸老誠雲福，遺形未免貧。求文空得草，埋玉遂為塵。", "靜想忘年契，冥思接武晨。連宵洽杯酒，分日掌絲綸。", "蠹簡書陳事，遺孤托世親。前賢同此歎，非我獨沾巾。"]'),
('yuding-0','送程德琳郎中學士','徐鍇','唐','御定全唐诗','yuding','','[]','瓜步妖氛滅，昆岡草樹青。終朝空望極，今日送君行。',48,'御定全唐詩/json/757.json','["瓜步妖氛滅，昆岡草樹青。終朝空望極，今日送君行。", "報政秋雲靜，微吟曉月生。樓中長可見，特用滅離情。"]'),
('yuding-1','太傅相公以東觀庭梅西垣舊植昔陪盛賞…伏愧斐然','徐鍇','唐','御定全唐诗','yuding','','[]','靜對含章樹，閑思共有時。香隨荀令在，根異武昌移。',48,'御定全唐詩/json/757.json','["靜對含章樹，閑思共有時。香隨荀令在，根異武昌移。", "物性雖搖落，人心豈變衰。唱酬勝笛曲，來往韻朱絲。"]'),
('yuding-2','太傅相公與家兄梅花酬唱許綴末篇再賜新詩…伏惟采覽','徐鍇','唐','御定全唐诗','yuding','','[]','重歎梅花落，非關塞笛悲。論文叨接萼，末曲愧吹篪。',48,'御定全唐詩/json/757.json','["重歎梅花落，非關塞笛悲。論文叨接萼，末曲愧吹篪。", "枝逐清風動，香因白雪知。陶鈞敷左悌，更賦邵公詩。"]'),
('yuding-3','同家兄哭喬侍郎','徐鍇','唐','御定全唐诗','yuding','','[]','諸公長者鄭當時，事事無心性坦夷。但是登臨皆有作，',40,'御定全唐詩/json/757.json','["諸公長者鄭當時，事事無心性坦夷。但是登臨皆有作，", "三日笑談成理命，一篇投吊尚應知。"]'),
('yuding-4','秋詞','徐鍇','唐','御定全唐诗','yuding','','[]','井梧紛墮砌，寒雁遠橫空。雨久莓苔紫，霜濃薜荔紅。',24,'御定全唐詩/json/757.json','["井梧紛墮砌，寒雁遠橫空。雨久莓苔紫，霜濃薜荔紅。"]'),
('yuding-5','和徐鼎臣見寄','包穎','唐','御定全唐诗','yuding','','[]','平生中表最情親，浮世那堪聚散頻。謝脁卻吟歸省閣，',40,'御定全唐詩/json/757.json','["平生中表最情親，浮世那堪聚散頻。謝脁卻吟歸省閣，", "且喜新吟報強健，明年相望杏園春。"]'),
('yuding-6','貽耀州將','鐘謨','唐','御定全唐诗','yuding','','[]','翩翩歸盡塞垣鴻，隱隱驚開蟄戶蟲。渭北離愁春色裏，',40,'御定全唐詩/json/757.json','["翩翩歸盡塞垣鴻，隱隱驚開蟄戶蟲。渭北離愁春色裏，", "多謝賢侯振吾道，免令搔首泣途窮。"]'),
('yuding-7','獻周世宗','鐘謨','唐','御定全唐诗','yuding','','[]','三年耀武群雄服，一日回鑾萬國春。',32,'御定全唐詩/json/757.json','["三年耀武群雄服，一日回鑾萬國春。", "南北通歡永無事，謝恩歸去老陪臣。"]'),
('yuding-8','代京妓越賓答徐鉉','鐘謨','唐','御定全唐诗','yuding','','[]','一幅輕綃寄海濱，越姑長感昔時恩。',32,'御定全唐詩/json/757.json','["一幅輕綃寄海濱，越姑長感昔時恩。", "欲知別後情多少，點點憑君看淚痕。"]'),
('yuding-9','寄麻姑仙壇道士','查文徽','唐','御定全唐诗','yuding','','[]','別後相思鶴信稀，郡樓南望遠峰迷。人歸仙洞雲連地，',40,'御定全唐詩/json/757.json','["別後相思鶴信稀，郡樓南望遠峰迷。人歸仙洞雲連地，", "方平車駕今何在，常苦塵中日易西。"]'),
('yuding-10','贈韓定辭','馬彧','唐','御定全唐诗','yuding','','[]','燧林芳草綿綿思，盡日相攜陟麗譙。',32,'御定全唐詩/json/757.json','["燧林芳草綿綿思，盡日相攜陟麗譙。", "別後巏嵍山上望，羨君時複見王喬。"]'),
('yuding-11','答馬彧','韓定辭','唐','御定全唐诗','yuding','','[]','崇霞臺上神仙客，學辨癡龍藝最多。',32,'御定全唐詩/json/757.json','["崇霞臺上神仙客，學辨癡龍藝最多。", "盛德好將銀管述，麗詞堪與雪兒歌。"]'),
('yuding-12','題楊克儉池館','何昌齡','唐','御定全唐诗','yuding','','[]','經旬因雨不重來，門有蛛絲徑有苔。',32,'御定全唐詩/json/757.json','["經旬因雨不重來，門有蛛絲徑有苔。", "再向白蓮亭上望，不知花木為誰開。"]'),
('yuding-13','獻江淮郡守盧公','李羽','唐','御定全唐诗','yuding','','[]','塞詔東來淝水濱，時情惟望秉陶鈞。',32,'御定全唐詩/json/757.json','["塞詔東來淝水濱，時情惟望秉陶鈞。", "將軍一陣為功業，忍見沙場百戰人。"]'),
('yuding-14','南山池','梁藻','唐','御定全唐诗','yuding','','[]','翡翠戲翻荷葉雨，鷺鷥飛破竹林煙。',32,'御定全唐詩/json/757.json','["翡翠戲翻荷葉雨，鷺鷥飛破竹林煙。", "時沽村酒臨軒酌，擬摘新茶靠石煎。"]'),
('yuding-15','嘲廬山道士','陳沆','唐','御定全唐诗','yuding','','[]','啖肉先生欲上升，黃雲踏破紫雲崩。',32,'御定全唐詩/json/757.json','["啖肉先生欲上升，黃雲踏破紫雲崩。", "龍腰鶴背無多力，傳與麻姑借大鵬。"]'),
('yuding-16','句','陳沆','唐','御定全唐诗','yuding','','[]','罷卻兒女戲，放他花木生。',40,'御定全唐詩/json/757.json','["罷卻兒女戲，放他花木生。", "掃地雲粘帚，耕山鳥怕牛。", "點入旱雲千國仰，力浮塵世一毫輕。"]'),
('yuding-17','贈織錦人','李詢','唐','御定全唐诗','yuding','','[]','劄劄機聲曉複晡，眼穿力盡竟何如。',32,'御定全唐詩/json/757.json','["劄劄機聲曉複晡，眼穿力盡竟何如。", "美人一曲成千賜，心裏猶嫌花樣疏。"]'),
('yuding-18','題金山','韓垂','唐','御定全唐诗','yuding','','[]','靈山一峰秀，岌然殊眾山。盤根大江底，插影浮雲間。',48,'御定全唐詩/json/757.json','["靈山一峰秀，岌然殊眾山。盤根大江底，插影浮雲間。", "雷霆常間作，風雨時往還。象外懸清影，千載長躋攀。"]'),
('yuding-19','後湖','朱存','唐','御定全唐诗','yuding','','[]','雷轟疊鼓火翻旗，三異翩翩試水師。',32,'御定全唐詩/json/757.json','["雷轟疊鼓火翻旗，三異翩翩試水師。", "驚起黑龍眠不得，狂風猛雨不多時。"]'),
('yuding-20','和徐舍人九月十一日見寄','陳彥','唐','御定全唐诗','yuding','','[]','衡門寂寂逢迎少，不見仙郎向五旬。',32,'御定全唐詩/json/757.json','["衡門寂寂逢迎少，不見仙郎向五旬。", "莫問龍山前日事，菊花開卻為閒人。"]'),
('yuding-21','登游齊山','許堅1','唐','御定全唐诗','yuding','','[]','星使南馳入楚重，此山偏得駐行蹤。',32,'御定全唐詩/json/757.json','["星使南馳入楚重，此山偏得駐行蹤。", "落花滿地月華冷，寂寞舊山三四峰。"]'),
('yuding-22','游溧陽下山寺','許堅1','唐','御定全唐诗','yuding','','[]','地枕吳溪與越峰，前朝恩錫靈泉額。竹林晴見雁塔高，',40,'御定全唐詩/json/757.json','["地枕吳溪與越峰，前朝恩錫靈泉額。竹林晴見雁塔高，", "客有經年說別林，落日啼猿情脈脈。"]'),
('yuding-23','題幽棲觀','許堅1','唐','御定全唐诗','yuding','','[]','仙翁上升去，丹井寄晴壑。山色接天臺，湖光照寥廓。',48,'御定全唐詩/json/757.json','["仙翁上升去，丹井寄晴壑。山色接天臺，湖光照寥廓。", "玉洞絕無人，老檜猶棲鶴。我欲掣青蛇，他時沖碧落。"]'),
('yuding-24','上舍人徐鉉','許堅1','唐','御定全唐诗','yuding','','[]','幾宵煙月鎖樓臺，欲寄侯門薦下才。',32,'御定全唐詩/json/757.json','["幾宵煙月鎖樓臺，欲寄侯門薦下才。", "滿面塵埃人不識，謾隨流水出山來。"]'),
('yuding-25','題茅山觀','許堅1','唐','御定全唐诗','yuding','','[]','常恨清風千載鬱，洞天令得恣遊遨。松楸古色玉壇靜，',40,'御定全唐詩/json/757.json','["常恨清風千載鬱，洞天令得恣遊遨。松楸古色玉壇靜，", "分明有個長生路，休向紅塵歎二毛。"]'),
('yuding-26','建州節帥更代，筵上獻詩','王感化','唐','御定全唐诗','yuding','','[]','旌旗赴天臺，溪山曉色開。萬家悲更喜，迎佛送如來。',24,'御定全唐詩/json/757.json','["旌旗赴天臺，溪山曉色開。萬家悲更喜，迎佛送如來。"]'),
('yuding-27','奉元宗命詠苑中白野鵲','王感化','唐','御定全唐诗','yuding','','[]','碧岩深洞恣遊遨，天與蘆花作羽毛。',32,'御定全唐詩/json/757.json','["碧岩深洞恣遊遨，天與蘆花作羽毛。", "要識此來棲宿處，上林瓊樹一枝高。"]'),
('yuding-28','句','王感化','唐','御定全唐诗','yuding','','[]','草中誤認將軍虎，山上曾為道士羊。（《題怪石》八句，',25,'御定全唐詩/json/757.json','["草中誤認將軍虎，山上曾為道士羊。（《題怪石》八句，"]'),
('yuding-29','元宗釣魚無獲，進詩','李家明','唐','御定全唐诗','yuding','','[]','玉甃垂鉤興正濃，碧池春暖水溶溶。',32,'御定全唐詩/json/757.json','["玉甃垂鉤興正濃，碧池春暖水溶溶。", "凡鱗不敢吞香餌，知是君王合釣龍。"]'),
('yuding-30','詠臥牛','李家明','唐','御定全唐诗','yuding','','[]','曾遭甯戚鞭敲角，又被田單火燎身。',32,'御定全唐詩/json/757.json','["曾遭甯戚鞭敲角，又被田單火燎身。", "閑向斜陽嚼枯草，近來問喘為無人。"]'),
('yuding-31','題紙鳶止宋齊丘哭子','李家明','唐','御定全唐诗','yuding','','[]','安排唐祚革強吳，儘是先生作計謨。',32,'御定全唐詩/json/757.json','["安排唐祚革強吳，儘是先生作計謨。", "一個孩兒拚不得，讓皇百口合何如。"]'),
('yuding-32','詠皖公山','李家明','唐','御定全唐诗','yuding','','[]','龍舟輕颭錦帆風，正值宸遊望遠空。',32,'御定全唐詩/json/757.json','["龍舟輕颭錦帆風，正值宸遊望遠空。", "回首皖公山色翠，影斜不到壽杯中。"]'),
('yuding-33','奉和聖制送鄧王牧宣城','湯悅','唐','御定全唐诗','yuding','','[]','千里陵陽同陝服，鑿門胙土寄親賢。曙煙已別黃金殿，',40,'御定全唐詩/json/757.json','["千里陵陽同陝服，鑿門胙土寄親賢。曙煙已別黃金殿，", "天心待報期年政，留與工師播管弦。"]'),
('yuding-34','早春寄華下同志','湯悅','唐','御定全唐诗','yuding','','[]','正是花時節，思君寢復興。市沽終不醉，春夢亦無憑。',48,'御定全唐詩/json/757.json','["正是花時節，思君寢復興。市沽終不醉，春夢亦無憑。", "嶽面懸清雨，河心走濁冰。東門一條路，離恨正相仍。"]'),
('yuding-35','鼎臣學士侍郎以東館庭梅昔翰苑之毫末今複半枯…攀和','湯悅','唐','御定全唐诗','yuding','','[]','憶見萌芽日，還憐合抱時。舊歡如夢想，物態暗還移。',48,'御定全唐詩/json/757.json','["憶見萌芽日，還憐合抱時。舊歡如夢想，物態暗還移。", "素豔今無幾，朱顏亦自衰。樹將人共老，何暇更悲絲。"]'),
('yuding-36','再次前韻代梅答','湯悅','唐','御定全唐诗','yuding','','[]','托植經多稔，頃筐向盛時。枝條雖已故，情分不曾移。',48,'御定全唐詩/json/757.json','["托植經多稔，頃筐向盛時。枝條雖已故，情分不曾移。", "莫向階前老，還同鏡裏衰。更應憐墮葉，殘吹掛蟲絲。"]'),
('yuding-37','鼎臣學士侍郎、楚金舍人學士以再傷…成四十字陳謝','湯悅','唐','御定全唐诗','yuding','','[]','人物同遷謝，重成念舊悲。連華得瓊玖，合奏發塤篪。',48,'御定全唐詩/json/757.json','["人物同遷謝，重成念舊悲。連華得瓊玖，合奏發塤篪。", "餘枿雖無取，殘芳尚獲知。問君何所似，珍重杜秋詩。"]'),
('yuding-38','送鐘員外','蕭彧','唐','御定全唐诗','yuding','','[]','麗漢金波滿，當筵玉斝傾。因思頻聚散，幾複換虧盈。',48,'御定全唐詩/json/757.json','["麗漢金波滿，當筵玉斝傾。因思頻聚散，幾複換虧盈。", "光徹離襟冷，聲符別管清。那堪還目此，兩地倚樓情。"]'),
('yuding-39','送德林郎中學士赴東府','蕭彧','唐','御定全唐诗','yuding','','[]','離情折楊柳，此別異春哉。含露東籬豔，泛香南浦杯。',48,'御定全唐詩/json/757.json','["離情折楊柳，此別異春哉。含露東籬豔，泛香南浦杯。", "惜持行次贈，留插醉中回。暮齒如能制，玉山甘判頹。"]'),
('yuding-40','送鐘員外','孫峴','唐','御定全唐诗','yuding','','[]','萬物中蕭灑，修篁獨逸群。貞姿曾冒雪，高節欲淩雲。',48,'御定全唐詩/json/757.json','["萬物中蕭灑，修篁獨逸群。貞姿曾冒雪，高節欲淩雲。", "細韻風初發，濃煙日正曛。因題偏惜別，不可暫無君。"]'),
('yuding-41','送鐘員外','謝仲宣','唐','御定全唐诗','yuding','','[]','送人多折柳，唯我獨吟松。若保歲寒在，何妨霜雪重。',48,'御定全唐詩/json/757.json','["送人多折柳，唯我獨吟松。若保歲寒在，何妨霜雪重。", "森梢逢靜境，廓落見孤峰。還似君高節，亭亭鮮繼蹤。"]'),
('yuding-42','別諸同志','鐘蒨','唐','御定全唐诗','yuding','','[]','隨陽來萬里，點點度遙空。影落長江水，聲悲半夜風。',48,'御定全唐詩/json/757.json','["隨陽來萬里，點點度遙空。影落長江水，聲悲半夜風。", "殘秋辭絕漠，無定似驚蓬。我有離群恨，飄飄類此鴻。"]'),
('yuding-43','送德林郎中學士赴東府','喬舜','唐','御定全唐诗','yuding','','[]','摻袂向江頭，朝宗勢未休。何人乘桂楫，之子過揚州。',48,'御定全唐詩/json/757.json','["摻袂向江頭，朝宗勢未休。何人乘桂楫，之子過揚州。", "颯颯翹沙雁，漂漂逐浪鷗。欲知離別恨，半是淚和流。"]'),
('yuding-44','送鐘員外','王沂','唐','御定全唐诗','yuding','','[]','靜追蘋末興，況複值蕭條。猛勢資新雁，寒聲伴暮潮。',48,'御定全唐詩/json/757.json','["靜追蘋末興，況複值蕭條。猛勢資新雁，寒聲伴暮潮。", "過山雲散亂，經樹葉飄颻。今日煙江上，征帆望望遙。"]'),
('yuding-45','送德林郎中學士赴東府','陳元裕','唐','御定全唐诗','yuding','','[]','上善湛然秋，恩波洽帝猷。謾言生險浪，豈爽見安流。',48,'御定全唐詩/json/757.json','["上善湛然秋，恩波洽帝猷。謾言生險浪，豈爽見安流。", "泛去星槎遠，澄來月練浮。滔滔對離酌，入洛稱仙舟。"]'),
('yuding-0','宿山寺','孟貫','唐','御定全唐诗','yuding','','[]','溪山盡日行，方聽遠鐘聲。入院逢僧定，登樓見月生。',48,'御定全唐詩/json/758.json','["溪山盡日行，方聽遠鐘聲。入院逢僧定，登樓見月生。", "露垂群木潤，泉落一岩清。此景關吾事，通宵寐不成。"]'),
('yuding-1','贈棲隱洞譚先生','孟貫','唐','御定全唐诗','yuding','','[]','先生雙鬢華，深谷臥雲霞。不伐有巢樹，多移無主花。',48,'御定全唐詩/json/758.json','["先生雙鬢華，深谷臥雲霞。不伐有巢樹，多移無主花。", "石泉春釀酒，松火夜煎茶。因問山中事，如君有幾家。"]'),
('yuding-2','歸雁','孟貫','唐','御定全唐诗','yuding','','[]','春至衡陽雁，思歸塞路長。汀洲齊奮翼，霄漢共成行。',48,'御定全唐詩/json/758.json','["春至衡陽雁，思歸塞路長。汀洲齊奮翼，霄漢共成行。", "雪盡翻風暖，寒收度月涼。直應到秋日，依舊返瀟湘。"]'),
('yuding-3','春江送人','孟貫','唐','御定全唐诗','yuding','','[]','春江多去情，相去枕長汀。數雁別湓浦，片帆離洞庭。',48,'御定全唐詩/json/758.json','["春江多去情，相去枕長汀。數雁別湓浦，片帆離洞庭。", "雨餘沙草綠，雲散岸峰青。誰共觀明月，漁歌夜好聽。"]'),
('yuding-4','過秦嶺','孟貫','唐','御定全唐诗','yuding','','[]','古今傳此嶺，高下勢崢嶸。安得青山路，化為平地行。',48,'御定全唐詩/json/758.json','["古今傳此嶺，高下勢崢嶸。安得青山路，化為平地行。", "蒼苔留虎跡，碧樹障溪聲。欲過一回首，踟躕無限情。"]'),
('yuding-5','送吳夢誾歸閩','孟貫','唐','御定全唐诗','yuding','','[]','甌閩在天末，此去整行衣。久客逢春盡，思家冒暑歸。',48,'御定全唐詩/json/758.json','["甌閩在天末，此去整行衣。久客逢春盡，思家冒暑歸。", "海雲添晚景，山瘴滅晴暉。相憶吟偏苦，不堪書信稀。"]'),
('yuding-6','山中夏日','孟貫','唐','御定全唐诗','yuding','','[]','深山宜避暑，門戶映嵐光。夏木蔭溪路，晝雲埋石床。',48,'御定全唐詩/json/758.json','["深山宜避暑，門戶映嵐光。夏木蔭溪路，晝雲埋石床。", "心源澄道靜，衣葛蘸泉涼。算得紅塵裏，誰知此興長。"]'),
('yuding-7','宿故人江居','孟貫','唐','御定全唐诗','yuding','','[]','渡口樹冥冥，南山漸隱青。漁舟歸舊浦，鷗鳥宿前汀。',48,'御定全唐詩/json/758.json','["渡口樹冥冥，南山漸隱青。漁舟歸舊浦，鷗鳥宿前汀。", "靜榻懸燈坐，閑門對浪扃。相思頻到此，幾番醉還醒。"]'),
('yuding-8','寄伍喬','孟貫','唐','御定全唐诗','yuding','','[]','蹉跎春又晚，天末信來遲。長憶分攜日，正當搖落時。',48,'御定全唐詩/json/758.json','["蹉跎春又晚，天末信來遲。長憶分攜日，正當搖落時。", "獨游饒旅恨，多事失歸期。君看前溪樹，山禽巢幾枝。"]'),
('yuding-9','山中訪人不遇','孟貫','唐','御定全唐诗','yuding','','[]','負琴兼杖藜，特地過岩西。已見竹軒閉，又聞山鳥啼。',48,'御定全唐詩/json/758.json','["負琴兼杖藜，特地過岩西。已見竹軒閉，又聞山鳥啼。", "長松寒倚穀，細草暗連溪。久立無人事，煙霞歸路迷。"]'),
('yuding-10','贈隱者','孟貫','唐','御定全唐诗','yuding','','[]','世路爭名利，深山獨結茅。安情自得所，非道豈相交。',48,'御定全唐詩/json/758.json','["世路爭名利，深山獨結茅。安情自得所，非道豈相交。", "百尺松當戶，千年鶴在巢。知君于此景，未欲等閒拋。"]'),
('yuding-11','寄暹上人','孟貫','唐','御定全唐诗','yuding','','[]','聞罷城中講，來安頂上禪。夜燈明石室，清磬出岩泉。',48,'御定全唐詩/json/758.json','["聞罷城中講，來安頂上禪。夜燈明石室，清磬出岩泉。", "欲訪慚多事，相思恨來年。終期息塵慮，接話虎溪邊。"]'),
('yuding-12','江邊閒步','孟貫','唐','御定全唐诗','yuding','','[]','閑來南渡口，迤邐看江楓。一路波濤畔，數家蘆葦中。',48,'御定全唐詩/json/758.json','["閑來南渡口，迤邐看江楓。一路波濤畔，數家蘆葦中。", "遠汀排晚樹，深浦漾寒鴻。吟罷慵回首，此情誰與同。"]'),
('yuding-13','過王逸人園林','孟貫','唐','御定全唐诗','yuding','','[]','穀口何時住，煙霞一徑深。水聲離遠洞，山色出疏林。',48,'御定全唐詩/json/758.json','["穀口何時住，煙霞一徑深。水聲離遠洞，山色出疏林。", "雪彩從沾鬢，年光不計心。自言人少到，猶喜我來尋。"]'),
('yuding-14','寄李處士','孟貫','唐','御定全唐诗','yuding','','[]','僧話磻溪叟，平生重赤松。夜堂悲蟋蟀，秋水老芙蓉。',48,'御定全唐詩/json/758.json','["僧話磻溪叟，平生重赤松。夜堂悲蟋蟀，秋水老芙蓉。", "吟坐倦垂釣，閑行多倚筇。聞名來已久，未得一相逢。"]'),
('yuding-15','夏日寄史處士','孟貫','唐','御定全唐诗','yuding','','[]','掩關苔滿地，終日坐騰騰。暑氣冷衣葛，暮雲催燭燈。',48,'御定全唐詩/json/758.json','["掩關苔滿地，終日坐騰騰。暑氣冷衣葛，暮雲催燭燈。", "寂寥知得趣，疏懶似無能。還憶舊游否，何年別杜陵。"]'),
('yuding-16','夏日登瀑頂寺，因寄諸知己','孟貫','唐','御定全唐诗','yuding','','[]','曾於塵裏望，此景在煙霄。岩靜水聲近，山深暑氣遙。',48,'御定全唐詩/json/758.json','["曾於塵裏望，此景在煙霄。岩靜水聲近，山深暑氣遙。", "杖藜青石路，煮茗白雲樵。寄語為郎者，誰能訪寂寥。"]'),
('yuding-17','懷果上人','孟貫','唐','御定全唐诗','yuding','','[]','擁錫南遊去，名香幾處焚。別來無遠信，多恐在深雲。',48,'御定全唐詩/json/758.json','["擁錫南遊去，名香幾處焚。別來無遠信，多恐在深雲。", "好月曾同步，幽香省共聞。相思不相見，林下葉紛紛。"]'),
('yuding-18','寄故園兄弟','孟貫','唐','御定全唐诗','yuding','','[]','久與鄉關阻，風塵損舊衣。水思和月泛，山憶共僧歸。',48,'御定全唐詩/json/758.json','["久與鄉關阻，風塵損舊衣。水思和月泛，山憶共僧歸。", "林想添鄰舍，溪應改釣磯。弟兄無苦事，不用別庭闈。"]'),
('yuding-19','早秋吟眺','孟貫','唐','御定全唐诗','yuding','','[]','新秋初雨後，獨立對遙山。去鳥望中沒，好雲吟裏還。',48,'御定全唐詩/json/758.json','["新秋初雨後，獨立對遙山。去鳥望中沒，好雲吟裏還。", "長年慚道薄，明代取身閑。從有西征思，園林懶閉關。"]'),
('yuding-20','送江為歸嶺南','孟貫','唐','御定全唐诗','yuding','','[]','舊山臨海色，歸路到天涯。此別各多事，重逢是幾時。',48,'御定全唐詩/json/758.json','["舊山臨海色，歸路到天涯。此別各多事，重逢是幾時。", "江行晴望遠，嶺宿夜吟遲。珍重南方客，清風失所思。"]'),
('yuding-21','山中答友人','孟貫','唐','御定全唐诗','yuding','','[]','偶愛春山住，因循值暑時。風塵非所願，泉石本相宜。',48,'御定全唐詩/json/758.json','["偶愛春山住，因循值暑時。風塵非所願，泉石本相宜。", "坐久松陰轉，吟餘蟬韻移。自慚疏野甚，多失故人期。"]'),
('yuding-22','山齋早秋雨中','孟貫','唐','御定全唐诗','yuding','','[]','深居少往還，卷箔早秋間。雨灑吟蟬樹，雲藏嘯狖山。',48,'御定全唐詩/json/758.json','["深居少往還，卷箔早秋間。雨灑吟蟬樹，雲藏嘯狖山。", "炎蒸如便退，衣葛亦堪閑。靜坐得無事，酒卮聊暢顏。"]'),
('yuding-23','送人游南越','孟貫','唐','御定全唐诗','yuding','','[]','孑然南越去，替爾畏前程。見說路岐嶮，不通車馬行。',48,'御定全唐詩/json/758.json','["孑然南越去，替爾畏前程。見說路岐嶮，不通車馬行。", "瘴煙迷海色，嶺樹帶猿聲。獨向山家宿，多應鄉思生。"]'),
('yuding-24','酬東溪史處士','孟貫','唐','御定全唐诗','yuding','','[]','咫尺東溪路，年來偶訪遲。泉聲迷夜雨，花片落空枝。',48,'御定全唐詩/json/758.json','["咫尺東溪路，年來偶訪遲。泉聲迷夜雨，花片落空枝。", "石徑逢僧出，山床見鶴移。貧齋有琴酒，曾許月圓期。"]'),
('yuding-25','秋江送客','孟貫','唐','御定全唐诗','yuding','','[]','秋風楚江上，送子話遊遨。遠水宿何處，孤舟春夜濤。',48,'御定全唐詩/json/758.json','["秋風楚江上，送子話遊遨。遠水宿何處，孤舟春夜濤。", "浦雲沈雁影，山月照猿嗥。莫為饑寒苦，便成名利勞。"]'),
('yuding-26','寄山中高逸人','孟貫','唐','御定全唐诗','yuding','','[]','煙霞多放曠，吟嘯是尋常。猿共摘山果，僧鄰住石房。',48,'御定全唐詩/json/758.json','["煙霞多放曠，吟嘯是尋常。猿共摘山果，僧鄰住石房。", "躡雲雙屐冷，采藥一身香。我憶相逢夜，松潭月色涼。"]'),
('yuding-27','懷友人','孟貫','唐','御定全唐诗','yuding','','[]','浮世況多事，飄流每歎君。路岐何處去，消息幾時聞。',48,'御定全唐詩/json/758.json','["浮世況多事，飄流每歎君。路岐何處去，消息幾時聞。", "吟裏落秋葉，望中生暮雲。孤懷誰慰我，夕鳥自成群。"]'),
('yuding-28','送人歸別業','孟貫','唐','御定全唐诗','yuding','','[]','別業五湖上，春殘去路賒。還尋舊山水，重到故人家。',48,'御定全唐詩/json/758.json','["別業五湖上，春殘去路賒。還尋舊山水，重到故人家。", "門徑掩芳草，園林落異花。君知釣磯在，猶喜有生涯。"]'),
('yuding-29','冬日登江樓','孟貫','唐','御定全唐诗','yuding','','[]','高樓臨古岸，野步晚來登。江水因寒落，山雲為雪凝。',48,'御定全唐詩/json/758.json','["高樓臨古岸，野步晚來登。江水因寒落，山雲為雪凝。", "遠村雖入望，危檻不堪憑。親老未歸去，鄉愁徒自興。"]'),
('yuding-30','寄張山人','孟貫','唐','御定全唐诗','yuding','','[]','草堂南澗邊，有客嘯雲煙。掃葉林風後，拾薪山雨前。',48,'御定全唐詩/json/758.json','["草堂南澗邊，有客嘯雲煙。掃葉林風後，拾薪山雨前。", "野橋通竹徑，流水入芝田。琴月相親夜，更深戀不眠。"]'),
('yuding-0','杜鵑花','成彥雄','唐','御定全唐诗','yuding','','[]','杜鵑花與鳥，怨豔兩何賒。疑是口中血，滴成枝上花。',48,'御定全唐詩/json/759.json','["杜鵑花與鳥，怨豔兩何賒。疑是口中血，滴成枝上花。", "一聲寒食夜，數朵野僧家。謝豹出不出，日遲遲又斜。"]'),
('yuding-1','江上楓','成彥雄','唐','御定全唐诗','yuding','','[]','江楓自蓊鬱，不競松筠力。一葉落漁家，殘陽帶秋色。',24,'御定全唐詩/json/759.json','["江楓自蓊鬱，不競松筠力。一葉落漁家，殘陽帶秋色。"]'),
('yuding-2','夜夜曲','成彥雄','唐','御定全唐诗','yuding','','[]','自從君去夜，錦幌孤蘭麝。欹枕對銀缸，秦箏綠窗下。',24,'御定全唐詩/json/759.json','["自從君去夜，錦幌孤蘭麝。欹枕對銀缸，秦箏綠窗下。"]'),
('yuding-3','村行','成彥雄','唐','御定全唐诗','yuding','','[]','曖曖村煙暮，牧童出深塢。騎牛不顧人，吹笛尋山去。',24,'御定全唐詩/json/759.json','["曖曖村煙暮，牧童出深塢。騎牛不顧人，吹笛尋山去。"]'),
('yuding-4','煎茶','成彥雄','唐','御定全唐诗','yuding','','[]','嶽寺春深睡起時，虎跑泉畔思遲遲。',32,'御定全唐詩/json/759.json','["嶽寺春深睡起時，虎跑泉畔思遲遲。", "蜀茶倩個雲僧碾，自拾枯松三四枝。"]'),
('yuding-5','松','成彥雄','唐','御定全唐诗','yuding','','[]','大夫名價古今聞，盤屈孤貞更出群。',32,'御定全唐詩/json/759.json','["大夫名價古今聞，盤屈孤貞更出群。", "將謂嶺頭閑得了，夕陽猶掛數枝雲。"]'),
('yuding-6','新燕','成彥雄','唐','御定全唐诗','yuding','','[]','才離海島宿江濱，應夢笙歌作近鄰。',32,'御定全唐詩/json/759.json','["才離海島宿江濱，應夢笙歌作近鄰。", "減省雕梁並頭語，畫堂中有未歸人。"]'),
('yuding-7','會友不至','成彥雄','唐','御定全唐诗','yuding','','[]','王孫還是負佳期，玉馬追遊日漸西。',32,'御定全唐詩/json/759.json','["王孫還是負佳期，玉馬追遊日漸西。", "獨上郊原人不見，鷓鴣飛過落花溪。"]'),
('yuding-8','惜花','成彥雄','唐','御定全唐诗','yuding','','[]','忘餐為戀滿枝紅，錦障頻移護晚風。',32,'御定全唐詩/json/759.json','["忘餐為戀滿枝紅，錦障頻移護晚風。", "客散酒酣歸未得，欄邊獨立月明中。"]'),
('yuding-9','中秋月','成彥雄','唐','御定全唐诗','yuding','','[]','王母妝成鏡未收，倚欄人在水精樓。',32,'御定全唐詩/json/759.json','["王母妝成鏡未收，倚欄人在水精樓。", "笙歌莫占清光盡，留與溪翁一釣舟。"]'),
('yuding-10','暮春日宴溪亭','成彥雄','唐','御定全唐诗','yuding','','[]','寒食尋芳遊不足，溪亭還醉綠楊煙。',32,'御定全唐詩/json/759.json','["寒食尋芳遊不足，溪亭還醉綠楊煙。", "誰家花落臨流樹，數片殘紅到檻前。"]'),
('yuding-11','曉','成彥雄','唐','御定全唐诗','yuding','','[]','列宿回元朝北極，爽神晞露滴樓臺。',32,'御定全唐詩/json/759.json','["列宿回元朝北極，爽神晞露滴樓臺。", "佳人卷箔臨階砌，笑指庭花昨夜開。"]'),
('yuding-12','夕','成彥雄','唐','御定全唐诗','yuding','','[]','台榭沉沉禁漏初，麝煙紅蠟透蝦須。',32,'御定全唐詩/json/759.json','["台榭沉沉禁漏初，麝煙紅蠟透蝦須。", "雕籠鸚鵡將棲宿，不許鴉鬟轉轆轤。"]'),
('yuding-13','露','成彥雄','唐','御定全唐诗','yuding','','[]','銀河昨夜降醍醐，灑遍坤維萬象蘇。',32,'御定全唐詩/json/759.json','["銀河昨夜降醍醐，灑遍坤維萬象蘇。", "疑是鮫人曾泣處，滿池荷葉捧真珠。"]'),
('yuding-14','游紫陽宮','成彥雄','唐','御定全唐诗','yuding','','[]','古殿煙霞簇畫屏，直疑蹤跡到蓬瀛。',32,'御定全唐詩/json/759.json','["古殿煙霞簇畫屏，直疑蹤跡到蓬瀛。", "碧桃滿地眠花鹿，深院松窗搗藥聲。"]'),
('yuding-15','除夜','成彥雄','唐','御定全唐诗','yuding','','[]','銅龍看卻送春來，莫惜顛狂酒百杯。',32,'御定全唐詩/json/759.json','["銅龍看卻送春來，莫惜顛狂酒百杯。", "吟鬢就中專擬白，那堪更被二更催。"]'),
('yuding-16','元日','成彥雄','唐','御定全唐诗','yuding','','[]','戴星先捧祝堯觴，鏡裏堪驚兩鬢霜。',32,'御定全唐詩/json/759.json','["戴星先捧祝堯觴，鏡裏堪驚兩鬢霜。", "好是燈前偷失笑，屠蘇應不得先嘗。"]'),
('yuding-17','寒夜吟','成彥雄','唐','御定全唐诗','yuding','','[]','洞房脈脈寒宵永，燭影香消金鳳冷。',32,'御定全唐詩/json/759.json','["洞房脈脈寒宵永，燭影香消金鳳冷。", "猧兒睡魘喚不醒，滿窗撲落銀蟾影。"]'),
('yuding-18','柳枝辭九首','成彥雄','唐','御定全唐诗','yuding','','[]','輕籠小徑近誰家，玉馬追風翠影斜。',288,'御定全唐詩/json/759.json','["輕籠小徑近誰家，玉馬追風翠影斜。", "愛把長條惱公子，惹他頭上海棠花。", "鵝黃剪出小花鈿，綴上芳枝色轉鮮。", "飲散無人收拾得，月明階下伴秋千。", "東君愛惜與先春，草澤無人處也新。", "委囑露華並細雨，莫教遲日惹風塵。", "句踐初迎西子年，琉璃為帚掃溪煙。", "至今不改當時色，留與王孫系酒船。", "綠楊移傍小亭栽，便擁穠煙撥不開。", "誰把金刀為刪掠，放教明月入窗來。", "遠接關河高接雲，雨餘洗出半天津。", "牡丹不用相輕薄，自有清陰覆得人。", "掩映鶯花媚有餘，風流才調比應無。", "朝朝奉禦臨池上，不羨青松拜大夫。", "王孫宴罷曲江池，折取春光伴醉歸。", "怪得美人爭鬥乞，要他穠翠染羅衣。", "殘照林梢嫋數枝，能招醉客上金堤。", "馬嬌如練纓如火，瑟瑟陰中步步嘶。"]'),
('yuding-19','句','成彥雄','唐','御定全唐诗','yuding','','[]','莎草放茵深護砌，海榴噴火巧橫牆。',32,'御定全唐詩/json/759.json','["莎草放茵深護砌，海榴噴火巧橫牆。", "紋鱗引子跳銀海，紫燕呼雛語畫梁。"]'),
('yuding-0','寄禪月大師','周庠','唐','御定全唐诗','yuding','','[]','昨日塵遊到幾家，就中偏省近宣麻。水田鋪座時移畫，',40,'御定全唐詩/json/760.json','["昨日塵遊到幾家，就中偏省近宣麻。水田鋪座時移畫，", "有時撚得休公卷，倚柱閑吟見落霞。"]'),
('yuding-1','寄禪月大師','張格','唐','御定全唐诗','yuding','','[]','龍華咫尺斷來音，日夕空馳詠德心。禪月字清師號別，',40,'御定全唐詩/json/760.json','["龍華咫尺斷來音，日夕空馳詠德心。禪月字清師號別，", "莫倚名高忘故舊，曉晴閒步一相尋。"]'),
('yuding-2','贈禪月大師','王鍇','唐','御定全唐诗','yuding','','[]','長愛吾師性自然，天心白月水中蓮。神通力遍恒沙外，',40,'御定全唐詩/json/760.json','["長愛吾師性自然，天心白月水中蓮。神通力遍恒沙外，", "太平時節俱無事，莫惜時來話草玄。"]'),
('yuding-3','奉詔賦蜀主降唐','牛希濟','唐','御定全唐诗','yuding','','[]','滿城文武欲朝天，不覺鄰師犯塞煙。唐主再懸新日月，',40,'御定全唐詩/json/760.json','["滿城文武欲朝天，不覺鄰師犯塞煙。唐主再懸新日月，", "古往今來亦如此，幾曾歡笑幾潸然。"]'),
('yuding-4','蜀馱引','馮涓','唐','御定全唐诗','yuding','','[]','昂藏大步蠶叢國，曲頸微伸高九尺。',64,'御定全唐詩/json/760.json','["昂藏大步蠶叢國，曲頸微伸高九尺。", "卓女窺窗莫我知，嚴仙據案何曾識。", "自古皆傳蜀道難，爾何能過拔蛇山。", "忽驚登得雞翁磧，又恐礙著鹿頭關。"]'),
('yuding-5','句','馮涓','唐','御定全唐诗','yuding','','[]','不隨俗物皆成土，只待良時卻補天。（《題支機石》，',40,'御定全唐詩/json/760.json','["不隨俗物皆成土，只待良時卻補天。（《題支機石》，", "釜魚化作池中物，木履浮為天際船。"]'),
('yuding-6','從幸秦川賦鷙獸詩','李浩弼','唐','御定全唐诗','yuding','','[]','岩下年年自寢訛，生靈餐盡意如何。爪牙眾後民隨減，',40,'御定全唐詩/json/760.json','["岩下年年自寢訛，生靈餐盡意如何。爪牙眾後民隨減，", "長途莫怪無人跡，盡被山王棱殺他。"]'),
('yuding-7','批子弟理舊居狀','楊玢','唐','御定全唐诗','yuding','','[]','四鄰侵我我從伊，畢竟須思未有時。',32,'御定全唐詩/json/760.json','["四鄰侵我我從伊，畢竟須思未有時。", "試上含元殿基望，秋風秋草正離離。"]'),
('yuding-8','登慈恩寺塔','楊玢','唐','御定全唐诗','yuding','','[]','紫雲樓下曲江平，鴉噪殘陽麥隴青。',32,'御定全唐詩/json/760.json','["紫雲樓下曲江平，鴉噪殘陽麥隴青。", "莫上慈恩最高處，不堪看又不堪聽。"]'),
('yuding-9','遣歌妓','楊玢','唐','御定全唐诗','yuding','','[]','垂老無端用意乖，誰知道侶厭清齋。',32,'御定全唐詩/json/760.json','["垂老無端用意乖，誰知道侶厭清齋。", "如今又采蘼蕪去，辜負張君繡靸鞋。"]'),
('yuding-10','和題劍門','韓昭','唐','御定全唐诗','yuding','','[]','閉關防老寇，孰敢振威棱。險固疑天設，山河自古憑。',48,'御定全唐詩/json/760.json','["閉關防老寇，孰敢振威棱。險固疑天設，山河自古憑。", "三川奚所賴，雙劍最堪矜。鳥道微通處，煙霞鎖百層。"]'),
('yuding-11','從幸秦川過白衛獻詩','韓昭','唐','御定全唐诗','yuding','','[]','吾王巡狩為安邊，此去秦亭尚數千。夜照路岐山店火，',40,'御定全唐詩/json/760.json','["吾王巡狩為安邊，此去秦亭尚數千。夜照路岐山店火，", "八駿似龍人似虎，何愁飛過大漫天。"]'),
('yuding-12','記皂江墮水事','楊鼎夫','唐','御定全唐诗','yuding','','[]','青城山峭皂江寒，欲度當時作等閒。棹逆狂風趨近岸，',40,'御定全唐詩/json/760.json','["青城山峭皂江寒，欲度當時作等閒。棹逆狂風趨近岸，", "今日深恩無以報，令人羞記雀銜環。"]'),
('yuding-13','題張道隱太山祠畫龍','蔣貽恭','唐','御定全唐诗','yuding','','[]','世人空解競丹青，惟子通玄得墨靈。應有鬼神看下筆，',40,'御定全唐詩/json/760.json','["世人空解競丹青，惟子通玄得墨靈。應有鬼神看下筆，", "靜閉綠堂深夜後，曉來簾幕似聞腥。"]'),
('yuding-14','詠蠶','蔣貽恭','唐','御定全唐诗','yuding','','[]','辛勤得繭不盈筐，燈下繅絲恨更長。',32,'御定全唐詩/json/760.json','["辛勤得繭不盈筐，燈下繅絲恨更長。", "著處不知來處苦，但貪衣上繡鴛鴦。"]'),
('yuding-15','漁父歌三首','李珣','唐','御定全唐诗','yuding','','[]','水接衡門十裏餘，信船歸去臥看書。',96,'御定全唐詩/json/760.json','["水接衡門十裏餘，信船歸去臥看書。", "輕爵祿，慕玄虛，莫道漁人只為魚。", "避世垂綸不記年，官高爭得似君閑。", "傾白酒，對青山，笑指柴門待月還。", "棹警鷗飛水濺袍，影侵潭面柳垂絛。", "終日醉，絕塵勞，曾見錢塘八月濤。"]'),
('yuding-16','感禿鶖潛吟','顧夐','唐','御定全唐诗','yuding','','[]','昔日曾看瑞應圖，萬般祥瑞不如無。',32,'御定全唐詩/json/760.json','["昔日曾看瑞應圖，萬般祥瑞不如無。", "摩訶池上分明見，仔細看來是那鶘。"]'),
('yuding-17','與杜光庭','張令問','唐','御定全唐诗','yuding','','[]','試問朝中為宰相，何如林下作神仙。',32,'御定全唐詩/json/760.json','["試問朝中為宰相，何如林下作神仙。", "一壺美酒一爐藥，飽聽松風白晝眠。"]'),
('yuding-0','題黃居寀秋山圖','徐光溥','唐','御定全唐诗','yuding','','[]','天與黃筌藝奇絕，筆精回感重瞳悅。運思潛通造化工，',264,'御定全唐詩/json/761.json','["天與黃筌藝奇絕，筆精回感重瞳悅。運思潛通造化工，", "高低向背無遺勢，重巒疊嶂何孱顏。目想心存妙尤極，", "崎嶇石磴絕遊蹤，薄霧冥冥藏半峰。娑蘿掩映迷仙洞，", "屈原江上嬋娟竹，陶潛籬下芳菲菊。良宵只恐鷓鴣啼，", "颯颯白蘋欲起風，黯黯紅蕉猶帶雨。曲沼芙蓉香馥鬱，", "秋山秀兮秋江靜，江光山色相輝映。雪迸飛泉濺釣磯，", "白旻鷹逞淩風勢，薛稷鶴誇警露姿。方原畫山空巉岩，", "若教對此定妍媸，必定伏膺懷愧悚。再三展向冕旒側。", "便是移山回澗力。大李小李滅聲華，獻之愷之無顏色。", "仿佛垂綸渭水濱，吾皇睹之思良臣。依稀荷鍤傅岩野，", "才當老人星應候，願與南山俱獻壽。微臣稽首貢長歌，"]'),
('yuding-1','同劉侍郎詠筍','徐光溥','唐','御定全唐诗','yuding','','[]','迸出班犀數十株，更添幽景向蓬壺。',32,'御定全唐詩/json/761.json','["迸出班犀數十株，更添幽景向蓬壺。", "出來似有淩雲勢，用作丹梯得也無。"]'),
('yuding-2','貫休應夢羅漢畫歌','歐陽炯','唐','御定全唐诗','yuding','','[]','西嶽高僧名貫休，孤情峭拔淩清秋。天教水墨畫羅漢，',230,'御定全唐詩/json/761.json','["西嶽高僧名貫休，孤情峭拔淩清秋。天教水墨畫羅漢，", "忽然夢裏見真儀，脫下袈裟點神筆。高握節腕當空擲，", "怪石安拂嵌複枯，真僧列坐連跏趺。形如瘦鶴精神健，", "看經弟子擬聞聲，瞌睡山童疑有夢。不知夏臘幾多年，", "案前臥象低垂鼻，崖畔戲猿斜展臂。芭蕉花裏刷輕紅，", "繩開梵夾兩三片，線補衲衣千萬行。林間亂葉紛紛墮，", "休公休公逸藝無人加，聲譽喧喧遍海涯。五七字句一千首，", "若將書畫比休公，只恐當時浪生死。", "休公休公始自江南來入秦，於今到蜀無交親。", "詩名畫手皆奇絕，覷你凡人爭是人。瓦棺寺裏維摩詰，"]'),
('yuding-3','題景煥畫應天寺壁天王歌','歐陽炯','唐','御定全唐诗','yuding','','[]','錦城東北黃金地，故跡何人興此寺。白眉長老重名公，',315,'御定全唐詩/json/761.json','["錦城東北黃金地，故跡何人興此寺。白眉長老重名公，", "鬼神怪異滿壁走，當簷颯颯生秋光。我聞天王分理四天下，", "毗沙大像何光輝，手擎巨塔淩雲飛。地神對出寶瓶子，", "張僧繇是有神人，吳道子稱無敵者。奇哉妙手傳孫公，", "寶冠動總生威容，趨蹌左右來傾恭。臂橫鷹爪尖纖利，", "蟒蛇拖得渾身墮，精魅搦來雙眼空。當時此藝實難有，", "後人見者皆心驚，盡為名公不敢爭。誰知未滿三十載，", "曾持象簡累為官，又有蛇珠常在握。昔年長老遇奇蹤，", "逡巡隊仗何顛逸，散漫奇形皆湧出。交加器械滿虛空，", "腕頭獅子咬金甲，腳底夜叉擊絡鞮。馬頭壯健多筋節，", "眉粗眼豎發如錐，怪異令人不可知。科頭巨卒欲生鬼，", "如何請得二山人，下筆咸成千古事。君不見明皇天寶年，", "後來畫品列名賢，唯此二人堪比肩。人間是物皆求得，"]'),
('yuding-4','漁父歌二首','歐陽炯','唐','御定全唐诗','yuding','','[]','擺脫塵機上釣船，免教榮辱有流年。無系絆，沒愁煎，',48,'御定全唐詩/json/761.json','["擺脫塵機上釣船，免教榮辱有流年。無系絆，沒愁煎，", "風浩寒溪照膽明，小君山上玉蟾生。荷露墜，翠煙輕，"]'),
('yuding-5','大遊仙詩','歐陽炯','唐','御定全唐诗','yuding','','[]','赤城霞起武陵春，桐柏先生解守真。白石橋高曾縱步，',40,'御定全唐詩/json/761.json','["赤城霞起武陵春，桐柏先生解守真。白石橋高曾縱步，", "自領蓬萊都水監，只憂滄海變成塵。"]'),
('yuding-6','楊柳枝','歐陽炯','唐','御定全唐诗','yuding','','[]','軟碧搖煙似送人，映花時把翠蛾嚬。',32,'御定全唐詩/json/761.json','["軟碧搖煙似送人，映花時把翠蛾嚬。", "青青自是風流主，慢颯金絲待洛神。"]'),
('yuding-7','句','歐陽炯','唐','御定全唐诗','yuding','','[]','古人重到今人愛，萬局都無一局同。（《賦棋》，',22,'御定全唐詩/json/761.json','["古人重到今人愛，萬局都無一局同。（《賦棋》，"]'),
('yuding-8','感懷詩','劉義度','唐','御定全唐诗','yuding','','[]','昨日方髽髻，如今滿頷髯。紫閣無心戀，青山有意潛。',24,'御定全唐詩/json/761.json','["昨日方髽髻，如今滿頷髯。紫閣無心戀，青山有意潛。"]'),
('yuding-9','同徐學士詠筍','劉羲叟','唐','御定全唐诗','yuding','','[]','徐徐出土非人種，枝葉難投日月壺。',32,'御定全唐詩/json/761.json','["徐徐出土非人種，枝葉難投日月壺。", "為是因緣生此地，從他長養譬如無。"]'),
('yuding-10','複留侯從效問南漢劉岩改名龑字音義','詹敦仁','唐','御定全唐诗','yuding','','[]','伏羲初畫卦，蒼氏乃制字。點畫有偏旁，陰陽貴協比。',265,'御定全唐詩/json/761.json','["伏羲初畫卦，蒼氏乃制字。點畫有偏旁，陰陽貴協比。", "古者不嫌名，周公始稱諱。始諱猶未酷，後習轉多忌。", "或援他代易，或變文回避。濫觴久滋蔓，傷心日益熾。", "孫休命子名，吳國尊王意。𩅦莔𩅔𧟨僻，h4昷h7h8異。", "梁複踵已非，時亦跡舊事。h5傑自其一，蜀闖是其二。", "鄙哉化䁈名，陋矣hAha義。大唐有天下，武后擁神器。", "私制迄無取，古音實相類。hBhChb囝星，hDhd厓he埊。", "缶圀及曌hE，作史難詳備。唐祚值傾危，劉龑懷僭偽。", "籲嗟毒蛟輩，睥睨飛龍位。龑岩雖同音，形體殊乖致。", "廢學愧未弘，來問辱不棄。奇字難雄博，摛文伏韓智。", "因誦鄙所聞，敢布諸下吏。"]'),
('yuding-11','柳堤詩','詹敦仁','唐','御定全唐诗','yuding','','[]','種稻三十頃，種柳百餘株。稻可供饘粥，柳可爨庖廚。',48,'御定全唐詩/json/761.json','["種稻三十頃，種柳百餘株。稻可供饘粥，柳可爨庖廚。", "息耒柳陰下，讀書稻田隅。以樂堯舜道，同是耕莘夫。"]'),
('yuding-12','勸王氏入貢，寵予以官，作辭命篇','詹敦仁','唐','御定全唐诗','yuding','','[]','爭霸圖王事總非，中原失統可傷悲。往來賓主如郵傳，',40,'御定全唐詩/json/761.json','["爭霸圖王事總非，中原失統可傷悲。往來賓主如郵傳，", "江山有待早歸去，好向鷦林擇一枝。"]'),
('yuding-13','餘遷泉山城，留侯招遊郡圃作此','詹敦仁','唐','御定全唐诗','yuding','','[]','當年巧匠制茅亭，台館翬飛匝郡城。萬灶貔貅戈甲散，',40,'御定全唐詩/json/761.json','["當年巧匠制茅亭，台館翬飛匝郡城。萬灶貔貅戈甲散，", "試問亭前花與柳，幾番衰謝幾番榮。"]'),
('yuding-14','留侯受南唐節度使知郡事，辟予為屬，以詩謝之','詹敦仁','唐','御定全唐诗','yuding','','[]','晉江江畔趁春風，耕破雲山幾萬重。',32,'御定全唐詩/json/761.json','["晉江江畔趁春風，耕破雲山幾萬重。", "兩足一犁無外事，使君何啻五侯封。"]'),
('yuding-15','遣子訪劉乙','詹敦仁','唐','御定全唐诗','yuding','','[]','掃石耕山舊子真，布衣草履自隨身。',32,'御定全唐詩/json/761.json','["掃石耕山舊子真，布衣草履自隨身。", "石崖壁立題詩處，知是當年鳳閣人。"]'),
('yuding-16','永嘉亂，衣冠南渡，流落南泉，作憶昔吟','詹琲','唐','御定全唐诗','yuding','','[]','憶昔永嘉際，中原板蕩年。衣冠墜塗炭，輿輅染腥膻。',48,'御定全唐詩/json/761.json','["憶昔永嘉際，中原板蕩年。衣冠墜塗炭，輿輅染腥膻。", "國勢多危厄，宗人苦播遷。南來頻灑淚，渴驥每思泉。"]'),
('yuding-17','癸卯閩亂，從弟監察禦史敬凝迎仕別作','詹琲','唐','御定全唐诗','yuding','','[]','一別幾經春，棲遲晉水濱。鶺鴒長在念，鴻雁忽來賓。',48,'御定全唐詩/json/761.json','["一別幾經春，棲遲晉水濱。鶺鴒長在念，鴻雁忽來賓。", "五鬥嫌腰折，朋山刺眼新。善辭如複我，四海五湖身。"]'),
('yuding-18','追和秦隱君辭薦之韻，上陳侯乞歸鳳山','詹琲','唐','御定全唐诗','yuding','','[]','誰言悅口是甘肥，獨酌鵝兒啖翠微。蠅利薄於青紙扇，',40,'御定全唐詩/json/761.json','["誰言悅口是甘肥，獨酌鵝兒啖翠微。蠅利薄於青紙扇，", "擊壤太平朝野客，鳳山深處□生輝。"]'),
('yuding-19','雲','幸夤遜','唐','御定全唐诗','yuding','','[]','因登巨石知來處，勃勃元生綠蘚痕。靜即等閒藏草木，',40,'御定全唐詩/json/761.json','["因登巨石知來處，勃勃元生綠蘚痕。靜即等閒藏草木，", "不獨朝朝在巫峽，楚王何事謾勞魂。"]'),
('yuding-20','句','幸夤遜','唐','御定全唐诗','yuding','','[]','苦教作鎮居中國，爭得泥金在泰山。（《岷山》，',107,'御定全唐詩/json/761.json','["苦教作鎮居中國，爭得泥金在泰山。（《岷山》，", "才聞暖律先偷眼，既待和風始展眉。", "蒙君知重惠瓊實，薄起金刀釘玉深。", "嚼處春冰敲齒冷，咽時雪液沃心寒。（《梨》，", "深妝玉瓦平無壟，亂拂蘆花細有聲。", "日回禽影穿疏木，風遞猿聲入小樓。"]'),
('yuding-21','詩','丁元和','唐','御定全唐诗','yuding','','[]','九重天子人中貴，五等諸侯閫外尊。',32,'御定全唐詩/json/761.json','["九重天子人中貴，五等諸侯閫外尊。", "爭似布衣雲水客，不將名字掛乾坤。"]'),
('yuding-22','詠蜀都城上芙蓉花','張立','唐','御定全唐诗','yuding','','[]','四十裏城花發時，錦囊高下照坤維。',32,'御定全唐詩/json/761.json','["四十裏城花發時，錦囊高下照坤維。", "雖妝蜀國三秋色，難入豳風七月詩。"]'),
('yuding-23','又詠','張立','唐','御定全唐诗','yuding','','[]','去年今日到城都，城上芙蓉錦繡舒。',32,'御定全唐詩/json/761.json','["去年今日到城都，城上芙蓉錦繡舒。", "今日重來舊遊處，此花憔悴不如初。"]'),
('yuding-24','句','張立','唐','御定全唐诗','yuding','','[]','朝廷不用憂巴蜀，稱霸何曾是蜀人。（《初唐明宗徙蜀',31,'御定全唐詩/json/761.json','["朝廷不用憂巴蜀，稱霸何曾是蜀人。（《初唐明宗徙蜀", "豪傑入洛賦》）"]'),
('yuding-0','括蒼山','劉昭禹','唐','御定全唐诗','yuding','','[]','盡日行方半，諸山直下看。白雲隨步起，危徑極天盤。',48,'御定全唐詩/json/762.json','["盡日行方半，諸山直下看。白雲隨步起，危徑極天盤。", "瀑頂橋形小，溪邊店影寒。往來空太息，玄鬢改非難。"]'),
('yuding-1','憶天臺山','劉昭禹','唐','御定全唐诗','yuding','','[]','常記遊靈境，道人情不低。岩房容偃息，天路許相攜。',48,'御定全唐詩/json/762.json','["常記遊靈境，道人情不低。岩房容偃息，天路許相攜。", "霞散曙峰外，虹生涼瀑西。何當塵役了，重去聽猿啼。"]'),
('yuding-2','冬日暮國清寺留題','劉昭禹','唐','御定全唐诗','yuding','','[]','天臺山下寺，冬暮景如屏。樹密風長在，年深像有靈。',48,'御定全唐詩/json/762.json','["天臺山下寺，冬暮景如屏。樹密風長在，年深像有靈。", "高鐘疑到月，遠燒欲連星。因共真僧話，心中萬慮寧。"]'),
('yuding-3','靈溪觀','劉昭禹','唐','御定全唐诗','yuding','','[]','鼇海西邊地，宵吟景象寬。雲開孤月上，瀑噴一山寒。',48,'御定全唐詩/json/762.json','["鼇海西邊地，宵吟景象寬。雲開孤月上，瀑噴一山寒。", "人異發常綠，草靈秋不幹。無由此棲息，魂夢在長安。"]'),
('yuding-4','懷華山隱者','劉昭禹','唐','御定全唐诗','yuding','','[]','先生入太華，杳杳絕良音。秋夢有時見，孤雲無處尋。',48,'御定全唐詩/json/762.json','["先生入太華，杳杳絕良音。秋夢有時見，孤雲無處尋。", "神清峰頂立，衣冷瀑邊吟。應笑幹名者，六街塵土深。"]'),
('yuding-5','贈惠律大師','劉昭禹','唐','御定全唐诗','yuding','','[]','秋是憶山日，禪窗露灑餘。幾懸華頂夢，應寄沃洲書。',48,'御定全唐詩/json/762.json','["秋是憶山日，禪窗露灑餘。幾懸華頂夢，應寄沃洲書。", "風月資吟筆，杉篁籠靜居。滿城誰不重，見著紫衣初。"]'),
('yuding-6','經費冠卿舊隱','劉昭禹','唐','御定全唐诗','yuding','','[]','節高終不起，死戀九華山。聖主情何切，孤雲性本閑。',48,'御定全唐詩/json/762.json','["節高終不起，死戀九華山。聖主情何切，孤雲性本閑。", "名傳中國外，墳在亂松間。依約曾棲處，斜陽鳥自還。"]'),
('yuding-7','聞蟬','劉昭禹','唐','御定全唐诗','yuding','','[]','一雨一番晴，山林冷落青。莫侵殘日噪，正在異鄉聽。',48,'御定全唐詩/json/762.json','["一雨一番晴，山林冷落青。莫侵殘日噪，正在異鄉聽。", "孤館宿漳浦，扁舟離洞庭。年年當此際，那免鬢凋零。"]'),
('yuding-8','送休公歸衡','劉昭禹','唐','御定全唐诗','yuding','','[]','草履初登南嶽船，銅瓶猶貯北山泉。',32,'御定全唐詩/json/762.json','["草履初登南嶽船，銅瓶猶貯北山泉。", "衡陽舊寺春歸晚，門鎖寒潭幾樹蟬。"]'),
('yuding-9','句','劉昭禹','唐','御定全唐诗','yuding','','[]','句向夜深得，心從天外歸。',92,'御定全唐詩/json/762.json','["句向夜深得，心從天外歸。", "危樓聊側耳，高柳又鳴蟬。（《秋日登樓》，", "蘚色圍波井，花陰上竹樓。", "對面雷瞋樹，當街雨趁人。", "春光懷玉闕，萬里起初程。", "江上呼風去，天邊掛席飛。", "漆燈尋黑洞，之字上危峰。"]'),
('yuding-10','銅柱辭','李宏皋','唐','御定全唐诗','yuding','','[]','招靈鑄柱垂英烈，手執干戈征百越。誕今鑄柱庇黔黎，',48,'御定全唐詩/json/762.json','["招靈鑄柱垂英烈，手執干戈征百越。誕今鑄柱庇黔黎，", "五溪之眾不足平，我師輕躡如春冰。溪人畏威思納質，"]'),
('yuding-11','題桃源','李宏皋','唐','御定全唐诗','yuding','','[]','山翠參差水渺茫，秦人昔在楚封疆。當時避世乾坤窄，',40,'御定全唐詩/json/762.json','["山翠參差水渺茫，秦人昔在楚封疆。當時避世乾坤窄，", "他年倘遂平生志，來著霞衣侍玉皇。"]'),
('yuding-12','李皋試詩','何仲舉','唐','御定全唐诗','yuding','','[]','似玉來投獄，拋家去就枷。可憐兩片木，夾卻一枝花。',24,'御定全唐詩/json/762.json','["似玉來投獄，拋家去就枷。可憐兩片木，夾卻一枝花。"]'),
('yuding-13','句','何仲舉','唐','御定全唐诗','yuding','','[]','碧雲章句才離手，紫府神仙盡點頭。',40,'御定全唐詩/json/762.json','["碧雲章句才離手，紫府神仙盡點頭。", "樹迎高鳥歸深野，雲傍斜陽過遠山。（《秋日晚望》，"]'),
('yuding-14','耕夫謠','徐仲雅','唐','御定全唐诗','yuding','','[]','張緒逞風流，王衍事輕薄。出門逢耕夫，顏色必不樂。',48,'御定全唐詩/json/762.json','["張緒逞風流，王衍事輕薄。出門逢耕夫，顏色必不樂。", "肥膚如玉潔，力拗絲不折。半日無耕夫，此輩總餓殺。"]'),
('yuding-15','贈齊己','徐仲雅','唐','御定全唐诗','yuding','','[]','我唐有僧號齊己，未出家時宰相器。爰見夢中逢五丁，',124,'御定全唐詩/json/762.json','["我唐有僧號齊己，未出家時宰相器。爰見夢中逢五丁，", "一言悟得生死海，芙蓉吐出琉璃心。悶見有唐風雅缺，", "格何古，天工未生誰知主。混沌鑿開雞子黃，", "真宰夜來調暖律，聲聲吹出嫩青春。調何雅，", "語何奇，血潑乾坤龍戰時。祖龍跨海日方出，", "一簟松風冷如冰，長伴巢由伸腳睡。"]'),
('yuding-16','贈江處士','徐仲雅','唐','御定全唐诗','yuding','','[]','門在松陰裏，山僧幾度過。藥靈丸不大，棋妙子無多。',48,'御定全唐詩/json/762.json','["門在松陰裏，山僧幾度過。藥靈丸不大，棋妙子無多。", "薄霧籠寒徑，殘風戀綠蘿。金烏兼玉兔，年幾奈公何。"]'),
('yuding-17','東華觀偃松','徐仲雅','唐','御定全唐诗','yuding','','[]','半已化為石，有靈通碧湘。生逢堯雨露，老直漢風霜。',48,'御定全唐詩/json/762.json','["半已化為石，有靈通碧湘。生逢堯雨露，老直漢風霜。", "月滴蟾心水，龍遺腦骨香。始于毫末後，曾見幾興亡。"]'),
('yuding-18','詠棕樹','徐仲雅','唐','御定全唐诗','yuding','','[]','葉似新蒲綠，身如亂錦纏。任君千度剝，意氣自沖天。',24,'御定全唐詩/json/762.json','["葉似新蒲綠，身如亂錦纏。任君千度剝，意氣自沖天。"]'),
('yuding-19','宮詞','徐仲雅','唐','御定全唐诗','yuding','','[]','內人曉起怯春寒，輕揭珠簾看牡丹。',32,'御定全唐詩/json/762.json','["內人曉起怯春寒，輕揭珠簾看牡丹。", "一把柳絲收不得，和風搭在玉欄杆。"]'),
('yuding-20','句','徐仲雅','唐','御定全唐诗','yuding','','[]','屋面盡生人耳朵，籬頭多是老翁須。',231,'御定全唐詩/json/762.json','["屋面盡生人耳朵，籬頭多是老翁須。", "平分造化雙苞去，拆破春風兩面開。", "雲路半開千里月，洞門斜掩一天春。（《馬希範夜宴", "迎四儀夫人》）", "鑿開青帝春風國，移下姮娥夜月樓。（《馬殷明月圃》，", "珠璣影冷偏粘草，蘭麝香濃卻損花。", "山色曉堆羅黛雨，草梢春戛麝香風。", "衰蘭寂寞含愁綠，小杏妖嬈弄色紅。", "旁搜水脈湘心滿，遍揭泉根梵底通。", "水□滴殘青□瘦，石脂傾盡白雲空。", "深浦送回芳草日，急灘牽斷綠楊風。", "藕梢逆入銀塘裏，蘋跡潛來玉井中。", "敗菊籬疏臨野渡，落梅村冷隔江楓。", "剪開淨澗分苗稼，劃破漣漪下釣筒。"]'),
('yuding-21','分水嶺','伍彬','唐','御定全唐诗','yuding','','[]','前賢功及物，禹後杳難儔。不改古今色，平分南北流。',48,'御定全唐詩/json/762.json','["前賢功及物，禹後杳難儔。不改古今色，平分南北流。", "寒沖山影岸，清繞荻花洲。儘是朝宗去，潺潺早晚休。"]'),
('yuding-22','句','伍彬','唐','御定全唐诗','yuding','','[]','稚子出看莎徑沒，漁翁來報竹橋流。',32,'御定全唐詩/json/762.json','["稚子出看莎徑沒，漁翁來報竹橋流。", "蹤跡未辭鴛鷺客，夢魂先到鷓鴣村。"]'),
('yuding-23','留宿廖融山齋','楊徽之','唐','御定全唐诗','yuding','','[]','清和春尚在，歡醉日何長。谷鳥隨柯轉，庭花奪酒香。',48,'御定全唐詩/json/762.json','["清和春尚在，歡醉日何長。谷鳥隨柯轉，庭花奪酒香。", "初晴岩翠滴，向晚樹陰涼。別有堪吟處，相留宿草堂。"]'),
('yuding-24','句','楊徽之','唐','御定全唐诗','yuding','','[]','新霜染楓葉，皎月借蘆花。',24,'御定全唐詩/json/762.json','["新霜染楓葉，皎月借蘆花。", "廢宅寒塘水，荒墳宿草煙。"]'),
('yuding-25','登祝融峰','王元','唐','御定全唐诗','yuding','','[]','草疊到孤頂，身齊高鳥翔。勢疑撞翼軫，翠欲滴瀟湘。',48,'御定全唐詩/json/762.json','["草疊到孤頂，身齊高鳥翔。勢疑撞翼軫，翠欲滴瀟湘。", "雲濕幽崖滑，風梳古木香。晴空聊縱目，杳杳極窮荒。"]'),
('yuding-26','懷翁宏','王元','唐','御定全唐诗','yuding','','[]','獨夜思君切，無人知此情。滄州歸未得，華髮別來生。',48,'御定全唐詩/json/762.json','["獨夜思君切，無人知此情。滄州歸未得，華髮別來生。", "孤館木初落，高空月正明。遠書多隔歲，獨念沒前程。"]'),
('yuding-27','聽琴','王元','唐','御定全唐诗','yuding','','[]','拂塵開素匣，有客獨傷時。古調俗不樂，正聲君自知。',48,'御定全唐詩/json/762.json','["拂塵開素匣，有客獨傷時。古調俗不樂，正聲君自知。", "寒泉出澗澀，老檜倚風悲。縱有來聽者，誰堪繼子期。"]'),
('yuding-28','哭李韶','王元','唐','御定全唐诗','yuding','','[]','韶也命何奇，生前與世違。貧棲古梵刹，終著舊麻衣。',48,'御定全唐詩/json/762.json','["韶也命何奇，生前與世違。貧棲古梵刹，終著舊麻衣。", "雅句僧抄遍，孤墳客吊稀。故園今孰在，應見夢中歸。"]'),
('yuding-29','題鄧真人遺址','王元','唐','御定全唐诗','yuding','','[]','三千功滿仙升去，留得山前舊隱基。但見白雲長掩映，',40,'御定全唐詩/json/762.json','["三千功滿仙升去，留得山前舊隱基。但見白雲長掩映，", "近代無人尋異事，野泉噴月瀉秋池。"]'),
('yuding-30','句','王元','唐','御定全唐诗','yuding','','[]','伴行惟瘦鶴，尋步入深雲。',12,'御定全唐詩/json/762.json','["伴行惟瘦鶴，尋步入深雲。"]'),
('yuding-31','謝翁宏以詩百篇見示','廖融','唐','御定全唐诗','yuding','','[]','高奇一百篇，造化見工全。積思遊滄海，冥搜入洞天。',48,'御定全唐詩/json/762.json','["高奇一百篇，造化見工全。積思遊滄海，冥搜入洞天。", "神珠迷罔象，端玉匪雕鐫。休歎不得力，離騷千古傳。"]'),
('yuding-32','贈天臺逸人','廖融','唐','御定全唐诗','yuding','','[]','移檜托禪子，攜家上赤城。拂琴天籟寂，欹枕海濤生。',48,'御定全唐詩/json/762.json','["移檜托禪子，攜家上赤城。拂琴天籟寂，欹枕海濤生。", "雲白寒峰晚，鳥歌春穀晴。又聞求桂楫，載月十洲行。"]'),
('yuding-33','古檜','廖融','唐','御定全唐诗','yuding','','[]','何人見植初，老樹梵王居。山鬼暗棲托，樵夫難破除。',48,'御定全唐詩/json/762.json','["何人見植初，老樹梵王居。山鬼暗棲托，樵夫難破除。", "聲高秋漢迥，影倒月潭虛。盡日無僧倚，清風長有餘。"]'),
('yuding-34','題伍彬屋壁','廖融','唐','御定全唐诗','yuding','','[]','圓塘綠水平，魚躍紫蓴生。要路貧無力，深村老退耕。',48,'御定全唐詩/json/762.json','["圓塘綠水平，魚躍紫蓴生。要路貧無力，深村老退耕。", "犢隨原草遠，蛙傍塹籬鳴。撥棹茶川去，初逢穀雨晴。"]'),
('yuding-35','夢仙謠','廖融','唐','御定全唐诗','yuding','','[]','琪木扶疏系辟邪，麻姑夜宴紫皇家。銀河旌節搖波影，',40,'御定全唐詩/json/762.json','["琪木扶疏系辟邪，麻姑夜宴紫皇家。銀河旌節搖波影，", "星稀猶倚虹橋立，擬就張騫搭漢槎。"]'),
('yuding-36','退宮妓','廖融','唐','御定全唐诗','yuding','','[]','神仙風格本難儔，曾從前皇翠輦遊。紅躑躅繁金殿暖，',40,'御定全唐詩/json/762.json','["神仙風格本難儔，曾從前皇翠輦遊。紅躑躅繁金殿暖，", "一旦色衰歸故里，月明猶夢按梁州。"]'),
('yuding-37','句','廖融','唐','御定全唐诗','yuding','','[]','圭灶先知曉，盆池別見天，',24,'御定全唐詩/json/762.json','["圭灶先知曉，盆池別見天，", "雲穿搗藥屋，雪壓釣魚舟。"]'),
('yuding-38','贈廖融','王正己','唐','御定全唐诗','yuding','','[]','病起正當秋閣迥，酒醒迎對夜濤寒。',32,'御定全唐詩/json/762.json','["病起正當秋閣迥，酒醒迎對夜濤寒。", "爐中藥熟分僧飯，枕上琴閑借客彈。"]'),
('yuding-39','句','王正己','唐','御定全唐诗','yuding','','[]','洗盂秋澗日華動，搗藥夜坐秋氣深。',16,'御定全唐詩/json/762.json','["洗盂秋澗日華動，搗藥夜坐秋氣深。"]'),
('yuding-40','送廖融處士南游','翁宏','唐','御定全唐诗','yuding','','[]','病臥瘴雲間，莓苔漬竹關。孤吟牛渚月，老憶洞庭山。',48,'御定全唐詩/json/762.json','["病臥瘴雲間，莓苔漬竹關。孤吟牛渚月，老憶洞庭山。", "壯志潛消盡，淳風竟未還。今朝忽相遇，執手一開顏。"]'),
('yuding-41','春殘','翁宏','唐','御定全唐诗','yuding','','[]','又是春殘也，如何出翠幃。落花人獨立，微雨燕雙飛。',48,'御定全唐詩/json/762.json','["又是春殘也，如何出翠幃。落花人獨立，微雨燕雙飛。", "寓目魂將斷，經年夢亦非。那堪向愁夕，蕭颯暮蟬輝。"]'),
('yuding-42','秋殘','翁宏','唐','御定全唐诗','yuding','','[]','又是秋殘也，無聊意若何。客程江外遠，歸思夜深多。',48,'御定全唐詩/json/762.json','["又是秋殘也，無聊意若何。客程江外遠，歸思夜深多。", "峴首飛黃葉，湘湄走白波。仍聞漢都護，今歲合休戈。"]'),
('yuding-43','句','翁宏','唐','御定全唐诗','yuding','','[]','萬木橫秋裏，孤舟半夜猿。',36,'御定全唐詩/json/762.json','["萬木橫秋裏，孤舟半夜猿。", "漏光殘井甃，缺影背山椒。", "風回山火斷，潮落岸冰高。"]'),
('yuding-44','過衡山贈廖處士','張觀','唐','御定全唐诗','yuding','','[]','未向漆園為傲吏，定應明代作征君。傳家奕世無金玉，',40,'御定全唐詩/json/762.json','["未向漆園為傲吏，定應明代作征君。傳家奕世無金玉，", "到頭終為蒼生起，休戀耕煙楚水濆。"]'),
('yuding-45','竹枝詞二首','孫光憲','唐','御定全唐诗','yuding','','[]','門前春水白蘋花，岸上無人小艇斜。',64,'御定全唐詩/json/762.json','["門前春水白蘋花，岸上無人小艇斜。", "商女經過江欲暮，散拋殘食飼神鴉。", "亂繩千結絆人深，越羅萬丈表長尋。", "楊柳在身垂意緒，藕花落盡見蓮心。"]'),
('yuding-46','楊柳枝詞四首','孫光憲','唐','御定全唐诗','yuding','','[]','閶門風暖落花幹，飛遍江城雪不寒。',128,'御定全唐詩/json/762.json','["閶門風暖落花幹，飛遍江城雪不寒。", "獨有晚來臨水驛，閒人多憑赤欄幹。", "有池有榭即濛濛，浸潤翻成長養功。", "恰似有人長點檢，著行排立向春風。", "根柢雖然傍濁河，無妨終日近笙歌。", "毿毿金帶誰堪比，還共黃鶯不較多。", "萬株枯槁怨亡隋，似吊吳台各自垂。", "好是淮陰明月裏，酒樓橫笛不勝吹。"]'),
('yuding-47','採蓮','孫光憲','唐','御定全唐诗','yuding','','[]','菡萏香連十頃陂，小姑貪戲採蓮遲。',32,'御定全唐詩/json/762.json','["菡萏香連十頃陂，小姑貪戲採蓮遲。", "晚來弄水船頭濕，更脫紅裙裹鴨兒。"]'),
('yuding-48','八拍蠻','孫光憲','唐','御定全唐诗','yuding','','[]','孔雀尾拖金線長，怕人飛起入丁香。',32,'御定全唐詩/json/762.json','["孔雀尾拖金線長，怕人飛起入丁香。", "越女沙頭爭拾翠，相呼歸去背斜陽。"]'),
('yuding-49','句','孫光憲','唐','御定全唐诗','yuding','','[]','曉廚烹淡菜，春杼種橦花。',12,'御定全唐詩/json/762.json','["曉廚烹淡菜，春杼種橦花。"]'),
('yuding-50','詠蒲鞋','劉章','唐','御定全唐诗','yuding','','[]','吳江浪浸白蒲春，越女初挑一樣新。才自繡窗離玉指，',40,'御定全唐詩/json/762.json','["吳江浪浸白蒲春，越女初挑一樣新。才自繡窗離玉指，", "今日高樓鴛瓦上，不知拋擲是何人。"]'),
('yuding-51','夜坐','路洵美','唐','御定全唐诗','yuding','','[]','簾卷竹軒清，四鄰無語聲。漏從吟裏轉，月自坐來明。',48,'御定全唐詩/json/762.json','["簾卷竹軒清，四鄰無語聲。漏從吟裏轉，月自坐來明。", "草木露華濕，衣裳寒氣生。難逢知鑒者，空悅此時情。"]'),
('yuding-52','荊台道院','梁震','唐','御定全唐诗','yuding','','[]','桑田一變賦歸來，爵祿焉能浼我哉。',32,'御定全唐詩/json/762.json','["桑田一變賦歸來，爵祿焉能浼我哉。", "黃犢依然花竹外，清風萬古凜荊台。"]'),
('yuding-0','寧州道中','楊夔','唐','御定全唐诗','yuding','','[]','城枕蕭關路，胡兵日夕臨。唯憑一炬火，以慰萬人心。',48,'御定全唐詩/json/763.json','["城枕蕭關路，胡兵日夕臨。唯憑一炬火，以慰萬人心。", "春老雪猶重，沙寒草不深。如何驅匹馬，向此獨閑吟。"]'),
('yuding-1','尋九華王山人','楊夔','唐','御定全唐诗','yuding','','[]','下馬扣荊扉，相尋春半時。捫蘿盤磴險，疊石渡溪危。',48,'御定全唐詩/json/763.json','["下馬扣荊扉，相尋春半時。捫蘿盤磴險，疊石渡溪危。", "松夾莓苔徑，花藏薜荔籬。臥雲情自逸，名姓厭人知。"]'),
('yuding-2','金陵逢張喬','楊夔','唐','御定全唐诗','yuding','','[]','殊鄉會面時，辛苦兩情知。有志年空過，無媒命共奇。',48,'御定全唐詩/json/763.json','["殊鄉會面時，辛苦兩情知。有志年空過，無媒命共奇。", "吟餘春漏急，語舊酒巡遲。天爵如堪倚，休驚鬢上絲。"]'),
('yuding-3','送鄒尊師歸洞庭','楊夔','唐','御定全唐诗','yuding','','[]','眾島在波心，曾居舊隱林。近聞飛檄急，轉憶臥雲深。',48,'御定全唐詩/json/763.json','["眾島在波心，曾居舊隱林。近聞飛檄急，轉憶臥雲深。", "賣藥唯供酒，歸舟只載琴。遙知明月夜，坐石自開襟。"]'),
('yuding-4','送日東僧游天臺','楊夔','唐','御定全唐诗','yuding','','[]','一瓶離日外，行指赤城中。去自重雲下，來從積水東。',48,'御定全唐詩/json/763.json','["一瓶離日外，行指赤城中。去自重雲下，來從積水東。", "攀蘿躋石徑，掛錫憩松風。回首雞林道，唯應夢想通。"]'),
('yuding-5','題甘露寺','楊夔','唐','御定全唐诗','yuding','','[]','高殿拂雲霓，登臨想虎溪。風勻帆影眾，煙亂鳥行迷。',72,'御定全唐詩/json/763.json','["高殿拂雲霓，登臨想虎溪。風勻帆影眾，煙亂鳥行迷。", "北倚波濤闊，南窺井邑低。滿城塵漠漠，隔岸草萋萋。", "虛閣延秋磬，澄江響暮鼙。客心還惜去，新月掛樓西。"]'),
('yuding-6','送張相公出征','楊夔','唐','御定全唐诗','yuding','','[]','得意在當年，登壇秉國權。漢推周勃重，晉讓趙宣賢。',120,'御定全唐詩/json/763.json','["得意在當年，登壇秉國權。漢推周勃重，晉讓趙宣賢。", "儒德尼丘降，兵鈐太白傳。援毫飛鳳藻，發匣吼龍泉。", "曆火金難耗，零霜桂益堅。從來稱玉潔，此更讓朱妍。", "鴛鷺臻門下，貔貅擁帳前。去知清朔漠，行不費陶甄。", "獻畫符中旨，推誠契上玄。願將班固筆，書頌勒燕然。"]'),
('yuding-7','題鄭山人郊居','楊夔','唐','御定全唐诗','yuding','','[]','穀口今逢避世才，入門瀟灑絕塵埃。漁舟下釣乘風去，',40,'御定全唐詩/json/763.json','["穀口今逢避世才，入門瀟灑絕塵埃。漁舟下釣乘風去，", "竹軒相對無言語，盡日南山不欲回。"]'),
('yuding-8','題宣州延慶寺益公院','楊夔','唐','御定全唐诗','yuding','','[]','嘿坐能除萬種情，臘高兼有賜衣榮。講經舊說傾朝聽，',40,'御定全唐詩/json/763.json','["嘿坐能除萬種情，臘高兼有賜衣榮。講經舊說傾朝聽，", "長年門外無塵客，時見元戎駐旆旌。"]'),
('yuding-9','寄當陽袁皓明府','楊夔','唐','御定全唐诗','yuding','','[]','高人為縣在南京，竹繞琴堂水繞城。地古既資攜酒興，',40,'御定全唐詩/json/763.json','["高人為縣在南京，竹繞琴堂水繞城。地古既資攜酒興，", "百里甚堪留惠愛，莫教空說魯恭名。"]'),
('yuding-10','送杜郎中入茶山修貢','楊夔','唐','御定全唐诗','yuding','','[]','一道澄瀾徹底清，仙郎輕棹出重城。采蘋虛得當時稱，',40,'御定全唐詩/json/763.json','["一道澄瀾徹底清，仙郎輕棹出重城。采蘋虛得當時稱，", "謝公攜妓東山去，何似乘春奉詔行。"]'),
('yuding-11','送鄭谷','楊夔','唐','御定全唐诗','yuding','','[]','春江瀲瀲清且急，春雨濛濛密複疏。',32,'御定全唐詩/json/763.json','["春江瀲瀲清且急，春雨濛濛密複疏。", "一曲狂歌兩行淚，送君兼寄故鄉書。"]'),
('yuding-12','自敘','杜建徽','唐','御定全唐诗','yuding','','[]','中劍斫耳缺，被箭射胛過。為將須有膽，有膽即無賈。',24,'御定全唐詩/json/763.json','["中劍斫耳缺，被箭射胛過。為將須有膽，有膽即無賈。"]'),
('yuding-13','游西湖','沈韜文','唐','御定全唐诗','yuding','','[]','□□□□□□□，菰米蘋花似故鄉。',32,'御定全唐詩/json/763.json','["□□□□□□□，菰米蘋花似故鄉。", "不是不歸歸未得，好風明月一思量。"]'),
('yuding-14','贈和龍妙空禪師','王繼勳','唐','御定全唐诗','yuding','','[]','白麵山南靈慶院，茅齋道者雪峰禪。只棲雲樹兩三畝，',40,'御定全唐詩/json/763.json','["白麵山南靈慶院，茅齋道者雪峰禪。只棲雲樹兩三畝，", "誰知今日秋江畔，獨步醫王闡法筵。"]'),
('yuding-15','題建造寺','劉乙','唐','御定全唐诗','yuding','','[]','曾看畫圖勞健羨，如今親見畫猶粗。減除天半石初泐，',40,'御定全唐詩/json/763.json','["曾看畫圖勞健羨，如今親見畫猶粗。減除天半石初泐，", "我來一聽支公論，自是吾身幻得吾。"]'),
('yuding-16','句','劉乙','唐','御定全唐诗','yuding','','[]','掃石雲隨帚，耕山鳥傍人。',12,'御定全唐詩/json/763.json','["掃石雲隨帚，耕山鳥傍人。"]'),
('yuding-17','和贈和龍妙空禪師','夏鴻','唐','御定全唐诗','yuding','','[]','翰林遺跡鏡潭前，孤峭高僧此處禪。出為信門興化日，',40,'御定全唐詩/json/763.json','["翰林遺跡鏡潭前，孤峭高僧此處禪。出為信門興化日，", "道果已圓名已遂，即看千匝繞香筵。"]'),
('yuding-18','題青草湖神祠','劉山甫','唐','御定全唐诗','yuding','','[]','壞牆風雨幾經春，草色盈庭一座塵。',32,'御定全唐詩/json/763.json','["壞牆風雨幾經春，草色盈庭一座塵。", "自是神明無感應，盛衰何得卻由人。"]'),
('yuding-19','漢宗廟樂舞辭','張昭','唐','御定全唐诗','yuding','','[]','高廟明靈再啟圖，金根玉輅幸神都。巢阿丹鳳銜書命，',72,'御定全唐詩/json/763.json','["高廟明靈再啟圖，金根玉輅幸神都。巢阿丹鳳銜書命，", "薦櫻鶴館笳簫咽，酌鬯金楹劍佩趨。星俎雲罍兼魯禮，", "薦豆奉觴親玉幾，配天合祖耀璿樞。受厘飲酒皇歡洽，"]'),
('yuding-20','農家','顏仁郁','唐','御定全唐诗','yuding','','[]','夜半呼兒趁曉耕，羸牛無力漸艱行。',32,'御定全唐詩/json/763.json','["夜半呼兒趁曉耕，羸牛無力漸艱行。", "時人不識農家苦，將謂田中穀自生。"]'),
('yuding-21','山居','顏仁郁','唐','御定全唐诗','yuding','','[]','柏樹松陰覆竹齋，罷燒藥灶縱高懷。',32,'御定全唐詩/json/763.json','["柏樹松陰覆竹齋，罷燒藥灶縱高懷。", "世間應少山間景，雲繞青松水繞階。"]'),
('yuding-22','春日寓感','王延彬','唐','御定全唐诗','yuding','','[]','兩衙前後訟堂清，軟錦披袍擁鼻行。雨後綠苔侵履跡，',40,'御定全唐詩/json/763.json','["兩衙前後訟堂清，軟錦披袍擁鼻行。雨後綠苔侵履跡，", "也解為詩也為政，儂家何似謝宣城。"]'),
('yuding-23','哭徐夤','王延彬','唐','御定全唐诗','yuding','','[]','延壽溪頭歎逝波，古今人事半銷磨。',32,'御定全唐詩/json/763.json','["延壽溪頭歎逝波，古今人事半銷磨。", "昔除正字今何在，所謂人生能幾何。"]'),
('yuding-0','塞上','譚用之','唐','御定全唐诗','yuding','','[]','秋風漢北雁飛天，單騎那堪繞賀蘭。磧暗更無岩樹影，',80,'御定全唐詩/json/764.json','["秋風漢北雁飛天，單騎那堪繞賀蘭。磧暗更無岩樹影，", "早晚橫戈似飛尉，擁旄深入異田單。", "缽略城邊日欲西，遊人卻憶舊山歸。牛羊集水煙黏步，", "橫行總是男兒事，早晚重來似漢飛。"]'),
('yuding-1','贈索處士','譚用之','唐','御定全唐诗','yuding','','[]','不將桂子種諸天，長得尋君水石邊。玄豹夜寒和霧隱，',40,'御定全唐詩/json/764.json','["不將桂子種諸天，長得尋君水石邊。玄豹夜寒和霧隱，", "一度相思一惆悵，水寒煙澹落花前。"]'),
('yuding-2','別雒下一二知己','譚用之','唐','御定全唐诗','yuding','','[]','金鼎光輝照雪袍，雒陽春夢憶波濤。塵埃滿眼人情異，',40,'御定全唐詩/json/764.json','["金鼎光輝照雪袍，雒陽春夢憶波濤。塵埃滿眼人情異，", "別來無限幽求子，應笑區區味六韜。"]'),
('yuding-3','約張處士游梁','譚用之','唐','御定全唐诗','yuding','','[]','莫學區區老一經，夷門關吏舊書生。晉朝滅後無中散，',40,'御定全唐詩/json/764.json','["莫學區區老一經，夷門關吏舊書生。晉朝滅後無中散，", "好攜長策幹時去，免逐漁樵度太平。"]'),
('yuding-4','送友人歸青社','譚用之','唐','御定全唐诗','yuding','','[]','雕鶚途程在碧天，彩衣東去複何言。二千賓客舊知己，',40,'御定全唐詩/json/764.json','["雕鶚途程在碧天，彩衣東去複何言。二千賓客舊知己，", "好期聖代重相見，莫學袁生老竹軒。"]'),
('yuding-5','送丁道士歸南中','譚用之','唐','御定全唐诗','yuding','','[]','孤雲無定鶴辭巢，自負焦桐不說勞。服藥幾年期碧落，',40,'御定全唐詩/json/764.json','["孤雲無定鶴辭巢，自負焦桐不說勞。服藥幾年期碧落，", "從此人稀見蹤跡，還應選地種仙桃。"]'),
('yuding-6','月夜懷寄友人','譚用之','唐','御定全唐诗','yuding','','[]','劍氣徒勞望鬥牛，故人別後阻仙舟。殘春謾道深傾酒，',40,'御定全唐詩/json/764.json','["劍氣徒勞望鬥牛，故人別後阻仙舟。殘春謾道深傾酒，", "清風未許重攜手，幾度高吟寄水流。"]'),
('yuding-7','閒居寄陳山人','譚用之','唐','御定全唐诗','yuding','','[]','閒居何處得閒名，坐掩衡茅損性靈。破夢曉鐘聞竹寺，',40,'御定全唐詩/json/764.json','["閒居何處得閒名，坐掩衡茅損性靈。破夢曉鐘聞竹寺，", "珍重先生全太古，應看名利似浮萍。"]'),
('yuding-8','憶南中','譚用之','唐','御定全唐诗','yuding','','[]','碧江頭與白雲門，別後秋霜點鬢根。長記學禪青石寺，',40,'御定全唐詩/json/764.json','["碧江頭與白雲門，別後秋霜點鬢根。長記學禪青石寺，", "未棹扁舟重回首，采薇收橘不堪論。"]'),
('yuding-9','寄友人','譚用之','唐','御定全唐诗','yuding','','[]','病多慵引架書看，官職無才思已闌。穴鳳瑞時來卻易，',40,'御定全唐詩/json/764.json','["病多慵引架書看，官職無才思已闌。穴鳳瑞時來卻易，", "早晚煙村碧江畔，掛罾重對蓼花灘。"]'),
('yuding-10','別江上一二友生','譚用之','唐','御定全唐诗','yuding','','[]','國風千載務重華，須逐浮雲背若耶。無地可歸堪種玉，',40,'御定全唐詩/json/764.json','["國風千載務重華，須逐浮雲背若耶。無地可歸堪種玉，", "他日成都卻回首，東山看取謝鯤家。"]'),
('yuding-11','寄岐山林逢吉明府','譚用之','唐','御定全唐诗','yuding','','[]','岐山高與隴山連，制錦無私服晏眠。鸚鵡語中分百里，',40,'御定全唐詩/json/764.json','["岐山高與隴山連，制錦無私服晏眠。鸚鵡語中分百里，", "莫役生靈種楊柳，一枝枝折灞橋邊。"]'),
('yuding-12','感懷呈所知','譚用之','唐','御定全唐诗','yuding','','[]','十年流落賦歸鴻，誰傍昏衢駕燭龍。竹屋亂煙思梓澤，',40,'御定全唐詩/json/764.json','["十年流落賦歸鴻，誰傍昏衢駕燭龍。竹屋亂煙思梓澤，", "早晚休歌白石爛，放教歸去臥群峰。"]'),
('yuding-13','江上聞笛','譚用之','唐','御定全唐诗','yuding','','[]','誰為梅花怨未平，一聲高喚百龍驚。風當閶闔庭初靜，',40,'御定全唐詩/json/764.json','["誰為梅花怨未平，一聲高喚百龍驚。風當閶闔庭初靜，", "臨流不欲殷勤聽，芳草王孫舊有情。"]'),
('yuding-14','寄孟進士','譚用之','唐','御定全唐诗','yuding','','[]','依舊池邊草色芳，故人何處憶山陽。書回科鬥江帆暮，',40,'御定全唐詩/json/764.json','["依舊池邊草色芳，故人何處憶山陽。書回科鬥江帆暮，", "別來南國知誰在，空對襜褕一斷腸。"]'),
('yuding-15','寄閻記室','譚用之','唐','御定全唐诗','yuding','','[]','織錦歌成下翠微，豈勞西去問支機。未開水府珠先見，',40,'御定全唐詩/json/764.json','["織錦歌成下翠微，豈勞西去問支機。未開水府珠先見，", "相逢半是雲霄客，應笑歌牛一布衣。"]'),
('yuding-16','幽居寄李秘書','譚用之','唐','御定全唐诗','yuding','','[]','幾年帝裏阻煙波，敢向明時叩角歌。看盡好花春臥穩，',40,'御定全唐詩/json/764.json','["幾年帝裏阻煙波，敢向明時叩角歌。看盡好花春臥穩，", "昨夜前溪有龍鬥，石橋風雨少人過。"]'),
('yuding-17','貽釣魚李處士','譚用之','唐','御定全唐诗','yuding','','[]','罷吟鸚鵡草芊芊，又泛鴛鴦水上天。一棹冷涵楊柳雨，',40,'御定全唐詩/json/764.json','["罷吟鸚鵡草芊芊，又泛鴛鴦水上天。一棹冷涵楊柳雨，", "何處邈將歸畫府，數莖紅蓼一漁船。"]'),
('yuding-18','河橋樓賦得群公夜宴','譚用之','唐','御定全唐诗','yuding','','[]','芙蓉簾幕扇秋紅，蠻府新郎夜宴同。滿座馬融吹笛月，',40,'御定全唐詩/json/764.json','["芙蓉簾幕扇秋紅，蠻府新郎夜宴同。滿座馬融吹笛月，", "深荷良宵慰憔悴，德星池館在江東。"]'),
('yuding-19','寄左先輩','譚用之','唐','御定全唐诗','yuding','','[]','狂歌白鹿上青天，何似蘭塘釣紫煙。萬卷祖龍坑外物，',40,'御定全唐詩/json/764.json','["狂歌白鹿上青天，何似蘭塘釣紫煙。萬卷祖龍坑外物，", "學取青蓮李居士，一生杯酒在神仙。"]'),
('yuding-20','貽費道人','譚用之','唐','御定全唐诗','yuding','','[]','誰如南浦傲煙霞，白葛衣輕稱帽紗。碧玉蜉蝣迎客酒，',40,'御定全唐詩/json/764.json','["誰如南浦傲煙霞，白葛衣輕稱帽紗。碧玉蜉蝣迎客酒，", "他日鳳書何處覓，武陵煙樹半桃花。"]'),
('yuding-21','寄許下前管記王侍禦','譚用之','唐','御定全唐诗','yuding','','[]','昔年南去得娛賓，頓遜杯前共好春。蟻泛羽觴蠻酒膩，',40,'御定全唐詩/json/764.json','["昔年南去得娛賓，頓遜杯前共好春。蟻泛羽觴蠻酒膩，", "別後青青鄭南陌，不知風月屬何人。"]'),
('yuding-22','秋日圃田送人隨計','譚用之','唐','御定全唐诗','yuding','','[]','僕射陂前是傳郵，去程雕鶚弄高秋。吟拋芍藥裁詩圃，',40,'御定全唐詩/json/764.json','["僕射陂前是傳郵，去程雕鶚弄高秋。吟拋芍藥裁詩圃，", "明年二月仙山下，莫遣桃花逐水流。"]'),
('yuding-23','途次宿友人別墅','譚用之','唐','御定全唐诗','yuding','','[]','千里崤函一夢勞，豈知雲館共蕭騷。半簾綠透偎寒竹，',40,'御定全唐詩/json/764.json','["千里崤函一夢勞，豈知雲館共蕭騷。半簾綠透偎寒竹，", "感君岩下閑招隱，細縷金盤鱠錯刀。"]'),
('yuding-24','春日期巢湖舊事','譚用之','唐','御定全唐诗','yuding','','[]','暖掠紅香燕燕飛，五雲仙佩曉相攜。花開鸚鵡韋郎曲，',40,'御定全唐詩/json/764.json','["暖掠紅香燕燕飛，五雲仙佩曉相攜。花開鸚鵡韋郎曲，", "不知多少開元事，露泣春叢向日低。"]'),
('yuding-25','再游韋曲山寺','譚用之','唐','御定全唐诗','yuding','','[]','鵲岩煙斷玉巢欹，罨畫春塘太白低。馬踏翠開垂柳寺，',40,'御定全唐詩/json/764.json','["鵲岩煙斷玉巢欹，罨畫春塘太白低。馬踏翠開垂柳寺，", "碧吐紅芳舊行處，豈堪回首草萋萋。"]'),
('yuding-26','寄徐拾遺','譚用之','唐','御定全唐诗','yuding','','[]','長竿一系白龍吟，誰和騶虞發素琴。野客碧雲魂易斷，',40,'御定全唐詩/json/764.json','["長竿一系白龍吟，誰和騶虞發素琴。野客碧雲魂易斷，", "好向明庭拾遺事，莫教玄豹老泉林。"]'),
('yuding-27','秋宿湘江遇雨','譚用之','唐','御定全唐诗','yuding','','[]','江上陰雲鎖夢魂，江邊深夜舞劉琨。秋風萬里芙蓉國，',40,'御定全唐詩/json/764.json','["江上陰雲鎖夢魂，江邊深夜舞劉琨。秋風萬里芙蓉國，", "漁人相見不相問，長笛一聲歸島門。"]'),
('yuding-28','貽南康陳處士陶','譚用之','唐','御定全唐诗','yuding','','[]','白玉堆邊蔣徑橫，空涵二十四灘聲。老無征戰軒轅國，',40,'御定全唐詩/json/764.json','["白玉堆邊蔣徑橫，空涵二十四灘聲。老無征戰軒轅國，", "時人莫笑非經濟，還待中原致太平。"]'),
('yuding-29','渭城春晚','譚用之','唐','御定全唐诗','yuding','','[]','秦樹朦朧春色微，香風煙暖樹依依。邊城夜靜月初上，',40,'御定全唐詩/json/764.json','["秦樹朦朧春色微，香風煙暖樹依依。邊城夜靜月初上，", "釣鄉千里斷消息，滿目碧雲空自飛。"]'),
('yuding-30','山中春晚寄賈員外','譚用之','唐','御定全唐诗','yuding','','[]','不隨黃鶴起煙波，應笑無成返薜蘿。看盡好花春臥穩，',40,'御定全唐詩/json/764.json','["不隨黃鶴起煙波，應笑無成返薜蘿。看盡好花春臥穩，", "珍重仙曹舊知己，往來星騎一相過。"]'),
('yuding-31','貽淨居寺新及第','譚用之','唐','御定全唐诗','yuding','','[]','秋池雲下白蓮香，池上吟仙寄竹房。閑頌國風文字古，',40,'御定全唐詩/json/764.json','["秋池雲下白蓮香，池上吟仙寄竹房。閑頌國風文字古，", "此境空門不曾有，從頭好語與醫王。"]'),
('yuding-32','江邊秋夕','譚用之','唐','御定全唐诗','yuding','','[]','千鐘紫酒薦菖蒲，松島蘭舟瀲灩居。曲內橘香江客笛，',40,'御定全唐詩/json/764.json','["千鐘紫酒薦菖蒲，松島蘭舟瀲灩居。曲內橘香江客笛，", "七色花虯一聲鶴，幾時乘興上清虛。"]'),
('yuding-33','送僧中孚南歸','譚用之','唐','御定全唐诗','yuding','','[]','琵琶峽口月溪邊，玉乳頭佗憶舊川。一錫冷涵蘭徑路，',40,'御定全唐詩/json/764.json','["琵琶峽口月溪邊，玉乳頭佗憶舊川。一錫冷涵蘭徑路，", "莫道翩翩去如夢，本來吟鳥在林泉。"]'),
('yuding-34','江館秋夕','譚用之','唐','御定全唐诗','yuding','','[]','耿耿銀河雁半橫，夢欹金碧轆轤輕。滿窗謝練江風白，',40,'御定全唐詩/json/764.json','["耿耿銀河雁半橫，夢欹金碧轆轤輕。滿窗謝練江風白，", "誰人更唱陽關曲，牢落煙霞夢不成。"]'),
('yuding-35','秋夜同友人話舊','譚用之','唐','御定全唐诗','yuding','','[]','露下銀河雁度頻，囊中壚火幾時真。數莖白髮生浮世，',40,'御定全唐詩/json/764.json','["露下銀河雁度頻，囊中壚火幾時真。數莖白髮生浮世，", "何當歸去重攜手，依舊紅霞作近鄰。"]'),
('yuding-36','古劍','譚用之','唐','御定全唐诗','yuding','','[]','鑄時天匠待英豪，紫焰寒星匣倍牢。三尺何年拂塵土，',40,'御定全唐詩/json/764.json','["鑄時天匠待英豪，紫焰寒星匣倍牢。三尺何年拂塵土，", "惜是真龍懶拋擲，夜來沖鬥氣何高。"]'),
('yuding-37','寄王侍禦','譚用之','唐','御定全唐诗','yuding','','[]','鳥盡弓藏良可哀，誰知歸釣子陵台。煉多不信黃金耗，',40,'御定全唐詩/json/764.json','["鳥盡弓藏良可哀，誰知歸釣子陵台。煉多不信黃金耗，", "燕歌別後休惆悵，黍已成畦菊已開。"]'),
('yuding-38','別何處士陵俊老','譚用之','唐','御定全唐诗','yuding','','[]','三皇上人春夢醒，東侯老大麒麟生。洞連龍穴全山冷，',40,'御定全唐詩/json/764.json','["三皇上人春夢醒，東侯老大麒麟生。洞連龍穴全山冷，", "誰人為向青編上，直傍巢由寫一名。"]'),
('yuding-39','句','譚用之','唐','御定全唐诗','yuding','','[]','流水物情諳世態，落花春夢厭塵勞。',70,'御定全唐詩/json/764.json','["流水物情諳世態，落花春夢厭塵勞。", "織檻錦紋苔乍結，墮書花印菊初殘。", "光陰老去無成事，富貴不來爭奈何。", "眠雲無限好知己，應笑不歸花滿樽。（《入關》，"]'),
('yuding-0','泊姑熟口','王周','唐','御定全唐诗','yuding','','[]','杳杳金陵路，難禁欲斷魂。雨晴山有態，風晚水無痕。',48,'御定全唐詩/json/765.json','["杳杳金陵路，難禁欲斷魂。雨晴山有態，風晚水無痕。", "遠色千檣岸，愁聲一笛村。如何遣懷抱，詩畢自開尊。"]'),
('yuding-1','湖口縣','王周','唐','御定全唐诗','yuding','','[]','柴桑分邑載圖經，屈曲山光展畫屏。',32,'御定全唐詩/json/765.json','["柴桑分邑載圖經，屈曲山光展畫屏。", "最是蘆洲東北望，人家殘照隔煙汀。"]'),
('yuding-2','嶽州眾湖阻風二首','王周','唐','御定全唐诗','yuding','','[]','眾湖湖口系蘭船，睡起中餐又卻眠。',64,'御定全唐詩/json/765.json','["眾湖湖口系蘭船，睡起中餐又卻眠。", "風伯如何解回怒，數宵檣倚碧蘆煙。", "偶系扁舟枕綠莎，旋移深處避驚波。", "曉來閑共漁人話，此去巴陵路幾多。"]'),
('yuding-3','問春','王周','唐','御定全唐诗','yuding','','[]','遊絲垂幄雨依依，枝上紅香片片飛。',32,'御定全唐詩/json/765.json','["遊絲垂幄雨依依，枝上紅香片片飛。", "把酒問春因底意，為誰來後為誰歸。"]'),
('yuding-4','春答','王周','唐','御定全唐诗','yuding','','[]','花枝千萬趁春開，三月瓓珊即自回。',32,'御定全唐詩/json/765.json','["花枝千萬趁春開，三月瓓珊即自回。", "剩向東園種桃李，明年依舊為君來。"]'),
('yuding-5','西塞山二首','王周','唐','御定全唐诗','yuding','','[]','西塞名山立翠屏，濃嵐橫入半江青。',64,'御定全唐詩/json/765.json','["西塞名山立翠屏，濃嵐橫入半江青。", "千尋鐵鎖無由問，石壁空存道者形。", "匹婦頑然莫問因，匹夫何去望千春。", "翻思岵屺傳詩什，舉世曾無化石人。"]'),
('yuding-6','使風','王周','唐','御定全唐诗','yuding','','[]','風起即千里，風回翻問津。沈思宦游者，何啻使風人。',24,'御定全唐詩/json/765.json','["風起即千里，風回翻問津。沈思宦游者，何啻使風人。"]'),
('yuding-7','石首山','王周','唐','御定全唐诗','yuding','','[]','首出崔嵬占上游，迥存濃翠向荊州。',32,'御定全唐詩/json/765.json','["首出崔嵬占上游，迥存濃翠向荊州。", "空聞別有回山力，卻見長江曲尺流。"]'),
('yuding-8','金口步','王周','唐','御定全唐诗','yuding','','[]','兩山鬥咽喉，群石矗牙齒。行客無限愁，橫吞一江水。',24,'御定全唐詩/json/765.json','["兩山鬥咽喉，群石矗牙齒。行客無限愁，橫吞一江水。"]'),
('yuding-9','采桑女二首','王周','唐','御定全唐诗','yuding','','[]','渡水采桑歸，蠶老催上機。紮紮得盈尺，輕素何人衣。',48,'御定全唐詩/json/765.json','["渡水采桑歸，蠶老催上機。紮紮得盈尺，輕素何人衣。", "采桑知蠶饑，投梭惜夜遲。誰誇羅綺叢，新畫學月眉。"]'),
('yuding-10','渡溪','王周','唐','御定全唐诗','yuding','','[]','渡溪溪水急，水濺羅衣濕。日暮猶未歸，盈盈水邊立。',24,'御定全唐詩/json/765.json','["渡溪溪水急，水濺羅衣濕。日暮猶未歸，盈盈水邊立。"]'),
('yuding-11','落葉','王周','唐','御定全唐诗','yuding','','[]','素律鑠欲脆，青女妒複稀。月冷天風吹，葉葉幹紅飛。',24,'御定全唐詩/json/765.json','["素律鑠欲脆，青女妒複稀。月冷天風吹，葉葉幹紅飛。"]'),
('yuding-12','宿疏陂驛','王周','唐','御定全唐诗','yuding','','[]','秋染棠梨葉半紅，荊州東望草平空。',32,'御定全唐詩/json/765.json','["秋染棠梨葉半紅，荊州東望草平空。", "誰知孤宦天涯意，微雨蕭蕭古驛中。"]'),
('yuding-13','再經秭歸二首','王周','唐','御定全唐诗','yuding','','[]','總角曾隨上峽船，尋思如夢可淒然。',64,'御定全唐詩/json/765.json','["總角曾隨上峽船，尋思如夢可淒然。", "夜來孤館重來宿，枕底灘聲似舊年。", "秭歸城邑昔曾過，舊識無人奈老何。", "獨有淒清難改處，月明聞唱竹枝歌。"]'),
('yuding-14','霞','王周','唐','御定全唐诗','yuding','','[]','拂拂生殘暉，層層如裂緋。天風剪成片，疑作仙人衣。',24,'御定全唐詩/json/765.json','["拂拂生殘暉，層層如裂緋。天風剪成片，疑作仙人衣。"]'),
('yuding-15','巫山公署壁有無名氏戲書二韻','王周','唐','御定全唐诗','yuding','','[]','南陵直上路盤盤，平地淩雲勢萬端。',32,'御定全唐詩/json/765.json','["南陵直上路盤盤，平地淩雲勢萬端。", "堪笑巴民不厭足，更嫌山少畫山看。"]'),
('yuding-16','道院','王周','唐','御定全唐诗','yuding','','[]','白日人稀到，簾垂道院深。雨苔生古壁，雪雀聚寒林。',48,'御定全唐詩/json/765.json','["白日人稀到，簾垂道院深。雨苔生古壁，雪雀聚寒林。", "忘慮憑三樂，消閒信五禽。誰知是官府，煙縷滿爐沈。"]'),
('yuding-17','會噲岑山人','王周','唐','御定全唐诗','yuding','','[]','渝州江上忽相逢，說隱西山最上峰。',32,'御定全唐詩/json/765.json','["渝州江上忽相逢，說隱西山最上峰。", "略坐移時又分別，片雲孤鶴一枝筇。"]'),
('yuding-18','巴江','王周','唐','御定全唐诗','yuding','','[]','巴江江水色，一帶濃藍碧。仙女瑟瑟衣，風梭晚來織。',24,'御定全唐詩/json/765.json','["巴江江水色，一帶濃藍碧。仙女瑟瑟衣，風梭晚來織。"]'),
('yuding-19','小園桃李始花，偶以成詠','王周','唐','御定全唐诗','yuding','','[]','桃李栽成豔格新，數枝留得小園春。',32,'御定全唐詩/json/765.json','["桃李栽成豔格新，數枝留得小園春。", "半紅半白無風雨，隨分夭容解笑人。"]'),
('yuding-20','公居','王周','唐','御定全唐诗','yuding','','[]','公居門館靜，旅寄萬州城。山共秋煙紫，霜並夜月清。',48,'御定全唐詩/json/765.json','["公居門館靜，旅寄萬州城。山共秋煙紫，霜並夜月清。", "無愁幹酒律，有句入詩評。何必須林下，方馳吏隱名。"]'),
('yuding-21','富池口','王周','唐','御定全唐诗','yuding','','[]','扁舟閑引望，望極更盤桓。山密礙江曲，雨多饒地寒。',48,'御定全唐詩/json/765.json','["扁舟閑引望，望極更盤桓。山密礙江曲，雨多饒地寒。", "短莎煙苒苒，驚浪雪漫漫。難寫愁何限，鄉關在一端。"]'),
('yuding-22','夔州病中','王周','唐','御定全唐诗','yuding','','[]','隱幾經旬疾未痊，孤燈孤驛若為眠。',32,'御定全唐詩/json/765.json','["隱幾經旬疾未痊，孤燈孤驛若為眠。", "郡樓昨夜西風急，一一更籌到枕前。"]'),
('yuding-23','題廳壁','王周','唐','御定全唐诗','yuding','','[]','永日無他念，孤清吏隱心。竹聲並雪碎，溪色共煙深。',48,'御定全唐詩/json/765.json','["永日無他念，孤清吏隱心。竹聲並雪碎，溪色共煙深。", "數息閑憑幾，緣情默寄琴。誰知同寂寞，相與結知音。"]'),
('yuding-24','過武寧縣','王周','唐','御定全唐诗','yuding','','[]','行過武甯縣，初晴物景和。岸回驚水急，山淺見天多。',48,'御定全唐詩/json/765.json','["行過武甯縣，初晴物景和。岸回驚水急，山淺見天多。", "細草濃藍潑，輕煙匹練拖。晚來何處宿，一笛起漁歌。"]'),
('yuding-25','路次覆盆驛','王周','唐','御定全唐诗','yuding','','[]','曾上青泥蜀道難，架空成路入雲寒。',32,'御定全唐詩/json/765.json','["曾上青泥蜀道難，架空成路入雲寒。", "如何卻向巴東去，三十六盤天外盤。"]'),
('yuding-26','藕池阻風，寄同行撫牧裘駕','王周','唐','御定全唐诗','yuding','','[]','船檣相望荊江中，岸蘆汀樹煙濛濛。',32,'御定全唐詩/json/765.json','["船檣相望荊江中，岸蘆汀樹煙濛濛。", "路間堤缺水如箭，未知何日生南風。"]'),
('yuding-27','無題二首','王周','唐','御定全唐诗','yuding','','[]','冰雪肌膚力不勝，落花飛絮繞風亭。',64,'御定全唐詩/json/765.json','["冰雪肌膚力不勝，落花飛絮繞風亭。", "不知何事秋千下，蹙破愁眉兩點青。", "梨花如雪已相迷，更被驚烏半夜啼。", "簾卷玉樓人寂寂，一鉤新月未沈西。"]'),
('yuding-28','泊巴東','王周','唐','御定全唐诗','yuding','','[]','偶泊巴東古縣前，宦情鄉思兩綿綿。',32,'御定全唐詩/json/765.json','["偶泊巴東古縣前，宦情鄉思兩綿綿。", "不堪蠟炬燒殘淚，雨打船窗半夜天。"]'),
('yuding-29','道中未開木杏花','王周','唐','御定全唐诗','yuding','','[]','粉英香萼一般般，無限行人立馬看。',32,'御定全唐詩/json/765.json','["粉英香萼一般般，無限行人立馬看。", "村女浴蠶桑柘綠，枉將顏色忍春寒。"]'),
('yuding-30','西山晚景','王周','唐','御定全唐诗','yuding','','[]','公局長清淡，池亭晚景中。蔗竿閑倚碧，蓮朵靜淹紅。',48,'御定全唐詩/json/765.json','["公局長清淡，池亭晚景中。蔗竿閑倚碧，蓮朵靜淹紅。", "半引彎彎月，微生飋飋風。無思複無慮，此味幾人同。"]'),
('yuding-31','自和','王周','唐','御定全唐诗','yuding','','[]','一片殘陽景，朦朧淡月中。蘭芽紆嫩紫，梨頰抹生紅。',48,'御定全唐詩/json/765.json','["一片殘陽景，朦朧淡月中。蘭芽紆嫩紫，梨頰抹生紅。", "琴阮資清格，冠簪養素風。煙霄半知足，吏隱少相同。"]'),
('yuding-32','齒落詞','王周','唐','御定全唐诗','yuding','','[]','己卯至庚辰，仲夏晦之暮。吾齒右排上，一齒脫而去。',144,'御定全唐詩/json/765.json','["己卯至庚辰，仲夏晦之暮。吾齒右排上，一齒脫而去。", "呼吸缺吾防，咀嚼欠吾助。年龠惜不返，日馭走為蠹。", "唇亡得無寒，舌在從何訴。輔車宜長依，發膚可增懼。", "不須考前古，聊且為近喻。有如雲中雨，雨散絕回顧。", "有如枝上葉，葉脫難再附。白髮非獨愁，紅顏豈私駐。", "何必鬱九回，何必牽百慮。開尊複開懷，引筆作長句。"]'),
('yuding-33','淘金磧','王周','唐','御定全唐诗','yuding','','[]','畫船晚過淘金磧，不見黃金惟見石。',32,'御定全唐詩/json/765.json','["畫船晚過淘金磧，不見黃金惟見石。", "猶恐黃金價未高，見得錙銖幾多力。"]'),
('yuding-34','施南路偶書','王周','唐','御定全唐诗','yuding','','[]','大石嶺頭梅欲發，南陵陂上雪初飛。',32,'御定全唐詩/json/765.json','["大石嶺頭梅欲發，南陵陂上雪初飛。", "苦無酒解愁成陣，又附蘭橈向秭歸。"]'),
('yuding-35','大石嶺驛梅花','王周','唐','御定全唐诗','yuding','','[]','仙中姑射接瑤姬，成陣清香擁路岐。',32,'御定全唐詩/json/765.json','["仙中姑射接瑤姬，成陣清香擁路岐。", "半出驛牆誰畫得，雪英相倚兩三枝。"]'),
('yuding-36','贈怤師','王周','唐','御定全唐诗','yuding','','[]','水中有片月，照耀嬋娟姿。庭前有孤柏，竦秀歲寒期。',108,'御定全唐詩/json/765.json','["水中有片月，照耀嬋娟姿。庭前有孤柏，竦秀歲寒期。", "堅然物莫遷，寂焉心為師。聲發響必答，形存影即隨。", "雪花安結子，雪葉寧附枝。蘭死不改香，井寒豈生澌。", "晨爐煙嫋嫋，病發霜絲絲。丈室冰凜冽，一衲雲離披。", "顧此名利場，得不慚冠綏。"]'),
('yuding-37','遊仙都觀','王周','唐','御定全唐诗','yuding','','[]','冷杉枯柏路盤空，毛髮生寒略略風。',32,'御定全唐詩/json/765.json','["冷杉枯柏路盤空，毛髮生寒略略風。", "兩漢真仙在何處，巡香行繞蕊珠宮。"]'),
('yuding-38','志峽船具詩：梢','王周','唐','御定全唐诗','yuding','','[]','制之居首尾，俾之辨斜正。首動尾聿隨，斜取正為定。',108,'御定全唐詩/json/765.json','["制之居首尾，俾之辨斜正。首動尾聿隨，斜取正為定。", "有如提吏筆，有如執時柄。有如秉師律，有如宣命令。", "守彼方與直，得其剛且勁。既能濟險難，何畏涉遼夐。", "招招俾作主，泛泛實司命。風烏愧斟酌，畫鷁空輝映。", "古人存豐規，猗歟聊引證。"]'),
('yuding-39','志峽船具詩：櫓','王周','唐','御定全唐诗','yuding','','[]','用之大曰櫓，冠乎小者楫。通津既能濟，巨浸即橫涉。',60,'御定全唐詩/json/765.json','["用之大曰櫓，冠乎小者楫。通津既能濟，巨浸即橫涉。", "身之使者頰，虎之拏者爪。魚之撥者鬣，弩之進者筴。", "此實為相須，相須航一葉。"]'),
('yuding-40','志峽船具詩：戙','王周','唐','御定全唐诗','yuding','','[]','箭飛峽中水，鋸立峽中石。峽與水為隘，水與石相擊。',132,'御定全唐詩/json/765.json','["箭飛峽中水，鋸立峽中石。峽與水為隘，水與石相擊。", "濆為生險艱，聲發甚霹靂。三老航一葉，百丈空千尺。", "蒼黃徒爾為，倏忽何可測。篙之小難制，戙之獨有力。", "猗嗟戙之為，彬彬堅且直。有如用武人，森森矗戈戟。", "有如敢言士，落落吐胸臆。拯危居坦夷，濟險免兢惕。", "志彼哲匠心，俾其來者識。"]'),
('yuding-41','志峽船具詩：百丈','王周','唐','御定全唐诗','yuding','','[]','少嘗侍先君，餘閑誦白氏。始得入峽詩，深味作詩旨。',169,'御定全唐詩/json/765.json','["少嘗侍先君，餘閑誦白氏。始得入峽詩，深味作詩旨。", "雲有萬仞山，雲有千丈水。自念坎壈時，尤多兢慎理。", "山束峽如口，水漱石如齒。孤舟行其中，薄冰猶坦履。", "孱顏屹焉立，洶湧勃然起。百丈為前牽，萬險即平砥。", "破之以筼簹，續之以麻枲。礪之堅以節，引之直如矢。", "杼軸連半空，長短隨兩涘。鐵鎖枉馳名，錦纜謾稱美。", "長繩豈能系，朽索何足擬。苟非dJ之為，胡可力行此。"]'),
('yuding-42','早春西園','王周','唐','御定全唐诗','yuding','','[]','引步攜筇竹，西園小徑通。雪欹梅蒂綠，春入杏梢紅。',48,'御定全唐詩/json/765.json','["引步攜筇竹，西園小徑通。雪欹梅蒂綠，春入杏梢紅。", "靜意崖穿溜，孤愁笛破空。如何將此景，收拾向圖中。"]'),
('yuding-43','金盤草詩','王周','唐','御定全唐诗','yuding','','[]','今春從南陵，得草名金盤。金盤有仁性，生在林一端。',180,'御定全唐詩/json/765.json','["今春從南陵，得草名金盤。金盤有仁性，生在林一端。", "根節歲一節，食之甘而酸。風俗競采掇，俾人防急難。", "巴中蛇虺毒，解之如走丸。巨葉展六出，軟幹分長竿。", "搖搖綠玉活，嫋嫋香荷寒。世雲暑酷月，鬱有神物看。", "天之產於此，意欲生民安。今之為政者，何不反此觀。", "知彼苛且猛，慎勿虐而殘。一物苟失所，萬金惟可歎。", "莫並蒿與萊，豈羨芝及蘭。勤渠護根本，栽植當庭欄。", "寄言好生者，休說神仙丹。"]'),
('yuding-44','和程刑部三首：公會亭','王周','唐','御定全唐诗','yuding','','[]','公事公言地，標名姓必臧。江山如得助，談笑若為妨。',48,'御定全唐詩/json/765.json','["公事公言地，標名姓必臧。江山如得助，談笑若為妨。", "均賦鄉原肅，詳刑郡邑康。官箴居座右，夙夜算難忘。"]'),
('yuding-45','和程刑部三首：碧鮮亭','王周','唐','御定全唐诗','yuding','','[]','飋飋籠清籟，蕭蕭鎖翠陰。向高思盡節，從直美虛心。',48,'御定全唐詩/json/765.json','["飋飋籠清籟，蕭蕭鎖翠陰。向高思盡節，從直美虛心。", "迥砌滋蒼蘚，幽窗伴素琴。公餘時引步，一徑靜中深。"]'),
('yuding-46','和程刑部三首：清漣合','王周','唐','御定全唐诗','yuding','','[]','照影翻窗綺，層紋滉額波。絲青迷岸柳，茸綠蘸汀莎。',48,'御定全唐詩/json/765.json','["照影翻窗綺，層紋滉額波。絲青迷岸柳，茸綠蘸汀莎。", "片雪翹饑鷺，孤香卷嫩荷。憑欄堪入畫，時聽竹枝歌。"]'),
('yuding-47','自喻','王周','唐','御定全唐诗','yuding','','[]','予念天之生，生本空疏器。五歲稟慈訓，憤悱讀書志。',264,'御定全唐詩/json/765.json','["予念天之生，生本空疏器。五歲稟慈訓，憤悱讀書志。", "七歲辨聲律，勤苦會詩賦。九歲執公卷，倜儻幹名意。", "乞薦鄉老書，幸會春官試。折桂愧巍峨，依蓮何氣味。", "性拙絕不佞，才短無餘地。前年會知己，薦章實非據。", "甯見民說平，空荷君恩寄。瞿唐抵巴渝，往來名攬轡。", "孤舟一水中，艱險實可畏。群操百丈牽，臨難無苟避。", "濆向江底發，水在石中沸。槌鼓稱打寬，系紉呼下緯。", "善惡胡可分，死生何足諱。騎衡與垂堂，非不知前喻。", "臨淵與履冰，非不知深慮。我今縻搢紳，善地誰人致。", "城狐與社鼠，巧佞誰從庇。奴顏與婢膝，醜直誰從媚。", "妻兒夐限越，容顏幾憔悴。致身霄漢人，呃嚱盡賢智。"]'),
('yuding-48','巫山廟','王周','唐','御定全唐诗','yuding','','[]','廟前溪水流潺潺，廟中修竹聲珊珊。',32,'御定全唐詩/json/765.json','["廟前溪水流潺潺，廟中修竹聲珊珊。", "襄王一夢杳難問，晚晴天氣歸雲閑。"]'),
('yuding-49','下瞿塘寄時同年','王周','唐','御定全唐诗','yuding','','[]','春寒天氣下瞿塘，大壤溪前柳線長。',32,'御定全唐詩/json/765.json','["春寒天氣下瞿塘，大壤溪前柳線長。", "須信孤雲似孤宦，莫將鄉思附歸艎。"]'),
('yuding-50','和杜運使巴峽地暖節物與中土異黯然有感詩三首','王周','唐','御定全唐诗','yuding','','[]','隨柳參差破綠芽，此中依約欲飛花。',96,'御定全唐詩/json/765.json','["隨柳參差破綠芽，此中依約欲飛花。", "春光是處傷離思，何況歸期未有涯。", "始看菊蕊開籬下，又見梅花寄嶺頭。", "攬轡巴西官局冷，幾憑春酒沃鄉愁。", "花品姚黃冠洛陽，巴中春早羨孤芳。", "不知別有栽培力，流詠新詩與激昂。"]'),
('yuding-51','施南太守以猿兒為寄作詩答之','王周','唐','御定全唐诗','yuding','','[]','虞人初獲酉江西，長臂難將意馬齊。',32,'御定全唐詩/json/765.json','["虞人初獲酉江西，長臂難將意馬齊。", "今日未啼頭已白，不堪深入白雲啼。"]'),
('yuding-52','巫廟','王周','唐','御定全唐诗','yuding','','[]','巴水走若箭，峽山開如屏。洶湧匹練白，崷崒濃藍青。',180,'御定全唐詩/json/765.json','["巴水走若箭，峽山開如屏。洶湧匹練白，崷崒濃藍青。", "崖空蓄雲雨，灘惡驚雷霆。神仙宅幽邃，廟貌橫杳冥。", "隱約可一夢，縹緲餘千齡。名利有所役，舟楫無暫停。", "悉窣垂肸蚃，祠禱希安寧。鴉鴉爾何物，飛飛來廟庭。", "紛紛颺寥泬，遠近隨虛舲。鐵石礪觜爪，金碧輝光翎。", "翔集托陰險，鵮啄貪膻腥。日既恃威福，歲久為精靈。", "依草與附木，誣詭殊不經。城狐與社鼠，瑣細何足聽。", "況乎人假人，心闊吞滄溟。"]'),
('yuding-0','貴游','劉兼','唐','御定全唐诗','yuding','','[]','繡衣公子宴池塘，淑景融融萬卉芳。珠翠照天春未老，',40,'御定全唐詩/json/766.json','["繡衣公子宴池塘，淑景融融萬卉芳。珠翠照天春未老，", "醉後不能離綺席，擬憑青帝系斜陽。"]'),
('yuding-1','夢歸故園','劉兼','唐','御定全唐诗','yuding','','[]','桐葉飛霜落井欄，菱花藏雪助衰顏。夜窗颯颯搖寒竹，',80,'御定全唐詩/json/766.json','["桐葉飛霜落井欄，菱花藏雪助衰顏。夜窗颯颯搖寒竹，", "覺來依舊三更月，離緒鄉心起萬端。", "舊館秋寒夜夢長，水簾疏影入回塘。宦情率爾拖魚艇，", "起來不語無人會，醉倚東軒半夕陽。"]'),
('yuding-2','蜀都春晚感懷','劉兼','唐','御定全唐诗','yuding','','[]','蜀都春色漸離披，夢斷雲空事莫追。宮闕一城荒作草，',40,'御定全唐詩/json/766.json','["蜀都春色漸離披，夢斷雲空事莫追。宮闕一城荒作草，", "可惜錦江無錦濯，海棠花下杜鵑啼。"]'),
('yuding-3','對雨','劉兼','唐','御定全唐诗','yuding','','[]','幽庭凝碧亦漣漪，簷溜聲繁聒夢歸。半岫金烏才委照，',40,'御定全唐詩/json/766.json','["幽庭凝碧亦漣漪，簷溜聲繁聒夢歸。半岫金烏才委照，", "因憶故園閑釣處，蒼苔斑駁滿漁磯。"]'),
('yuding-4','春霽','劉兼','唐','御定全唐诗','yuding','','[]','春霽江山似畫圖，醉垂鞭袂出康衢。倡狂亂打貔貅鼓，',40,'御定全唐詩/json/766.json','["春霽江山似畫圖，醉垂鞭袂出康衢。倡狂亂打貔貅鼓，", "苔錢遍地知多少，買得花枝不落無。"]'),
('yuding-5','秋夕書懷','劉兼','唐','御定全唐诗','yuding','','[]','荒僻淹留歲已深，解龜無計恨難任。守方半會蠻夷語，',80,'御定全唐詩/json/766.json','["荒僻淹留歲已深，解龜無計恨難任。守方半會蠻夷語，", "宦情總逐愁腸斷，一箸鱸魚直萬金。", "直氣從來不入時，掩關慵更釣磻溪。斯文未喪宣尼歎，", "南陽臥久無人問，薄命非才有可疑。"]'),
('yuding-6','春宵','劉兼','唐','御定全唐诗','yuding','','[]','春雲春日共朦朧，滿院梨花半夜風。宿酒未醒珠箔卷，',40,'御定全唐詩/json/766.json','["春雲春日共朦朧，滿院梨花半夜風。宿酒未醒珠箔卷，", "再取素琴聊假寐，南柯靈夢莫相通。"]'),
('yuding-7','秋夕書懷呈戎州郎中','劉兼','唐','御定全唐诗','yuding','','[]','素律初回枕簟涼，松風飄泊入華堂。譚雞寂默紗窗靜，',80,'御定全唐詩/json/766.json','["素律初回枕簟涼，松風飄泊入華堂。譚雞寂默紗窗靜，", "霜砧月笛休相引，只有離襟淚兩行。", "風送秋荷滿鼻香，竹聲敲玉近虛廊。夢回故國情方黯，", "鸞膠處處難尋覓，斷盡相思寸寸腸。"]'),
('yuding-8','晚樓寓懷','劉兼','唐','御定全唐诗','yuding','','[]','薄暮疏林宿鳥還，倚樓垂袂複憑欄。月沈江底珠輪淨，',40,'御定全唐詩/json/766.json','["薄暮疏林宿鳥還，倚樓垂袂複憑欄。月沈江底珠輪淨，", "無言獨對秋風立，擬把朝簪換釣竿。"]'),
('yuding-9','征婦怨','劉兼','唐','御定全唐诗','yuding','','[]','金閨寂寞罷妝台，玉箸闌幹界粉腮。花落掩關春欲暮，',40,'御定全唐詩/json/766.json','["金閨寂寞罷妝台，玉箸闌幹界粉腮。花落掩關春欲暮，", "曾寄錦書無限意，塞鴻何事不歸來。"]'),
('yuding-10','對鏡','劉兼','唐','御定全唐诗','yuding','','[]','青鏡重磨照白須，白須撚閑意何如。故園迢遞千山外，',40,'御定全唐詩/json/766.json','["青鏡重磨照白須，白須撚閑意何如。故園迢遞千山外，", "秋霜滿領難消釋，莫讀離騷失意書。"]'),
('yuding-11','春燕','劉兼','唐','御定全唐诗','yuding','','[]','多時窗外語呢喃，只要佳人卷繡簾。大廈已成須慶賀，',40,'御定全唐詩/json/766.json','["多時窗外語呢喃，只要佳人卷繡簾。大廈已成須慶賀，", "棲息數年情已厚，營巢爭肯傍他簷。"]'),
('yuding-12','春晚寓懷','劉兼','唐','御定全唐诗','yuding','','[]','一承兌澤蒞方州，八度春光照郡樓。好景幾將官吏醉，',40,'御定全唐詩/json/766.json','["一承兌澤蒞方州，八度春光照郡樓。好景幾將官吏醉，", "歸去杜陵池閣在，只能歡笑不能愁。"]'),
('yuding-13','中春宴游','劉兼','唐','御定全唐诗','yuding','','[]','二月風光似洞天，紅英翠萼簇芳筵。楚王雲雨迷巫峽，',40,'御定全唐詩/json/766.json','["二月風光似洞天，紅英翠萼簇芳筵。楚王雲雨迷巫峽，", "酒闌香袂初分散，笑指漁翁釣暮煙。"]'),
('yuding-14','春晚閑望','劉兼','唐','御定全唐诗','yuding','','[]','東風滿地是梨花，只把琴心殢酒家。立處晚樓橫短笛，',40,'御定全唐詩/json/766.json','["東風滿地是梨花，只把琴心殢酒家。立處晚樓橫短笛，", "歸計未成頭欲白，釣舟煙浪思無涯。"]'),
('yuding-15','秋夕書事','劉兼','唐','御定全唐诗','yuding','','[]','搖落江天萬木空，雁行斜戛塞垣風。征閨搗月離愁遠，',40,'御定全唐詩/json/766.json','["搖落江天萬木空，雁行斜戛塞垣風。征閨搗月離愁遠，", "此心曠蕩誰相會，盡在南華十卷中。"]'),
('yuding-16','蓮塘霽望','劉兼','唐','御定全唐诗','yuding','','[]','新秋菡萏發紅英，向晚風飄滿郡馨。萬疊水紋羅乍展，',40,'御定全唐詩/json/766.json','["新秋菡萏發紅英，向晚風飄滿郡馨。萬疊水紋羅乍展，", "遠岸牧童吹短笛，蓼花深處信牛行。"]'),
('yuding-17','送從弟舍人入蜀','劉兼','唐','御定全唐诗','yuding','','[]','嘉陵江畔餞行車，離袂難分十裏餘。慷慨莫誇心似鐵，',40,'御定全唐詩/json/766.json','["嘉陵江畔餞行車，離袂難分十裏餘。慷慨莫誇心似鐵，", "立馬舉鞭無限意，會稀別遠擬何如。"]'),
('yuding-18','新回車院筵上作','劉兼','唐','御定全唐诗','yuding','','[]','回車院子未回車，三載疲民詠袴襦。借寇已承英主詔，',40,'御定全唐詩/json/766.json','["回車院子未回車，三載疲民詠袴襦。借寇已承英主詔，", "因問滿筵詩酒客，錦江何處有鱸魚。"]'),
('yuding-19','寄長安鄭員外','劉兼','唐','御定全唐诗','yuding','','[]','屈指良交十四人，隙駒風燭漸為塵。當初花下三秦客，',40,'御定全唐詩/json/766.json','["屈指良交十四人，隙駒風燭漸為塵。當初花下三秦客，", "此時阻隔關山遠，月滿江樓淚滿巾。"]'),
('yuding-20','咸陽懷古','劉兼','唐','御定全唐诗','yuding','','[]','高秋咸鎬起霜風，秦漢荒陵樹葉紅。七國鬥雞方賈勇，',40,'御定全唐詩/json/766.json','["高秋咸鎬起霜風，秦漢荒陵樹葉紅。七國鬥雞方賈勇，", "立馬舉鞭遙望處，阿房遺址夕陽東。"]'),
('yuding-21','春怨','劉兼','唐','御定全唐诗','yuding','','[]','繡林紅岸落花鈿，故去新來感自然。絕塞杪春悲漢月，',40,'御定全唐詩/json/766.json','["繡林紅岸落花鈿，故去新來感自然。絕塞杪春悲漢月，", "獨倚畫屏人不會，夢魂才別戍樓邊。"]'),
('yuding-22','登樓寓望','劉兼','唐','御定全唐诗','yuding','','[]','憑高多是偶汍瀾，紅葉何堪照病顏。萬疊雲山供遠恨，',40,'御定全唐詩/json/766.json','["憑高多是偶汍瀾，紅葉何堪照病顏。萬疊雲山供遠恨，", "獨倚郡樓無限意，夕陽西去水東還。"]'),
('yuding-23','江岸獨步','劉兼','唐','御定全唐诗','yuding','','[]','醉卓寒筇傍水行，漁翁不會獨吟情。龜能顧印誰相重，',40,'御定全唐詩/json/766.json','["醉卓寒筇傍水行，漁翁不會獨吟情。龜能顧印誰相重，", "是非得喪皆閒事，休向南柯與夢爭。"]'),
('yuding-24','江樓望鄉寄內','劉兼','唐','御定全唐诗','yuding','','[]','獨上江樓望故鄉，淚襟霜笛共淒涼。雲生隴首秋雖早，',40,'御定全唐詩/json/766.json','["獨上江樓望故鄉，淚襟霜笛共淒涼。雲生隴首秋雖早，", "蜀箋都有三千幅，總寫離情寄孟光。"]'),
('yuding-25','命妓不至','劉兼','唐','御定全唐诗','yuding','','[]','琴中難挑孰憐才，獨對良宵酒數杯。蘇子黑貂將已盡，',40,'御定全唐詩/json/766.json','["琴中難挑孰憐才，獨對良宵酒數杯。蘇子黑貂將已盡，", "欹枕夢魂何處去，醉和春色入天臺。"]'),
('yuding-26','宣賜錦袍設上贈諸郡客','劉兼','唐','御定全唐诗','yuding','','[]','十月芙蓉花滿枝，天庭驛騎賜寒衣。將同玉蝶侵肌冷，',40,'御定全唐詩/json/766.json','["十月芙蓉花滿枝，天庭驛騎賜寒衣。將同玉蝶侵肌冷，", "深冬若得朝丹闕，太華峰前衣錦歸。"]'),
('yuding-27','晨雞','劉兼','唐','御定全唐诗','yuding','','[]','朱冠金距彩毛身，昧爽高聲已報晨。作瑞莫慚先貢楚，',40,'御定全唐詩/json/766.json','["朱冠金距彩毛身，昧爽高聲已報晨。作瑞莫慚先貢楚，", "此日卑棲隨飲啄，宰君驅我亦相馴。"]'),
('yuding-28','芳春','劉兼','唐','御定全唐诗','yuding','','[]','微雨微風隔畫簾，金爐檀炷冷慵添。桃花滿地春牢落，',40,'御定全唐詩/json/766.json','["微雨微風隔畫簾，金爐檀炷冷慵添。桃花滿地春牢落，", "宦情歸興休相撓，隼旆漁舟總未厭。"]'),
('yuding-29','春遊','劉兼','唐','御定全唐诗','yuding','','[]','柳成金穗草如茵，載酒尋花共賞春。',72,'御定全唐詩/json/766.json','["柳成金穗草如茵，載酒尋花共賞春。", "先入醉鄉君莫問，十年風景在三秦。", "搖搖離緒不能持，滿郡花開酒熟時。羞聽黃鶯求善友，", "聖主未容歸北闕，且將勤儉撫南夷。"]'),
('yuding-30','重陽感懷','劉兼','唐','御定全唐诗','yuding','','[]','重陽不忍上高樓，寒菊年年照暮秋。萬疊故山雲總隔，',80,'御定全唐詩/json/766.json','["重陽不忍上高樓，寒菊年年照暮秋。萬疊故山雲總隔，", "歸計未成年漸老，茱萸羞戴雪霜頭。", "載花乘酒上高山，四望秋空八極寬。蜀國江山存不得，", "獨對斜陽更惆悵，錦江東注似波瀾。"]'),
('yuding-31','宴游池館','劉兼','唐','御定全唐诗','yuding','','[]','綺筵金碧照芳菲，酒滿瑤卮水滿池。去歲南岐離郡日，',40,'御定全唐詩/json/766.json','["綺筵金碧照芳菲，酒滿瑤卮水滿池。去歲南岐離郡日，", "座客半酣言笑狎，孔融懷抱正怡怡。"]'),
('yuding-32','寄高書記','劉兼','唐','御定全唐诗','yuding','','[]','齊朝慶裔祖敖曹，麟角無雙鳳九毛。聲價五侯爭辟命，',40,'御定全唐詩/json/766.json','["齊朝慶裔祖敖曹，麟角無雙鳳九毛。聲價五侯爭辟命，", "補袞應星曾奏舉，北山南海孰為高。"]'),
('yuding-33','再見從弟舍人','劉兼','唐','御定全唐诗','yuding','','[]','屈指依稀十五年，鸞台秘閣位相懸。分飛淮甸雁行斷，',40,'御定全唐詩/json/766.json','["屈指依稀十五年，鸞台秘閣位相懸。分飛淮甸雁行斷，", "願君通理須還早，拜慶慈親几杖前。"]'),
('yuding-34','春晝醉眠','劉兼','唐','御定全唐诗','yuding','','[]','朱欄芳草綠纖纖，欹枕高堂卷畫簾。處處落花春寂寂，',40,'御定全唐詩/json/766.json','["朱欄芳草綠纖纖，欹枕高堂卷畫簾。處處落花春寂寂，", "自有卷書銷永日，霜華未用鬢邊添。"]'),
('yuding-35','中夏晝臥','劉兼','唐','御定全唐诗','yuding','','[]','寂寂無聊九夏中，傍簷依壁待清風。',32,'御定全唐詩/json/766.json','["寂寂無聊九夏中，傍簷依壁待清風。", "壯圖奇策無人問，不及南陽一臥龍。"]'),
('yuding-36','春夕寓興','劉兼','唐','御定全唐诗','yuding','','[]','忘憂何必在庭萱，是事悠悠竟可寬。酒病未能辭錦裏，',40,'御定全唐詩/json/766.json','["忘憂何必在庭萱，是事悠悠竟可寬。酒病未能辭錦裏，", "閑泥金徽度芳夕，幽泉石上自潺湲。"]'),
('yuding-37','春夜','劉兼','唐','御定全唐诗','yuding','','[]','薄薄春雲籠皓月，杏花滿地堆香雪。',32,'御定全唐詩/json/766.json','["薄薄春雲籠皓月，杏花滿地堆香雪。", "醉垂羅袂倚朱欄，小數玉仙歌未闋。"]'),
('yuding-38','訪飲妓不遇，招酒徒不至','劉兼','唐','御定全唐诗','yuding','','[]','小橋流水接平沙，何處行雲不在家。畢卓未來輕竹葉，',40,'御定全唐詩/json/766.json','["小橋流水接平沙，何處行雲不在家。畢卓未來輕竹葉，", "回首卻尋芳草路，金鞍拂柳思無涯。"]'),
('yuding-39','春宴河亭','劉兼','唐','御定全唐诗','yuding','','[]','柳擺輕絲拂嫩黃，檻前流水滿池塘。一筵金翠臨芳岸，',40,'御定全唐詩/json/766.json','["柳擺輕絲拂嫩黃，檻前流水滿池塘。一筵金翠臨芳岸，", "蠻箋象管休凝思，且放春心入醉鄉。"]'),
('yuding-40','蜀都道中','劉兼','唐','御定全唐诗','yuding','','[]','劍關雲棧亂崢嶸，得喪何由險與平。千載龜城終失守，',40,'御定全唐詩/json/766.json','["劍關雲棧亂崢嶸，得喪何由險與平。千載龜城終失守，", "李特後來多二世，納降歸擬盡公卿。"]'),
('yuding-41','萬葛樹','劉兼','唐','御定全唐诗','yuding','','[]','葉如羽蓋豈堪論，百步清陰鎖綠雲。善政已聞思召伯，',40,'御定全唐詩/json/766.json','["葉如羽蓋豈堪論，百步清陰鎖綠雲。善政已聞思召伯，", "更有歲寒霜雪操，莫將樗櫟擬相群。"]'),
('yuding-42','春夕遣懷','劉兼','唐','御定全唐诗','yuding','','[]','窮通分定莫淒涼，且放歡情入醉鄉。範蠡扁舟終去相，',40,'御定全唐詩/json/766.json','["窮通分定莫淒涼，且放歡情入醉鄉。範蠡扁舟終去相，", "休把虛名撓懷抱，九原丘隴盡侯王。"]'),
('yuding-43','西齋','劉兼','唐','御定全唐诗','yuding','','[]','西齋新竹兩三莖，也有風敲碎玉聲。',32,'御定全唐詩/json/766.json','["西齋新竹兩三莖，也有風敲碎玉聲。", "莫恨移來欄檻遠，譬如元本此間生。"]'),
('yuding-44','新蟬','劉兼','唐','御定全唐诗','yuding','','[]','齊女屏幃失舊容，侍中冠冕有芳蹤。翅翻晚鬢尋香露，',40,'御定全唐詩/json/766.json','["齊女屏幃失舊容，侍中冠冕有芳蹤。翅翻晚鬢尋香露，", "只知送恨添愁事，誰見淩霄羽蛻功。"]'),
('yuding-45','寄滑州文秀大師','劉兼','唐','御定全唐诗','yuding','','[]','分飛屈指十三年，菡萏峰前別社蓮。薄宦偶然來左蜀，',40,'御定全唐詩/json/766.json','["分飛屈指十三年，菡萏峰前別社蓮。薄宦偶然來左蜀，", "珍重湯休惠佳句，郡齋吟久不成眠。"]'),
('yuding-46','中春登樓','劉兼','唐','御定全唐诗','yuding','','[]','金杯不以滌愁腸，江郡芳時憶故鄉。兩岸煙花春富貴，',80,'御定全唐詩/json/766.json','["金杯不以滌愁腸，江郡芳時憶故鄉。兩岸煙花春富貴，", "歸去蓮花歸未得，白雲深處有茅堂。", "古今通塞莫咨嗟，謾把霜髯敵歲華。失手已慚蛇有足，", "獨倚郡樓人不會，釣舟春浪接平沙。"]'),
('yuding-47','自遣','劉兼','唐','御定全唐诗','yuding','','[]','未上亨衢獨醉吟，賦成無處博黃金。家人莫問張儀舌，',40,'御定全唐詩/json/766.json','["未上亨衢獨醉吟，賦成無處博黃金。家人莫問張儀舌，", "鶤鵬鱗翼途程在，九萬風雲海浪深。"]'),
('yuding-48','偶有下殤，因而自遣','劉兼','唐','御定全唐诗','yuding','','[]','彭壽殤齡共兩空，幻泡緣影夢魂中。缺圓宿會長如月，',40,'御定全唐詩/json/766.json','["彭壽殤齡共兩空，幻泡緣影夢魂中。缺圓宿會長如月，", "南柯太守知人意，休問陶陶塞上翁。"]'),
('yuding-49','倦學','劉兼','唐','御定全唐诗','yuding','','[]','樂廣亡來冰鏡稀，宓妃嫫母混妍媸。且于霧裏藏玄豹，',40,'御定全唐詩/json/766.json','["樂廣亡來冰鏡稀，宓妃嫫母混妍媸。且于霧裏藏玄豹，", "門前春色芳如畫，好掩書齋任所之。"]'),
('yuding-50','去年今日','劉兼','唐','御定全唐诗','yuding','','[]','去年今日到榮州，五騎紅塵入郡樓。貔虎只知迎太守，',40,'御定全唐詩/json/766.json','["去年今日到榮州，五騎紅塵入郡樓。貔虎只知迎太守，", "聖主若容辭重祿，便歸煙水狎群鷗。"]'),
('yuding-51','晝寢','劉兼','唐','御定全唐诗','yuding','','[]','花落青苔錦數重，書淫不覺避春慵。恣情枕上飛莊蝶，',40,'御定全唐詩/json/766.json','["花落青苔錦數重，書淫不覺避春慵。恣情枕上飛莊蝶，", "起來已被詩魔引，窗外寒敲翠竹風。"]'),
('yuding-52','郡齋寓興','劉兼','唐','御定全唐诗','yuding','','[]','依約樊川似旭川，郡齋風物盡蕭然。秋庭碧蘚鋪雲錦，',40,'御定全唐詩/json/766.json','["依約樊川似旭川，郡齋風物盡蕭然。秋庭碧蘚鋪雲錦，", "情懷放蕩無羈束，地角天涯亦信緣。"]'),
('yuding-53','郡樓閑望書懷','劉兼','唐','御定全唐诗','yuding','','[]','郡城樓閣繞江濱，風物清秋入望頻。銅鼓祭龍雲塞廟，',40,'御定全唐詩/json/766.json','["郡城樓閣繞江濱，風物清秋入望頻。銅鼓祭龍雲塞廟，", "歸去杜陵池館在，且將朝服拂埃塵。"]'),
('yuding-54','玉燭花','劉兼','唐','御定全唐诗','yuding','','[]','嫋嫋香英三四枝，亭亭紅豔照階墀。正當晚檻初開處，',40,'御定全唐詩/json/766.json','["嫋嫋香英三四枝，亭亭紅豔照階墀。正當晚檻初開處，", "夜深斜倚朱欄外，擬把鄰光借與誰。"]'),
('yuding-55','從弟舍人惠茶','劉兼','唐','御定全唐诗','yuding','','[]','曾求芳茗貢蕪詞，果沐頒沾味甚奇。龜背起紋輕炙處，',40,'御定全唐詩/json/766.json','["曾求芳茗貢蕪詞，果沐頒沾味甚奇。龜背起紋輕炙處，", "珍重宗親相寄惠，水亭山閣自攜持。"]'),
('yuding-56','再看光福寺牡丹','劉兼','唐','御定全唐诗','yuding','','[]','去年曾看牡丹花，蛺蝶迎人傍彩霞。今日再遊光福寺，',40,'御定全唐詩/json/766.json','["去年曾看牡丹花，蛺蝶迎人傍彩霞。今日再遊光福寺，", "來歲未朝金闕去，依前和露載歸衙。"]'),
('yuding-57','海棠花','劉兼','唐','御定全唐诗','yuding','','[]','淡淡微紅色不深，依依偏得似春心。煙輕虢國顰歌黛，',40,'御定全唐詩/json/766.json','["淡淡微紅色不深，依依偏得似春心。煙輕虢國顰歌黛，", "良宵更有多情處，月下芬芳伴醉吟。"]'),
('yuding-58','新竹','劉兼','唐','御定全唐诗','yuding','','[]','近窗臥砌兩三叢，佐靜添幽別有功。影鏤碎金初透月，',40,'御定全唐詩/json/766.json','["近窗臥砌兩三叢，佐靜添幽別有功。影鏤碎金初透月，", "自是子猷偏愛爾，虛心高節雪霜中。"]'),
('yuding-59','木芙蓉','劉兼','唐','御定全唐诗','yuding','','[]','素靈失律詐風流，強把芳菲半載偷。是葉葳蕤霜照夜，',40,'御定全唐詩/json/766.json','["素靈失律詐風流，強把芳菲半載偷。是葉葳蕤霜照夜，", "誰道金風能肅物，因何厚薄不相侔。"]'),
('yuding-60','送二郎君歸長安','劉兼','唐','御定全唐诗','yuding','','[]','我兒辭去淚雙流，蜀郡秦川兩處愁。紅葉滿山歸故國，',40,'御定全唐詩/json/766.json','["我兒辭去淚雙流，蜀郡秦川兩處愁。紅葉滿山歸故國，", "好向雲泉營舊隱，莫教莊叟畏犧牛。"]'),
('yuding-61','送文英大師','劉兼','唐','御定全唐诗','yuding','','[]','屈指平陽別社蓮，蟾光一百度曾圓。孤雲自在知何處，',40,'御定全唐詩/json/766.json','["屈指平陽別社蓮，蟾光一百度曾圓。孤雲自在知何處，", "搖鞭相送嘉陵岸，回首群峰隔翠煙。"]'),
('yuding-62','酬勾評事','劉兼','唐','御定全唐诗','yuding','','[]','閒庭欹枕正悲秋，忽覺新編浣遠愁。才薄只愁安雁戶，',40,'御定全唐詩/json/766.json','["閒庭欹枕正悲秋，忽覺新編浣遠愁。才薄只愁安雁戶，", "對景卻慚無藻思，南金荊玉卒難酬。"]'),
('yuding-63','初至郡界','劉兼','唐','御定全唐诗','yuding','','[]','嘉陵江畔接榮川，兩畔旌旗下瀨船。郡印已分炎瘴地，',40,'御定全唐詩/json/766.json','["嘉陵江畔接榮川，兩畔旌旗下瀨船。郡印已分炎瘴地，", "錦字莫嫌歸路遠，華夷一統太平年。"]'),
('yuding-64','到郡後有寄','劉兼','唐','御定全唐诗','yuding','','[]','蜀路新修盡坦平，交親深幸再逢迎。正當返袂思鄉國，',40,'御定全唐詩/json/766.json','["蜀路新修盡坦平，交親深幸再逢迎。正當返袂思鄉國，", "欲將感戀裁書旨，多少魚箋寫得成。"]'),
('yuding-65','長春節','劉兼','唐','御定全唐诗','yuding','','[]','聖朝佳節遇長春，跪捧金爐祝又焚。寶藏發來天地秀，',40,'御定全唐詩/json/766.json','["聖朝佳節遇長春，跪捧金爐祝又焚。寶藏發來天地秀，", "更有馨香滿芳檻，和風遲日在蘭蓀。"]'),
('yuding-66','登郡樓書事','劉兼','唐','御定全唐诗','yuding','','[]','偶奉綸書蒞旭川，郡樓嘉致盡依然。松欹鳥道雲藏寺，',40,'御定全唐詩/json/766.json','["偶奉綸書蒞旭川，郡樓嘉致盡依然。松欹鳥道雲藏寺，", "有時倚檻垂雙袂，故國風光似眼前。"]'),
('yuding-67','旭川祁宰思家而卒，因述意呈秦川知己','劉兼','唐','御定全唐诗','yuding','','[]','歲稔民康絕訟論，政成公暇自由身。朝看五馬閑如社，',40,'御定全唐詩/json/766.json','["歲稔民康絕訟論，政成公暇自由身。朝看五馬閑如社，", "豈同齷齪祁員外，至死悲涼一婦人。"]'),
('yuding-68','登郡樓書懷','劉兼','唐','御定全唐诗','yuding','','[]','煙雨樓臺漸晦冥，錦江澄碧浪花平。卞和未雪荊山恥，',120,'御定全唐詩/json/766.json','["煙雨樓臺漸晦冥，錦江澄碧浪花平。卞和未雪荊山恥，", "登高欲繼離騷詠，魂斷愁深寫不成。", "邊郡荒涼悲且歌，故園迢遞隔煙波。琴聲背俗終如是，", "北山更有移文者，白首無塵歸去麼。", "莫嗔阮氏哭途窮，萬代深沈恨亦同。瑞玉豈知將抵鵲，", "獨倚郡樓無限意，滿江煙雨正冥蒙。"]'),
('yuding-69','偶聞官吏舉請，輒有一篇寄從弟舍人','劉兼','唐','御定全唐诗','yuding','','[]','官吏潛陳借寇詞，宦情鄉夢兩相違。青城錦水無心住，',40,'御定全唐詩/json/766.json','["官吏潛陳借寇詞，宦情鄉夢兩相違。青城錦水無心住，", "黃茅瘴色看看起，貪者猶疑別是機。"]'),
('yuding-70','誡是非','劉兼','唐','御定全唐诗','yuding','','[]','巧舌如簧總莫聽，是非多自愛憎生。三人告母雖投杼，',40,'御定全唐詩/json/766.json','["巧舌如簧總莫聽，是非多自愛憎生。三人告母雖投杼，", "因思疇昔游談者，六國交馳亦受烹。"]'),
('yuding-71','簡豎儒','劉兼','唐','御定全唐诗','yuding','','[]','蹄涔豈信有滄浪，螢火何堪並太陽。淵奧未曾探禹穴，',40,'御定全唐詩/json/766.json','["蹄涔豈信有滄浪，螢火何堪並太陽。淵奧未曾探禹穴，", "近日冰壺多晦昧，虎皮羊質也觀光。"]'),
('yuding-72','貽諸學童','劉兼','唐','御定全唐诗','yuding','','[]','橫經叉手步還趨，積善方知慶有餘。五個小雛離學院，',40,'御定全唐詩/json/766.json','["橫經叉手步還趨，積善方知慶有餘。五個小雛離學院，", "勸汝立身須苦志，月中丹桂自扶疏。"]'),
('yuding-0','吳：黃金車','孫元晏','唐','御定全唐诗','yuding','','[]','分擘山河即漸開，許昌基業已傾頹。',32,'御定全唐詩/json/767.json','["分擘山河即漸開，許昌基業已傾頹。", "黃金車與斑斕耳，早個須知入讖來。"]'),
('yuding-1','吳：赤壁','孫元晏','唐','御定全唐诗','yuding','','[]','會獵書來舉國驚，只應周魯不教迎。',32,'御定全唐詩/json/767.json','["會獵書來舉國驚，只應周魯不教迎。", "曹公一戰奔波後，赤壁功傳萬古名。"]'),
('yuding-2','吳：魯肅指囷','孫元晏','唐','御定全唐诗','yuding','','[]','破產移家事亦難，佐吳從此霸江山。',32,'御定全唐詩/json/767.json','["破產移家事亦難，佐吳從此霸江山。", "爭教不立功勳得，指出千囷如等閒。"]'),
('yuding-3','吳：甘甯斫營','孫元晏','唐','御定全唐诗','yuding','','[]','夜深偷入魏軍營，滿寨驚忙火似星。',32,'御定全唐詩/json/767.json','["夜深偷入魏軍營，滿寨驚忙火似星。", "百口寶刀千匹絹，也應消得與甘寧。"]'),
('yuding-4','吳：徐盛','孫元晏','唐','御定全唐诗','yuding','','[]','欲把江山鼎足分，邢真銜冊到江南。',32,'御定全唐詩/json/767.json','["欲把江山鼎足分，邢真銜冊到江南。", "當時將相誰堪重，徐盛將軍最不甘。"]'),
('yuding-5','吳：魯肅','孫元晏','唐','御定全唐诗','yuding','','[]','斫案興言斷眾疑，鼎分從此定雄雌。',32,'御定全唐詩/json/767.json','["斫案興言斷眾疑，鼎分從此定雄雌。", "若無子敬心相似，爭得烏林破魏師。"]'),
('yuding-6','吳：武昌','孫元晏','唐','御定全唐诗','yuding','','[]','西塞山高截九垓，讖謠終日自相催。',32,'御定全唐詩/json/767.json','["西塞山高截九垓，讖謠終日自相催。", "武昌魚美應難戀，歷數須歸建業來。"]'),
('yuding-7','吳：顧雍','孫元晏','唐','御定全唐诗','yuding','','[]','贊國經綸更有誰，蔡公相歎亦相師。',32,'御定全唐詩/json/767.json','["贊國經綸更有誰，蔡公相歎亦相師。", "貴為丞相封侯了，歸後家人總不知。"]'),
('yuding-8','吳：呂蒙','孫元晏','唐','御定全唐诗','yuding','','[]','幼小家貧實可哀，願征行去志難回。',32,'御定全唐詩/json/767.json','["幼小家貧實可哀，願征行去志難回。", "不探虎穴求身達，爭得人間富貴來。"]'),
('yuding-9','吳：介象','孫元晏','唐','御定全唐诗','yuding','','[]','好道君王遇亦難，變通靈異幾多般。',32,'御定全唐詩/json/767.json','["好道君王遇亦難，變通靈異幾多般。", "介先生有神仙術，釣得鱸魚在玉盤。"]'),
('yuding-10','吳：濡須塢','孫元晏','唐','御定全唐诗','yuding','','[]','風揭洪濤響若雷，枕波為壘險相隈。',32,'御定全唐詩/json/767.json','["風揭洪濤響若雷，枕波為壘險相隈。", "莫言有個濡須塢，幾度曹公失志回。"]'),
('yuding-11','吳：周泰','孫元晏','唐','御定全唐诗','yuding','','[]','名與諸公又不同，金瘡痕在滿身中。',32,'御定全唐詩/json/767.json','["名與諸公又不同，金瘡痕在滿身中。", "不將禦蓋宣恩澤，誰信將軍別有功。"]'),
('yuding-12','吳：張紘','孫元晏','唐','御定全唐诗','yuding','','[]','東部張公與眾殊，共施經略贊全吳。',32,'御定全唐詩/json/767.json','["東部張公與眾殊，共施經略贊全吳。", "陳琳漫自稱雄伯，神氣應須怯大巫。"]'),
('yuding-13','吳：太史慈','孫元晏','唐','御定全唐诗','yuding','','[]','聖德招賢遠近知，曹公心計卻成欺。',32,'御定全唐詩/json/767.json','["聖德招賢遠近知，曹公心計卻成欺。", "陳韓昔日嘗投楚，豈是當歸召得伊。"]'),
('yuding-14','吳：孫堅後','孫元晏','唐','御定全唐诗','yuding','','[]','委存張公翊聖材，幾將賢德贊文台。',32,'御定全唐詩/json/767.json','["委存張公翊聖材，幾將賢德贊文台。", "爭教不霸江山得，日月征曾入夢來。"]'),
('yuding-15','吳：陸統','孫元晏','唐','御定全唐诗','yuding','','[]','將軍身歿有兒孤，虎子為名教讀書。',32,'御定全唐詩/json/767.json','["將軍身歿有兒孤，虎子為名教讀書。", "更向宮中教騎馬，感君恩重合何如。"]'),
('yuding-16','吳：青蓋','孫元晏','唐','御定全唐诗','yuding','','[]','歷數將終勢已摧，不修君德更堪哀。',32,'御定全唐詩/json/767.json','["歷數將終勢已摧，不修君德更堪哀。", "被他青蓋言相誤，元是須教入晉來。"]'),
('yuding-17','晉：七寶鞭','孫元晏','唐','御定全唐诗','yuding','','[]','天命須知豈偶然，亂臣徒欲用兵權。',32,'御定全唐詩/json/767.json','["天命須知豈偶然，亂臣徒欲用兵權。", "聖謨廟略還應別，渾不消他七寶鞭。"]'),
('yuding-18','晉：庾悅鵝炙','孫元晏','唐','御定全唐诗','yuding','','[]','春暖江南景氣新，子鵝炙美就中珍。',32,'御定全唐詩/json/767.json','["春暖江南景氣新，子鵝炙美就中珍。", "庾家廚盛劉公困，渾弗相貽也惱人。"]'),
('yuding-19','晉：謝玄','孫元晏','唐','御定全唐诗','yuding','','[]','百萬兵來逼合肥，謝玄為將統雄師。',32,'御定全唐詩/json/767.json','["百萬兵來逼合肥，謝玄為將統雄師。", "旌旗首尾千餘裏，渾不消他一局棋。"]'),
('yuding-20','晉：謝混','孫元晏','唐','御定全唐诗','yuding','','[]','尚主當初偶未成，此時誰合更關情。',32,'御定全唐詩/json/767.json','["尚主當初偶未成，此時誰合更關情。", "可憐謝混風華在，千古翻傳禁臠名。"]'),
('yuding-21','晉：陸玩','孫元晏','唐','御定全唐诗','yuding','','[]','陸公高論亦由衷，謙讓還慚未有功。',32,'御定全唐詩/json/767.json','["陸公高論亦由衷，謙讓還慚未有功。", "天下忠良人欲盡，始應交我作三公。"]'),
('yuding-22','晉：王坦之','孫元晏','唐','御定全唐诗','yuding','','[]','晉祚安危只此行，坦之何必苦憂驚。',32,'御定全唐詩/json/767.json','["晉祚安危只此行，坦之何必苦憂驚。", "謝公合定寰區在，爭遣當時事得成。"]'),
('yuding-23','晉：蒲葵扇','孫元晏','唐','御定全唐诗','yuding','','[]','拋舍東山歲月遙，幾施經略挫雄豪。',32,'御定全唐詩/json/767.json','["拋舍東山歲月遙，幾施經略挫雄豪。", "若非名德喧寰宇，爭得蒲葵價數高。"]'),
('yuding-24','晉：王郎','孫元晏','唐','御定全唐诗','yuding','','[]','太尉門庭亦甚高，王郎名重禮相饒。',32,'御定全唐詩/json/767.json','["太尉門庭亦甚高，王郎名重禮相饒。", "自家妻父猶如此，誰更逢君得折腰。"]'),
('yuding-25','晉：劉毅','孫元晏','唐','御定全唐诗','yuding','','[]','繞床堪壯喝盧聲，似鐵容儀眾盡驚。',32,'御定全唐詩/json/767.json','["繞床堪壯喝盧聲，似鐵容儀眾盡驚。", "二十七人同舉義，幾人全得舊功名。"]'),
('yuding-26','晉：王恭','孫元晏','唐','御定全唐诗','yuding','','[]','春風濯濯柳容儀，鶴氅神情舉世推。',32,'御定全唐詩/json/767.json','["春風濯濯柳容儀，鶴氅神情舉世推。", "可惜教君仗旄鉞，枉將心地托牢之。"]'),
('yuding-27','晉：謝公賭墅','孫元晏','唐','御定全唐诗','yuding','','[]','發遣將軍欲去時，略無情撓只貪棋。',32,'御定全唐詩/json/767.json','["發遣將軍欲去時，略無情撓只貪棋。", "自從乞與羊曇後，賭墅功成更有誰。"]'),
('yuding-28','晉：苻堅投棰','孫元晏','唐','御定全唐诗','yuding','','[]','投棰填江語未終，謝安乘此立殊功。',32,'御定全唐詩/json/767.json','["投棰填江語未終，謝安乘此立殊功。", "三台星爛乾坤在，且與張華死不同。"]'),
('yuding-29','晉：衛玠','孫元晏','唐','御定全唐诗','yuding','','[]','叔寶羊車海內稀，山家女婿好風姿。',32,'御定全唐詩/json/767.json','["叔寶羊車海內稀，山家女婿好風姿。", "江東士女無端甚，看殺玉人渾不知。"]'),
('yuding-30','晉：郭璞脫襦','孫元晏','唐','御定全唐诗','yuding','','[]','吟坐因思郭景純，每言窮達似通神。',32,'御定全唐詩/json/767.json','["吟坐因思郭景純，每言窮達似通神。", "到頭分命難移改，解脫青襦與別人。"]'),
('yuding-31','晉：庾樓','孫元晏','唐','御定全唐诗','yuding','','[]','江州樓上月明中，從事同登眺遠空。',32,'御定全唐詩/json/767.json','["江州樓上月明中，從事同登眺遠空。", "玉樹忽薶千載後，有誰重此繼清風。"]'),
('yuding-32','晉：新亭','孫元晏','唐','御定全唐诗','yuding','','[]','容易乘虛逼帝畿，滿江艛櫓與旌旗。',32,'御定全唐詩/json/767.json','["容易乘虛逼帝畿，滿江艛櫓與旌旗。", "盧循若解新亭上，勝負還應未可知。"]'),
('yuding-33','宋：大峴','孫元晏','唐','御定全唐诗','yuding','','[]','大峴才過喜可知，指空言已副心期。',32,'御定全唐詩/json/767.json','["大峴才過喜可知，指空言已副心期。", "公孫計策嗟無用，天與南朝作霸基。"]'),
('yuding-34','宋：放宮人','孫元晏','唐','御定全唐诗','yuding','','[]','納諫廷臣免犯顏，自然恩可霸江山。',32,'御定全唐詩/json/767.json','["納諫廷臣免犯顏，自然恩可霸江山。", "姚興侍女方承寵，放出宮闈若等閒。"]'),
('yuding-35','宋：借南苑','孫元晏','唐','御定全唐诗','yuding','','[]','人主詞應不偶然，幾人曾說笑掀天。',32,'御定全唐詩/json/767.json','["人主詞應不偶然，幾人曾說笑掀天。", "不知南苑今何在，借與張公三百年。"]'),
('yuding-36','宋：謝澹雲霞友','孫元晏','唐','御定全唐诗','yuding','','[]','仗氣淩人豈可親，只將範泰是知聞。',32,'御定全唐詩/json/767.json','["仗氣淩人豈可親，只將範泰是知聞。", "緣何喚作雲霞友，卻恐雲霞未似君。"]'),
('yuding-37','宋：烏衣巷','孫元晏','唐','御定全唐诗','yuding','','[]','古跡荒基好歎嗟，滿川吟景只煙霞。',32,'御定全唐詩/json/767.json','["古跡荒基好歎嗟，滿川吟景只煙霞。", "烏衣巷在何人住，回首令人憶謝家。"]'),
('yuding-38','宋：袁粲','孫元晏','唐','御定全唐诗','yuding','','[]','負才尚氣滿朝知，高臥閑吟見客稀。',32,'御定全唐詩/json/767.json','["負才尚氣滿朝知，高臥閑吟見客稀。", "獨步何人識袁尹，白楊郊外醉方歸。"]'),
('yuding-39','宋：劉伯龍','孫元晏','唐','御定全唐诗','yuding','','[]','位重何如不厭貧，伯龍孤子只修身。',32,'御定全唐詩/json/767.json','["位重何如不厭貧，伯龍孤子只修身。", "固知生計還須有，窮鬼臨時也笑人。"]'),
('yuding-40','宋：王方平','孫元晏','唐','御定全唐诗','yuding','','[]','拂衣耕釣已多時，江上山前樂可知。',32,'御定全唐詩/json/767.json','["拂衣耕釣已多時，江上山前樂可知。", "著卻貂裘將采藥，任他人喚作漁師。"]'),
('yuding-41','宋：黃羅襦','孫元晏','唐','御定全唐诗','yuding','','[]','戚屬群臣盡見猜，預憂身後又堪哀。',32,'御定全唐詩/json/767.json','["戚屬群臣盡見猜，預憂身後又堪哀。", "到頭委付何曾是，虛把羅襦與彥回。"]'),
('yuding-42','宋：謝朏','孫元晏','唐','御定全唐诗','yuding','','[]','謝家諸子盡蘭香，各震芳名滿帝鄉。',32,'御定全唐詩/json/767.json','["謝家諸子盡蘭香，各震芳名滿帝鄉。", "惟有千金更堪重，只將高臥向齊王。"]'),
('yuding-43','宋：羊玄保','孫元晏','唐','御定全唐诗','yuding','','[]','運命將來各有期，好官才闕即思之。',32,'御定全唐詩/json/767.json','["運命將來各有期，好官才闕即思之。", "就中堪愛羊玄保，偏受君王分外知。"]'),
('yuding-44','齊：謝朏','孫元晏','唐','御定全唐诗','yuding','','[]','解璽傳呼詔侍中，卻來高臥豈疏慵。',32,'御定全唐詩/json/767.json','["解璽傳呼詔侍中，卻來高臥豈疏慵。", "此時忠節還稀有，堪羨君王特地容。"]'),
('yuding-45','齊：小兒執燭','孫元晏','唐','御定全唐诗','yuding','','[]','謝公情量已難量，忠宋心誠豈暫忘。',32,'御定全唐詩/json/767.json','["謝公情量已難量，忠宋心誠豈暫忘。", "執燭小兒渾放去，略無言語與君王。"]'),
('yuding-46','齊：王僧佑','孫元晏','唐','御定全唐诗','yuding','','[]','肯與公卿作等倫，澹然名德只推君。',32,'御定全唐詩/json/767.json','["肯與公卿作等倫，澹然名德只推君。", "任他車騎來相訪，簫鼓盈庭似不聞。"]'),
('yuding-47','齊：王僧虔','孫元晏','唐','御定全唐诗','yuding','','[]','位高名重不堪疑，懇讓儀同帝亦知。',32,'御定全唐詩/json/767.json','["位高名重不堪疑，懇讓儀同帝亦知。", "不學常流爭進取，卻憂門有二台司。"]'),
('yuding-48','齊：明帝裹蒸','孫元晏','唐','御定全唐诗','yuding','','[]','至尊尊貴異人間，禦膳天廚豈等閒。',32,'御定全唐詩/json/767.json','["至尊尊貴異人間，禦膳天廚豈等閒。", "惜得裹蒸無用處，不如安霸取江山。"]'),
('yuding-49','齊：郁林王','孫元晏','唐','御定全唐诗','yuding','','[]','強哀強慘亦從伊，歸到私庭喜可知。',32,'御定全唐詩/json/767.json','["強哀強慘亦從伊，歸到私庭喜可知。", "喜字漫書三十六，到頭能得幾多時。"]'),
('yuding-50','齊：何氏小山','孫元晏','唐','御定全唐诗','yuding','','[]','顯達何曾肯系心，築居郊外好園林。',32,'御定全唐詩/json/767.json','["顯達何曾肯系心，築居郊外好園林。", "賺他謝朏出山去，贏得高名直至今。"]'),
('yuding-51','齊：王倫之','孫元晏','唐','御定全唐诗','yuding','','[]','豫章太守重詞林，圖畫陳蕃與華歆。',32,'御定全唐詩/json/767.json','["豫章太守重詞林，圖畫陳蕃與華歆。", "更奠子將並孺子，為君千載作知音。"]'),
('yuding-52','齊：潘妃','孫元晏','唐','御定全唐诗','yuding','','[]','曾步金蓮寵絕倫，豈甘今日委埃塵。',32,'御定全唐詩/json/767.json','["曾步金蓮寵絕倫，豈甘今日委埃塵。", "玉兒還有懷恩處，不肯將身嫁小臣。"]'),
('yuding-53','齊：王亮','孫元晏','唐','御定全唐诗','yuding','','[]','後見梁王未免哀，奈何無計拯傾頹。',32,'御定全唐詩/json/767.json','["後見梁王未免哀，奈何無計拯傾頹。", "若教彼相顛扶得，爭遣明公到此來。"]'),
('yuding-54','梁：分宮女','孫元晏','唐','御定全唐诗','yuding','','[]','滌蕩齊宮法令新，分張宮女二千人。',32,'御定全唐詩/json/767.json','["滌蕩齊宮法令新，分張宮女二千人。", "可憐無限如花貌，重見世間桃李春。"]'),
('yuding-55','梁：馬仙埤','孫元晏','唐','御定全唐诗','yuding','','[]','齊朝太守不甘降，忠節當時動四方。',32,'御定全唐詩/json/767.json','["齊朝太守不甘降，忠節當時動四方。", "義士要教天下見，且留君住待袁昂。"]'),
('yuding-56','梁：勍敵','孫元晏','唐','御定全唐诗','yuding','','[]','傳聞天子重儒才，特為皇華綺宴開。',32,'御定全唐詩/json/767.json','["傳聞天子重儒才，特為皇華綺宴開。", "今日方驚遇勍敵，此人元自北朝來。"]'),
('yuding-57','梁：蔡撙','孫元晏','唐','御定全唐诗','yuding','','[]','紫茄白莧以為珍，守任清真轉更貧。',32,'御定全唐詩/json/767.json','["紫茄白莧以為珍，守任清真轉更貧。", "不飲吳興郡中水，古今能有幾多人。"]'),
('yuding-58','梁：楚祠','孫元晏','唐','御定全唐诗','yuding','','[]','曾與蕭侯醉玉杯，此時神影盡傾頹。',32,'御定全唐詩/json/767.json','["曾與蕭侯醉玉杯，此時神影盡傾頹。", "莫雲千古無靈聖，也向西川助敵來。"]'),
('yuding-59','梁：謝朏小輿','孫元晏','唐','御定全唐诗','yuding','','[]','小輿升殿掌鈞台，不免無憀卻憶回。',32,'御定全唐詩/json/767.json','["小輿升殿掌鈞台，不免無憀卻憶回。", "應恨被他何胤誤，悔先容易出山來。"]'),
('yuding-60','梁：八關齋','孫元晏','唐','御定全唐诗','yuding','','[]','依憑金地甚虔誠，忍溺空王為聖明。',32,'御定全唐詩/json/767.json','["依憑金地甚虔誠，忍溺空王為聖明。", "內殿設齋申禱祝，豈無功德及台城。"]'),
('yuding-61','梁：庾信','孫元晏','唐','御定全唐诗','yuding','','[]','苦心詞賦向誰談，淪落周朝志豈甘。',32,'御定全唐詩/json/767.json','["苦心詞賦向誰談，淪落周朝志豈甘。", "可惜多才庾開府，一生惆悵憶江南。"]'),
('yuding-62','陳：王僧辨','孫元晏','唐','御定全唐诗','yuding','','[]','彼此英雄各有名，石頭高臥擬爭衡。',32,'御定全唐詩/json/767.json','["彼此英雄各有名，石頭高臥擬爭衡。", "當時堪笑王僧辨，待欲將心托聖明。"]'),
('yuding-63','陳：武帝蚌盤','孫元晏','唐','御定全唐诗','yuding','','[]','金翠絲黃略不舒，蚌盤清宴意何如。',32,'御定全唐詩/json/767.json','["金翠絲黃略不舒，蚌盤清宴意何如。", "豈知三閣繁華日，解為君王妙破除。"]'),
('yuding-64','陳：虞居士','孫元晏','唐','御定全唐诗','yuding','','[]','苦諫將軍總不知，幾隨煙焰作塵飛。',32,'御定全唐詩/json/767.json','["苦諫將軍總不知，幾隨煙焰作塵飛。", "東山居士何人識，惟有君王卻許歸。"]'),
('yuding-65','陳：姚察','孫元晏','唐','御定全唐诗','yuding','','[]','曾佐徐陵向北游，剖陳疑事動名流。',32,'御定全唐詩/json/767.json','["曾佐徐陵向北游，剖陳疑事動名流。", "卻歸掌選清何甚，一匹花綀不肯收。"]'),
('yuding-66','陳：宣帝傷將卒','孫元晏','唐','御定全唐诗','yuding','','[]','前後兵師戰勝回，百餘城壘盡歸來。',32,'御定全唐詩/json/767.json','["前後兵師戰勝回，百餘城壘盡歸來。", "當時將卒應知感，況得君王為舉哀。"]'),
('yuding-67','陳：臨春閣','孫元晏','唐','御定全唐诗','yuding','','[]','臨春高閣上侵雲，風起香飄數裏聞。',32,'御定全唐詩/json/767.json','["臨春高閣上侵雲，風起香飄數裏聞。", "自是君王正沈醉，豈知消息報隋軍。"]'),
('yuding-68','陳：結綺閣','孫元晏','唐','御定全唐诗','yuding','','[]','結綺高宜眺海涯，上淩丹漢拂雲霞。',32,'御定全唐詩/json/767.json','["結綺高宜眺海涯，上淩丹漢拂雲霞。", "一千朱翠同居此，爭奈恩多屬麗華。"]'),
('yuding-69','陳：望仙閣','孫元晏','唐','御定全唐诗','yuding','','[]','多少沈檀結築成，望仙為號倚青冥。',32,'御定全唐詩/json/767.json','["多少沈檀結築成，望仙為號倚青冥。", "不知孔氏何形狀，醉得君王不解醒。"]'),
('yuding-70','陳：三閣','孫元晏','唐','御定全唐诗','yuding','','[]','三閣相通綺宴開，數千朱翠繞周回。',32,'御定全唐詩/json/767.json','["三閣相通綺宴開，數千朱翠繞周回。", "只知斷送君王醉，不道韓擒已到來。"]'),
('yuding-71','陳：狎客','孫元晏','唐','御定全唐诗','yuding','','[]','八宮妃盡賦篇章，風揭歌聲錦繡香。',32,'御定全唐詩/json/767.json','["八宮妃盡賦篇章，風揭歌聲錦繡香。", "選得十人為狎客，有誰能解諫君王。"]'),
('yuding-72','陳：淮水','孫元晏','唐','御定全唐诗','yuding','','[]','文物衣冠盡入秦，六朝繁盛忽埃塵。',32,'御定全唐詩/json/767.json','["文物衣冠盡入秦，六朝繁盛忽埃塵。", "自從淮水乾枯後，不見王家更有人。"]'),
('yuding-73','陳：江令宅','孫元晏','唐','御定全唐诗','yuding','','[]','不向南朝立諫名，舊居基在事分明。',32,'御定全唐詩/json/767.json','["不向南朝立諫名，舊居基在事分明。", "令人惆悵江中令，只作篇章過一生。"]'),
('yuding-74','陳：後庭舞','孫元晏','唐','御定全唐诗','yuding','','[]','嬿婉回風態若飛，麗華翹袖玉為姿。',32,'御定全唐詩/json/767.json','["嬿婉回風態若飛，麗華翹袖玉為姿。", "後庭一曲從教舞，舞破江山君未知。"]'),
('yuding-0','班婕妤','嚴識玄','唐','御定全唐诗','yuding','','[]','賤妾如桃李，君王若歲時。秋風一已勁，搖落不勝悲。',48,'御定全唐詩/json/768.json','["賤妾如桃李，君王若歲時。秋風一已勁，搖落不勝悲。", "寂寂蒼苔滿，沉沉綠草滋。繁華非此日，指輦競何辭。"]'),
('yuding-1','賦得禦制句朔野陣雲飛','何象','唐','御定全唐诗','yuding','','[]','塞日穿痕斷，邊鴻背影飛。縹緲浮黃屋，陰沈護禦衣。',24,'御定全唐詩/json/768.json','["塞日穿痕斷，邊鴻背影飛。縹緲浮黃屋，陰沈護禦衣。"]'),
('yuding-2','宿金河戍','張震','唐','御定全唐诗','yuding','','[]','朝發鐵麟驛，夕宿金河戍。奔波急王程，一日千里路。',48,'御定全唐詩/json/768.json','["朝發鐵麟驛，夕宿金河戍。奔波急王程，一日千里路。", "但見容鬢改，不知歲華暮。悠悠沙漠行，王事彌多故。"]'),
('yuding-3','補新宮','丘光庭','唐','御定全唐诗','yuding','','[]','奐奐新宮，禮樂其融。爾德惟賢，爾□維忠。',120,'御定全唐詩/json/768.json','["奐奐新宮，禮樂其融。爾德惟賢，爾□維忠。", "為忠以公，斯筵是同。人之醉我，與我延賓。", "奐奐新宮，既奐而輪。其固如山，其儼如雲。", "其寢斯安，□□□分。我既考落，以燕群臣。", "奐奐新宮，既祭既延。我□□鏞，於以醉賢。", "有禮無愆，我有斯宮。斯宮以安，康後萬年。"]'),
('yuding-4','補茅鴟','丘光庭','唐','御定全唐诗','yuding','','[]','茅鴟茅鴟，無集我岡。汝食汝飽，莫我為祥。',161,'御定全唐詩/json/768.json','["茅鴟茅鴟，無集我岡。汝食汝飽，莫我為祥。", "願彈去汝，來彼鳳凰。來彼鳳凰，其儀有章。", "茅鴟茅鴟，無啄我雀。汝食汝飽，莫我肯略。", "願彈去汝，來彼瑞鵲。來彼瑞鵲，其音可樂。", "茅鴟茅鴟，無搏鷅鶹。汝食汝飽，莫我為休。", "願彈去汝，來彼鳲鳩。來彼鳲鳩，食子其周。", "茅鴟茅鴟，無ew我陵。汝食汝飽，莫我好聲。", "願彈去汝，來彼蒼鷹。來彼蒼鷹，祭鳥是征。"]'),
('yuding-5','瑕瑜不相掩','武翊黃','唐','御定全唐诗','yuding','','[]','抱璞應難辨，妍媸每自融。貞姿偏特達，微玷遇磨礱。',72,'御定全唐詩/json/768.json','["抱璞應難辨，妍媸每自融。貞姿偏特達，微玷遇磨礱。", "涇渭流終異，瑕瑜自不同。半曾光透石，未掩氣如虹。", "縝密誠為智，包藏豈謂忠。停看分美惡，今得值良工。"]'),
('yuding-6','袁江口懷王司勳王吏部','李祜','唐','御定全唐诗','yuding','','[]','京華不啻三千里，客淚如今一萬雙。',32,'御定全唐詩/json/768.json','["京華不啻三千里，客淚如今一萬雙。", "若個最為相憶處，青楓黃竹入袁江。"]'),
('yuding-7','贈進士李守微','韓嶼','唐','御定全唐诗','yuding','','[]','一定童顏老歲華，貧寒遊歷貴人家。煉成正氣功應大，',40,'御定全唐詩/json/768.json','["一定童顏老歲華，貧寒遊歷貴人家。煉成正氣功應大，", "如何蓬閬不歸去，落盡蟠桃幾度花。"]'),
('yuding-8','馬上有見','李茂複','唐','御定全唐诗','yuding','','[]','行盡疏林見小橋，綠楊深處有紅蕉。',32,'御定全唐詩/json/768.json','["行盡疏林見小橋，綠楊深處有紅蕉。", "無端眼界無分別，安置心頭不肯銷。"]'),
('yuding-9','自歎','李茂複','唐','御定全唐诗','yuding','','[]','落日西山近一竿，世間恩愛極難yR。近來不作顛狂事，免被冤家惡眼看。',33,'御定全唐詩/json/768.json','["落日西山近一竿，世間恩愛極難yR。近來不作顛狂事，免被冤家惡眼看。"]'),
('yuding-10','贈吳圓','李曜','唐','御定全唐诗','yuding','','[]','經年理郡少歡娛，為習干戈間飲徒。',32,'御定全唐詩/json/768.json','["經年理郡少歡娛，為習干戈間飲徒。", "今日臨行盡交割，分明收取媚川珠。"]'),
('yuding-11','答李曜','吳圓','唐','御定全唐诗','yuding','','[]','曳履優容日日歡，須言達德倍汍瀾。',32,'御定全唐詩/json/768.json','["曳履優容日日歡，須言達德倍汍瀾。", "韶光今已輸先手，領得蠙珠掌上看。"]'),
('yuding-12','和訾家洲宴游','陸弘休','唐','御定全唐诗','yuding','','[]','新春蕊綻訾家洲，信是南方最勝遊。酒滿百分殊不怕，',40,'御定全唐詩/json/768.json','["新春蕊綻訾家洲，信是南方最勝遊。酒滿百分殊不怕，", "莫惜今朝同酩酊，任他龜鶴與蜉蝣。"]'),
('yuding-13','題賈島墓','安錡','唐','御定全唐诗','yuding','','[]','倚恃才難繼，昂藏貌不恭。騎驢沖大尹，奪卷忤宣宗。',48,'御定全唐詩/json/768.json','["倚恃才難繼，昂藏貌不恭。騎驢沖大尹，奪卷忤宣宗。", "馳譽超先輩，居官下我儂。司倉舊曹署，一見一心忡。"]'),
('yuding-14','贈別營妓卿卿','油蔚','唐','御定全唐诗','yuding','','[]','憐君無那是多情，枕上相看直到明。日照綠窗人去住，',40,'御定全唐詩/json/768.json','["憐君無那是多情，枕上相看直到明。日照綠窗人去住，", "為報花時少惆悵，此生終不負卿卿。"]'),
('yuding-15','巢燕','胡玢','唐','御定全唐诗','yuding','','[]','燕來巢我簷，我屋非高大。所貴兒童善，保爾無殃禍。',48,'御定全唐詩/json/768.json','["燕來巢我簷，我屋非高大。所貴兒童善，保爾無殃禍。", "莫巢孀婦家，孀婦怨孤坐。妒爾長雙飛，打爾危巢破。"]'),
('yuding-16','廬山桑落洲','胡玢','唐','御定全唐诗','yuding','','[]','莫問桑田事，但看桑落洲。數家新住處，昔日大江流。',48,'御定全唐詩/json/768.json','["莫問桑田事，但看桑落洲。數家新住處，昔日大江流。", "古岸崩欲盡，平沙長未休。想應百年後，人世更悠悠。"]'),
('yuding-17','石楠樹','胡玢','唐','御定全唐诗','yuding','','[]','本自清江石上生，移栽此處稱閒情。青雲士盡識珍木，',40,'御定全唐詩/json/768.json','["本自清江石上生，移栽此處稱閒情。青雲士盡識珍木，", "餘今一日千回看，每度看來眼益明。"]'),
('yuding-18','句','胡玢','唐','御定全唐诗','yuding','','[]','輪中別有物，光外更無空。',12,'御定全唐詩/json/768.json','["輪中別有物，光外更無空。"]'),
('yuding-19','酒鬍子','盧注','唐','御定全唐诗','yuding','','[]','同心相遇思同歡，擎出酒胡當玉盤。盤中臲卼不自定，',88,'御定全唐詩/json/768.json','["同心相遇思同歡，擎出酒胡當玉盤。盤中臲卼不自定，", "爾不耕，亦不饑。爾不蠶，亦有衣。有眼不能分黼黻，", "雕鐫匠意苦多端，翠帽朱衫巧妝飾。長安鬥酒十千酤，", "酒胡一滴不入眼，空令酒胡名酒胡。"]'),
('yuding-20','西施','盧注','唐','御定全唐诗','yuding','','[]','惆悵興亡系綺羅，世人猶自選青娥。',32,'御定全唐詩/json/768.json','["惆悵興亡系綺羅，世人猶自選青娥。", "越王解破夫差國，一個西施已是多。"]'),
('yuding-21','題西施浣紗石','胡幽貞','唐','御定全唐诗','yuding','','[]','一朝入紫宮，萬古遺芳塵。至今溪邊花，不敢嬌青春。',24,'御定全唐詩/json/768.json','["一朝入紫宮，萬古遺芳塵。至今溪邊花，不敢嬌青春。"]'),
('yuding-22','歸四明','胡幽貞','唐','御定全唐诗','yuding','','[]','海色連四明，仙舟去容易。天籍豈輒問，不是卑朝士。',24,'御定全唐詩/json/768.json','["海色連四明，仙舟去容易。天籍豈輒問，不是卑朝士。"]'),
('yuding-23','送人游邵州','狄煥','唐','御定全唐诗','yuding','','[]','春江正渺渺，送別兩依依。煙裏棹將遠，渡頭人未歸。',48,'御定全唐詩/json/768.json','["春江正渺渺，送別兩依依。煙裏棹將遠，渡頭人未歸。", "漁家侵疊浪，島樹掛殘暉。況入湖湘路，那堪花亂飛。"]'),
('yuding-24','題柳','狄煥','唐','御定全唐诗','yuding','','[]','天南與天北，此處影婆娑。翠色折不盡，離情生更多。',48,'御定全唐詩/json/768.json','["天南與天北，此處影婆娑。翠色折不盡，離情生更多。", "雨餘籠灞岸，煙暝夾隋河。自有佳名在，秦松繼得麼。"]'),
('yuding-25','詠南嶽徑松','狄煥','唐','御定全唐诗','yuding','','[]','一陣雨聲歸嶽嶠，兩條寒色下瀟湘。',32,'御定全唐詩/json/768.json','["一陣雨聲歸嶽嶠，兩條寒色下瀟湘。", "客吟晚景停孤棹，僧踏清陰徹上方。"]'),
('yuding-26','句','狄煥','唐','御定全唐诗','yuding','','[]','數點當秋霽，不知何處峰。',24,'御定全唐詩/json/768.json','["數點當秋霽，不知何處峰。", "更無聲接續，空有影相隨。"]'),
('yuding-27','潯陽觀水','韓溉','唐','御定全唐诗','yuding','','[]','朝宗漢水接陽臺，唅呀填坑吼作雷。莫見九江平穩去，',40,'御定全唐詩/json/768.json','["朝宗漢水接陽臺，唅呀填坑吼作雷。莫見九江平穩去，", "直至滄溟涵貯盡，沈深不動浸昭回。"]'),
('yuding-28','水','韓溉','唐','御定全唐诗','yuding','','[]','方圓不定性空求，東注滄溟早晚休。高截碧塘長耿耿，',40,'御定全唐詩/json/768.json','["方圓不定性空求，東注滄溟早晚休。高截碧塘長耿耿，", "別有嶺頭嗚咽處，為君分作斷腸流。"]'),
('yuding-29','松','韓溉','唐','御定全唐诗','yuding','','[]','倚空高檻冷無塵，往事閑征夢欲分。翠色本宜霜後見，',40,'御定全唐詩/json/768.json','["倚空高檻冷無塵，往事閑征夢欲分。翠色本宜霜後見，", "莫向東園競桃李，春光還是不容君。"]'),
('yuding-30','柳','韓溉','唐','御定全唐诗','yuding','','[]','雪盡青門弄影微，暖風遲日早鶯歸。如憑細葉留春色，',40,'御定全唐詩/json/768.json','["雪盡青門弄影微，暖風遲日早鶯歸。如憑細葉留春色，", "世間惹恨偏饒此，可是行人折贈稀。"]'),
('yuding-31','竹','韓溉','唐','御定全唐诗','yuding','','[]','樹色連雲萬葉開，王孫不厭滿庭栽。淩霜盡節無人見，',40,'御定全唐詩/json/768.json','["樹色連雲萬葉開，王孫不厭滿庭栽。淩霜盡節無人見，", "朱門處處多閑地，正好移陰覆翠苔。"]'),
('yuding-32','鵲','韓溉','唐','御定全唐诗','yuding','','[]','才見離巢羽翼開，盡能輕颺出塵埃。人間樹好紛紛占，',40,'御定全唐詩/json/768.json','["才見離巢羽翼開，盡能輕颺出塵埃。人間樹好紛紛占，", "若教顏色如霜雪，應與清平作瑞來。"]'),
('yuding-33','燈','韓溉','唐','御定全唐诗','yuding','','[]','分影由來恨不同，綠窗孤館兩何窮。熒煌短焰長疑暗，',40,'御定全唐詩/json/768.json','["分影由來恨不同，綠窗孤館兩何窮。熒煌短焰長疑暗，", "莫言明滅無多重，曾比人生一世中。"]'),
('yuding-34','句','韓溉','唐','御定全唐诗','yuding','','[]','門掩落花人別後，窗含殘月酒醒時。（《愁詩》，',22,'御定全唐詩/json/768.json','["門掩落花人別後，窗含殘月酒醒時。（《愁詩》，"]'),
('yuding-35','春怨','金昌緒','唐','御定全唐诗','yuding','','[]','打起黃鶯兒，莫教枝上啼。啼時驚妾夢，不得到遼西。',24,'御定全唐詩/json/768.json','["打起黃鶯兒，莫教枝上啼。啼時驚妾夢，不得到遼西。"]'),
('yuding-36','放猿','曾麻幾','唐','御定全唐诗','yuding','','[]','孤猿鎖檻歲年深，放出城南百丈林。',32,'御定全唐詩/json/768.json','["孤猿鎖檻歲年深，放出城南百丈林。", "綠水任從聯臂飲，青山不用斷腸吟。"]'),
('yuding-0','觀兄弟同夜成婚','鄭軌','唐','御定全唐诗','yuding','','[]','棠棣開雙萼，夭桃照兩花。分庭含佩響，隔扇偶妝華。',48,'御定全唐詩/json/769.json','["棠棣開雙萼，夭桃照兩花。分庭含佩響，隔扇偶妝華。", "迎風俱似雪，映綺共如霞。今宵二神女，並在一仙家。"]'),
('yuding-1','夏彈琴','劉戩','唐','御定全唐诗','yuding','','[]','碧山本岑寂，素琴何清幽。彈為風入松，崖谷颯已秋。',84,'御定全唐詩/json/769.json','["碧山本岑寂，素琴何清幽。彈為風入松，崖谷颯已秋。", "庭鶴舞白雪，泉魚躍洪流。予欲娛世人，明月難暗投。", "感歎未終曲，淚下不可收。嗚呼鐘子期，零落歸荒丘。", "死而若有知，魂兮從我遊。"]'),
('yuding-2','過函谷關','楊齊哲','唐','御定全唐诗','yuding','','[]','地險崤函北，途經分陝東。逶迤眾山盡，荒涼古塞空。',48,'御定全唐詩/json/769.json','["地險崤函北，途經分陝東。逶迤眾山盡，荒涼古塞空。", "河光流曉日，樹影散朝風。聖德今無外，何處是關中。"]'),
('yuding-3','傷死奴','劉夷道','唐','御定全唐诗','yuding','','[]','丹籍生涯淺，黃泉歸路深。不及江陵樹，千秋長作林。',24,'御定全唐詩/json/769.json','["丹籍生涯淺，黃泉歸路深。不及江陵樹，千秋長作林。"]'),
('yuding-4','侍宴賦得起坐彈鳴琴二首','楊希道','唐','御定全唐诗','yuding','','[]','北林鵲夜飛，南軒月初進。調弦發清征，蕩心祛褊吝。',72,'御定全唐詩/json/769.json','["北林鵲夜飛，南軒月初進。調弦發清征，蕩心祛褊吝。", "變作離鴻聲，還入思歸引。長歎未終極，秋風飄素鬢。", "絲傳園客意，曲奏楚妃情。罕有知音者，空勞流水聲。"]'),
('yuding-5','詠琴','楊希道','唐','御定全唐诗','yuding','','[]','久擅龍門質，孤竦嶧陽名。齊娥初發弄，趙女正調聲。',36,'御定全唐詩/json/769.json','["久擅龍門質，孤竦嶧陽名。齊娥初發弄，趙女正調聲。", "嘉客勿遽反，繁弦曲未成。"]'),
('yuding-6','詠笙','楊希道','唐','御定全唐诗','yuding','','[]','短長插鳳翼，洪細摹鸞音。能令楚妃歎，複使荊王吟。',36,'御定全唐詩/json/769.json','["短長插鳳翼，洪細摹鸞音。能令楚妃歎，複使荊王吟。", "切切孤竹管，來應雲和琴。"]'),
('yuding-7','詠舞','楊希道','唐','御定全唐诗','yuding','','[]','二八如同雪，三春類早花。分行向燭轉，一種逐風斜。',24,'御定全唐詩/json/769.json','["二八如同雪，三春類早花。分行向燭轉，一種逐風斜。"]'),
('yuding-8','詠妓','王績','唐','御定全唐诗','yuding','','[]','妖姬飾靚妝，窈窕出蘭房。日照當軒影，風吹滿路香。',48,'御定全唐詩/json/769.json','["妖姬飾靚妝，窈窕出蘭房。日照當軒影，風吹滿路香。", "早時歌扇薄，今日舞衫長。不應令曲誤，持此試周郎。"]'),
('yuding-9','益州城西張超亭觀妓','王績','唐','御定全唐诗','yuding','','[]','落日明歌席，行雲逐舞人。江前飛暮雨，梁上下輕塵。',48,'御定全唐詩/json/769.json','["落日明歌席，行雲逐舞人。江前飛暮雨，梁上下輕塵。", "冶服看疑畫，妝台望似春。高車勿遽返，長袖欲相親。"]'),
('yuding-10','辛司法宅觀妓','王績','唐','御定全唐诗','yuding','','[]','南國佳人至，北堂羅薦開。長裙隨鳳管，促柱送鸞杯。',48,'御定全唐詩/json/769.json','["南國佳人至，北堂羅薦開。長裙隨鳳管，促柱送鸞杯。", "雲光身後落，雪態掌中回。到愁金穀晚，不怪玉山頹。"]'),
('yuding-11','秋池一枝蓮','郭恭','唐','御定全唐诗','yuding','','[]','秋至皆零落，淩波獨吐紅。托根方得所，未肯即隨風。',24,'御定全唐詩/json/769.json','["秋至皆零落，淩波獨吐紅。托根方得所，未肯即隨風。"]'),
('yuding-12','婕妤怨','張烜','唐','御定全唐诗','yuding','','[]','賤妾裁紈扇，初搖明月姿。君王看舞席，坐起秋風時。',48,'御定全唐詩/json/769.json','["賤妾裁紈扇，初搖明月姿。君王看舞席，坐起秋風時。", "玉樹清禦路，金陳翳垂絲。昭陽無分理，愁寂任前期。"]'),
('yuding-13','長門怨','張修之','唐','御定全唐诗','yuding','','[]','長門落景盡，洞房秋月明。玉階草露積，金屋網塵生。',48,'御定全唐詩/json/769.json','["長門落景盡，洞房秋月明。玉階草露積，金屋網塵生。", "妾妒今應改，君恩昔未平。寄語臨邛客，何時作賦成。"]'),
('yuding-14','王昭君','梁獻','唐','御定全唐诗','yuding','','[]','圖畫失天真，容華坐誤人。君恩不可再，妾命在和親。',48,'御定全唐詩/json/769.json','["圖畫失天真，容華坐誤人。君恩不可再，妾命在和親。", "淚點關山月，衣銷邊塞塵。一聞陽鳥至，思絕漢宮春。"]'),
('yuding-15','芳樹','符子珪','唐','御定全唐诗','yuding','','[]','芳樹宜三月，曈曈豔綺年。香交珠箔氣，陰占綠庭煙。',48,'御定全唐詩/json/769.json','["芳樹宜三月，曈曈豔綺年。香交珠箔氣，陰占綠庭煙。", "小葉風吹長，繁花露濯鮮。遂令穠李兒，折取簪花鈿。"]'),
('yuding-16','觀妓','李何','唐','御定全唐诗','yuding','','[]','向晚小乘遊，朝來新上頭。從來許長袖，未有客難留。',24,'御定全唐詩/json/769.json','["向晚小乘遊，朝來新上頭。從來許長袖，未有客難留。"]'),
('yuding-17','邯鄲俠少年','鄭鏦','唐','御定全唐诗','yuding','','[]','夜渡濁河津，衣中劍滿身。兵符劫晉鄙，匕首刺秦人。',48,'御定全唐詩/json/769.json','["夜渡濁河津，衣中劍滿身。兵符劫晉鄙，匕首刺秦人。", "執事非無膽，高堂念有親。昨緣秦苦趙，來往大樑頻。"]'),
('yuding-18','玉階怨','鄭鏦','唐','御定全唐诗','yuding','','[]','昔日同飛燕，今朝似伯勞。情深爭擲果，寵罷怨殘桃。',48,'御定全唐詩/json/769.json','["昔日同飛燕，今朝似伯勞。情深爭擲果，寵罷怨殘桃。", "別殿春心斷，長門夜樹高。雖能不自悔，誰見舊衣褒。"]'),
('yuding-19','婕妤怨','鄭鏦','唐','御定全唐诗','yuding','','[]','南國承歡日，東方候曉時。那能妒褒姒，只愛笑唐兒。',48,'御定全唐詩/json/769.json','["南國承歡日，東方候曉時。那能妒褒姒，只愛笑唐兒。", "寶葉隨雲髻，珠絲鍛履綦。不知飛燕意，何事苦相疑。"]'),
('yuding-20','入塞曲','鄭鏦','唐','御定全唐诗','yuding','','[]','留滯邊庭久，歸思歲月賒。黃雲同入塞，白首獨還家。',48,'御定全唐詩/json/769.json','["留滯邊庭久，歸思歲月賒。黃雲同入塞，白首獨還家。", "宛馬隨秦草，胡人問漢花。還傷李都尉，獨自沒黃沙。"]'),
('yuding-21','賞殘花','紇幹著','唐','御定全唐诗','yuding','','[]','零落多依草，芳香散著人。低簷一枝在，猶占滿堂春。',24,'御定全唐詩/json/769.json','["零落多依草，芳香散著人。低簷一枝在，猶占滿堂春。"]'),
('yuding-22','古仙詞','紇幹著','唐','御定全唐诗','yuding','','[]','珠幡絳節曉霞中，漢武清齋待少翁。',32,'御定全唐詩/json/769.json','["珠幡絳節曉霞中，漢武清齋待少翁。", "不向人間戀春色，桃花自滿紫陽宮。"]'),
('yuding-23','感春詞','紇幹著','唐','御定全唐诗','yuding','','[]','未得鳴珂謁漢宮，江頭寂寞向春風。',32,'御定全唐詩/json/769.json','["未得鳴珂謁漢宮，江頭寂寞向春風。", "悲歌一曲心應醉，萬葉千花淚眼中。"]'),
('yuding-24','灞上','紇幹著','唐','御定全唐诗','yuding','','[]','鳴鞭晚日禁城東，渭水晴煙灞岸風。',32,'御定全唐詩/json/769.json','["鳴鞭晚日禁城東，渭水晴煙灞岸風。", "都傍柳陰回首望，春天樓閣五雲中。"]'),
('yuding-25','淩雲寺','李習','唐','御定全唐诗','yuding','','[]','古寺臨江間碧波，石梯深入白雲窠。',32,'御定全唐詩/json/769.json','["古寺臨江間碧波，石梯深入白雲窠。", "僧禪寂寂無人跡，滿地落花春又過。"]'),
('yuding-26','鳳棲怨','顏舒','唐','御定全唐诗','yuding','','[]','佳人名莫愁，珠箔上花鉤。清鏡鴛鴦匣，新妝翡翠樓。',48,'御定全唐詩/json/769.json','["佳人名莫愁，珠箔上花鉤。清鏡鴛鴦匣，新妝翡翠樓。", "擣衣明月夜，吹管白雲秋。惟恨金吾子，年年向隴頭。"]'),
('yuding-27','春女怨','朱絳','唐','御定全唐诗','yuding','','[]','獨坐紗窗刺繡遲，紫荊花下囀黃鸝。',32,'御定全唐詩/json/769.json','["獨坐紗窗刺繡遲，紫荊花下囀黃鸝。", "欲知無限傷春意，盡在停針不語時。"]'),
('yuding-28','失題','徐璧','唐','御定全唐诗','yuding','','[]','雙燕今朝至，何時發海濱。窺簷向人語，如道故鄉春。',24,'御定全唐詩/json/769.json','["雙燕今朝至，何時發海濱。窺簷向人語，如道故鄉春。"]'),
('yuding-29','催妝','徐安期','唐','御定全唐诗','yuding','','[]','傳聞燭下調紅粉，明鏡台前別作春。',32,'御定全唐詩/json/769.json','["傳聞燭下調紅粉，明鏡台前別作春。", "不須面上渾妝卻，留著雙眉待畫人。"]'),
('yuding-30','隔壁聞奏伎','裴延','唐','御定全唐诗','yuding','','[]','徒聞管弦切，不見舞腰回。賴有歌梁合，塵飛一半來。',24,'御定全唐詩/json/769.json','["徒聞管弦切，不見舞腰回。賴有歌梁合，塵飛一半來。"]'),
('yuding-31','詠剪花','裴延','唐','御定全唐诗','yuding','','[]','花寒未聚蝶，色豔已驚人。懸知陌上柳，應妒手中春。',24,'御定全唐詩/json/769.json','["花寒未聚蝶，色豔已驚人。懸知陌上柳，應妒手中春。"]'),
('yuding-32','歎美人照鏡','陳述','唐','御定全唐诗','yuding','','[]','插花枝共動，含笑靨俱生。衫分兩處色，釧響一邊聲。',36,'御定全唐詩/json/769.json','["插花枝共動，含笑靨俱生。衫分兩處色，釧響一邊聲。", "就中還妒影，恐奪可憐名。"]'),
('yuding-33','開緘怨','朱琳','唐','御定全唐诗','yuding','','[]','夫婿邊庭久，幽閨恨幾重。玉琴知別日，金鏡識愁容。',48,'御定全唐詩/json/769.json','["夫婿邊庭久，幽閨恨幾重。玉琴知別日，金鏡識愁容。", "懶寄雲中服，慵開海上封。年年得衣慣，且試莫裁縫。"]'),
('yuding-34','雜言','謝陶','唐','御定全唐诗','yuding','','[]','天不與人言，禍福能自至。水火雖活人，暫不得即死。',48,'御定全唐詩/json/769.json','["天不與人言，禍福能自至。水火雖活人，暫不得即死。", "蹈之焚斯須，憑之溺容易。水火與禍福，豈有先言耳。"]'),
('yuding-35','書事','何贊','唐','御定全唐诗','yuding','','[]','果決生涯向路中，西投知己話從容。雲遮劍閣三千里，',40,'御定全唐詩/json/769.json','["果決生涯向路中，西投知己話從容。雲遮劍閣三千里，", "到頭須卜林泉隱，自愧無能繼臥龍。"]'),
('yuding-36','雁塔','解彥融','唐','御定全唐诗','yuding','','[]','崢嶸徹倒景，刻峭俯無地。勇進攀有緣，即嶮恐迷墜。',120,'御定全唐詩/json/769.json','["崢嶸徹倒景，刻峭俯無地。勇進攀有緣，即嶮恐迷墜。", "窅然喪五蘊，蠢爾懷萬類。實際罔他尋，波羅必可致。", "南山繚上苑，祇樹連岩翠。北斗臨帝城，扶宮切太清。", "餐和裨日用，味道懿天明。綠野冷風浹，紫微佳氣晶。", "馴禽演法要，忍草藉經行。本願從茲適，方知物世輕。"]'),
('yuding-0','昭君怨','董初','唐','御定全唐诗','yuding','','[]','新年猶尚小，那堪遠聘秦。裾衫沾馬汗，眉黛染胡塵。',48,'御定全唐詩/json/770.json','["新年猶尚小，那堪遠聘秦。裾衫沾馬汗，眉黛染胡塵。", "舉眼無相識，路逢皆異人。唯有梅將李，猶帶故鄉春。"]'),
('yuding-1','南山','賀朝清','唐','御定全唐诗','yuding','','[]','湖北雨初晴，湖南山盡見。岩岩石帆影，如得海風便。',48,'御定全唐詩/json/770.json','["湖北雨初晴，湖南山盡見。岩岩石帆影，如得海風便。", "仙穴茅山峰，彩雲時一見。邀君共探此，異籙殘幾卷。"]'),
('yuding-2','賦得遊人久不歸','賀朝清','唐','御定全唐诗','yuding','','[]','鄉關眇天末，引領悵懷歸。羈旅久淫滯，物色屢芳菲。',48,'御定全唐詩/json/770.json','["鄉關眇天末，引領悵懷歸。羈旅久淫滯，物色屢芳菲。", "稍覺私意盡，行看鬔鬢稀。如何千裏外，佇立沾裳衣。"]'),
('yuding-3','白紵辭','楊衡','唐','御定全唐诗','yuding','','[]','玉纓翠佩雜輕羅，香汗微漬朱顏酡。為君起唱白紵歌，',48,'御定全唐詩/json/770.json','["玉纓翠佩雜輕羅，香汗微漬朱顏酡。為君起唱白紵歌，", "躡珠履，步瓊筵，輕身起舞紅燭前。芳姿豔態妖且妍，"]'),
('yuding-4','還渭南感舊二首','唐暄','唐','御定全唐诗','yuding','','[]','寢室悲長簟，妝樓泣鏡臺。獨悲桃李節，不共一時開。',84,'御定全唐詩/json/770.json','["寢室悲長簟，妝樓泣鏡臺。獨悲桃李節，不共一時開。", "魂兮若有感，仿佛夢中來。", "常時華室靜，笑語度更籌。恍惚人事改，冥漠委荒丘。", "陽原歎薤露，陰壑悼藏舟。清夜妝台月，空想畫眉愁。"]');
